INSERT INTO public.site_settings VALUES ('newsContent', '{"posts": [{"id": "aiahottsdkee7afn", "slug": "rapat-anggota-tahunan-tahun-buku-2025-kopera-sivitas-akademika-unb-bogor", "title": "Rapat Anggota Tahunan Tahun Buku 2025 Kopera Sivitas Akademika UNB Bogor.", "author": "Humas UNB", "blocks": [{"id": "4pb5980yetvfsn0i", "text": "[av_textblock size='''' font_color='''' color='''' av-medium-font-size='''' av-small-font-size='''' av-mini-font-size='''' av_uid=''av-mm8omenl'' admin_preview_bg='''']", "type": "paragraph"}, {"id": "8bkte405222g51db", "text": "Koperasi Universitas Nusa Bangsa (KOSIVA) Melaksanakan kegiatan rapat tahunan untuk RAT buku 2025. Rapat tahunan ini di pimpin langsung oleh Ketua Koperasi Universitas Nusa Bangsa Bapak Agus Pranamulia.,SE.,MM yang biasa disapa Ki Guru dan juga sebagai salah satu budayawan kota Bogor. Rapat tahunan KOSIVA ini di hadiri oleh seluruh anggota Koperasi untuk berpartisipasi dalam memajukan KOSIVA agar lebih baik.", "type": "paragraph"}, {"id": "b0en4vtwz8kngeqg", "text": "Ketua Koperasi UNB Ki Guru Agus Pranamulia (Budayawan)", "type": "paragraph"}, {"id": "anua2jm5zpautkvh", "text": "Jajaran anggota KOSIVA", "type": "paragraph"}, {"id": "s8mhq82kznch26tc", "url": "https://unb.ac.id/wp-content/uploads/2026/03/kiguru.jpg", "type": "image", "caption": ""}, {"id": "qyab16i8bs8omb8c", "url": "https://unb.ac.id/wp-content/uploads/2026/03/koperasi-1-1.jpg", "type": "image", "caption": ""}], "excerpt": "[av_textblock size='''' font_color='''' color='''' av-medium-font-size='''' av-small-font-size='''' av-mini-font-size='''' av_uid=''av-mm8omenl'' admin_preview_bg=''''] Koperasi Universitas Nusa Bangsa (KOSIVA) Melaksanakan kegiatan rap...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/03/kiguru.jpg", "publishedAt": "2026-03-02"}, {"id": "842e863r6hzwhfye", "slug": "mery-futrian-berhasil-meraih-juara-1-duta-cendikia-muda-biifest-bogor-icmi-islam", "title": "Mery Futrian Berhasil Meraih Juara 1 Duta Cendikia Muda BIIFest Bogor – ICMI Islamic Festival 2026", "author": "Humas UNB", "blocks": [{"id": "m2wtoskpl6cwufxz", "text": "Bangga dan penuh syukur! 🤍 Selamat kepada Mery Futrian yang berhasil meraih Juara 1 Duta Cendikia Muda BIIFest Bogor – ICMI Islamic Festival 2026 Prestasi ini membuktikan bahwa semangat, dedikasi, dan kecintaan pada ilmu akan selalu membawa hasil terbaik. Terus bersinar dan menginspirasi!", "type": "paragraph"}, {"id": "ka4rrz3q6qkk06ob", "url": "https://unb.ac.id/wp-content/uploads/2026/03/meri2-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Mery Futrian Bangga dan penuh syukur! 🤍 Selamat kepada Mery Futrian yang berhasil meraih Juara 1 Duta Cendikia Muda BIIFest Bogor – ICMI Islamic Festival 2026 Prestasi ini membuktikan bahwa semangat, dedikasi, dan kecin...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/03/meri2-845x684.jpg", "publishedAt": "2026-03-02"}, {"id": "klw9av22ryowuj3p", "slug": "rektor-universitas-nusa-bangsa-prof-budi-mendapatkan-penghargaan-insan-cendikia-", "title": "Rektor Universitas Nusa Bangsa Prof. Budi Mendapatkan Penghargaan Insan Cendikia ICMI ORDA Kota Bogor", "author": "Humas UNB", "blocks": [{"id": "w36dcfjehpo9ulx3", "text": "Selamat Prof. Budi atas penghargaan Insan Cendikia dari ICMI ORDA KT BOGOR", "type": "paragraph"}, {"id": "7qiw2b4kw2k8lcl3", "url": "https://unb.ac.id/wp-content/uploads/2026/03/rektor-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Selamat Prof. Budi atas penghargaan Insan Cendikia dari ICMI ORDA KT BOGOR", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/03/rektor-845x684.jpg", "publishedAt": "2026-03-02"}, {"id": "n3e9hrf5dbsangpw", "slug": "sk-ban-pt-reakreditasi-universitas-nusa-bangsa-baik-sekali", "title": "SK BAN-PT Reakreditasi Universitas Nusa Bangsa \"Baik Sekali\"", "author": "Humas UNB", "blocks": [{"id": "460y5f9m9zet6633", "text": "Kepada: Bapak/Ibu Mahasiswa/ Alumni/ pengguna alumni/ mitra kerjasama UNB Dengan penuh rasa syukur, kami (pimpinan UNB) mengucapkan terimakasih yang mendalam kepada seluruh stakeholder yang terlibat dan membantu selama proses Asesmen Lapang, sehingga hasil keputusan akreditasi UNB telah diumumkan. Alhamdulillah UNB terakreditasi BAIK SEKALI, sesuai dengan SK BAN-PT NOMOR: 56/SK/BAN-PT/Ak/PT/II/2026 berlaku dari tanggal 24 Februari 2026 hingga 24 Februari 2031 Hasil ini tak luput dari bantuan para stakeholder baik dosen, mahasiswa, alumni, pengguna alumni dan mitra kerjasama yang telah berkenan hadir memberikan support selama proses AL oleh asesor BAN PT. Semoga kedepan UNB semakin maju dan dapat memperoleh peringkat akreditasi \"UNGGUL\" REKTOR", "type": "paragraph"}, {"id": "w7256haoc4hzmuq5", "url": "https://unb.ac.id/wp-content/uploads/2026/02/WhatsApp-Image-2026-02-27-at-11.35.18-AM-845x680.jpeg", "type": "image", "caption": ""}], "excerpt": "Kepada: Bapak/Ibu Mahasiswa/ Alumni/ pengguna alumni/ mitra kerjasama UNB Dengan penuh rasa syukur, kami (pimpinan UNB) mengucapkan terimakasih yang mendalam kepada seluruh stakeholder yang terlibat dan membantu selama p...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/WhatsApp-Image-2026-02-27-at-11.35.18-AM-845x680.jpeg", "publishedAt": "2026-02-27"}, {"id": "1bj49eylcapbyqor", "slug": "universitas-nusa-bangsa-terakreditasi-baik-sekali", "title": "Universitas Nusa Bangsa Terakreditasi : Baik Sekali", "author": "Humas UNB", "blocks": [{"id": "hjsmsxe60h79m99m", "text": "Universitas Nusa Bangsa (UNB) Memperoleh akreditasi Institusi (AIPT) Baik Sekali dengan nilai 324 yang mendekati Unggul. Reakreditasi institusi ini Sesuai dengan No.SK: 56/SK/BAN-PT/Ak/PT/II/2026. Pencapaian prestasi UNB ini berkat kerjasama semua lapisan akademik mulai dari Rektor UNB, Para Wakil Rektor, Para Dekan, Kepala Biro, Kepala Lembaga, Kepala Bagian, Kaprodi, semua jajaran staf kependidikan UNB demikian disampaikan oleh Rektor UNB Prof. Dr. Budi Mulyanto.", "type": "paragraph"}, {"id": "zz2yyj8143i5scva", "url": "https://unb.ac.id/wp-content/uploads/2026/02/unb-845x433.jpg", "type": "image", "caption": ""}], "excerpt": "Universitas Nusa Bangsa (UNB) Memperoleh akreditasi Institusi (AIPT) Baik Sekali dengan nilai 324 yang mendekati Unggul. Reakreditasi institusi ini Sesuai dengan No.SK: 56/SK/BAN-PT/Ak/PT/II/2026. Pencapaian prestasi UNB...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/unb-845x433.jpg", "publishedAt": "2026-02-25"}, {"id": "6jidlonm4r7lshx7", "slug": "pelepasan-kuliah-kerja-nyata-tematik-kknt", "title": "Pelepasan Kuliah Kerja Nyata Tematik (KKNT)", "author": "Humas UNB", "blocks": [{"id": "6mh4v7dvcvo3zjjm", "text": "Mahasiswa Universitas Nusa Bangsa melakukan kegiatan pelepasan kuliah kerja nyata tematik (KKNT). Pelaksanaan pelepasan kuliah kerja nyata tematik (KKNT) masuk pada periode 1 di tahun 2026. Acara pelepasan ini langsung dipimpin oleh Ketua LPPM Universitas Nusa Bangsa Bapak Dr.Zaenal. Pelaksanaan pelepasan kuliah kerja nyata tematik (KKNT) berada di wilayah Kecamatan Tajur Halang Bogor.", "type": "paragraph"}, {"id": "ago48ktxd20vpi2q", "url": "https://unb.ac.id/wp-content/uploads/2026/02/kknt01.jpg", "type": "image", "caption": ""}, {"id": "8jpkmeamofdnz3cf", "url": "https://unb.ac.id/wp-content/uploads/2026/02/kknt02.jpg", "type": "image", "caption": ""}], "excerpt": "Mahasiswa Universitas Nusa Bangsa melakukan kegiatan pelepasan kuliah kerja nyata tematik (KKNT). Pelaksanaan pelepasan kuliah kerja nyata tematik (KKNT) masuk pada periode 1 di tahun 2026. Acara pelepasan ini langsung d...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/kknt01.jpg", "publishedAt": "2026-02-20"}, {"id": "csqceq30g1oxi212", "slug": "asesmen-lapangan-aipt-universitas-nusa-bangsa", "title": "Asesmen Lapangan AIPT Universitas Nusa Bangsa", "author": "Humas UNB", "blocks": [{"id": "v6xdcjpyczmd1l6r", "text": "Universitas Nusa Bangsa (UNB) melaksanakan kegiatan penerimaan asesmen lapangan reakreditasi institutsi perguruan tinggi pada tanggal 26-28 Januari 2026. Tim asesor dari BAN PT yang terdiri dari Prof. Dr. Supratman., S.Hut., MP sebagai asesor 1, Lina Salim., SE., MBA., MA., Ph.D., CPM(A) sebagai asesor 2, dan Dr. Ahim Abdurahim., SE., M.Si., Ak., SAS., CA sebagai asesor 3. Acara kegiatan asesmen lapangan ini berjalan dengan lancar yang dihadiri oleh tim AIPT Universitas Nusa Bangsa yang ketuai oleh Ibu Mamay Maslahat., S.Si., M.Si. Acara ini dimulai dengan laporan kegiatan AIPT oleh Rektor UNB Prof. Dr. Budi Mulyanto.M.Si, yang didampingi oleh Wakil Rektor 1 Prof. Dr. Ucu Cahyana., M.Si, Wakil Rektor 2 Sunrizal., SE., MM., CFrA, CFE., CGCAE., QRGP, dan Wakil Rektor 3 Ibu Dr.Karmanah., M.Si. Acara asesmen lapangan AIPT UNB dilanjutkan dengan kunjungan ke gedung Fakultas Ekonomi dan Bisnis, Fakultas Kehutanan dan Lingkungan, Fakultas Agroteknopreneur dan Agraria, Fakultas Sains dan Teknologi, dan fasilitas UNB lainnya.", "type": "paragraph"}, {"id": "j910mjvb5e47c34p", "url": "https://unb.ac.id/wp-content/uploads/2026/02/aipt-1-845x684.jpg", "type": "image", "caption": ""}, {"id": "l6e1vwuughbhhtna", "url": "https://unb.ac.id/wp-content/uploads/2026/02/aipt-2-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Universitas Nusa Bangsa (UNB) melaksanakan kegiatan penerimaan asesmen lapangan reakreditasi institutsi perguruan tinggi pada tanggal 26-28 Januari 2026. Tim asesor dari BAN PT yang terdiri dari Prof. Dr. Supratman., S.H...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/aipt-1-845x684.jpg", "publishedAt": "2026-02-18"}, {"id": "etbihz86pne7n3nj", "slug": "sekolah-kepemimpinan-km-unb-2026", "title": "Sekolah Kepemimpinan KM-UNB 2026", "author": "Humas UNB", "blocks": [{"id": "o71aisbxl6sw2er6", "text": "Badan Eksekutif Mahasiswa (BEM) Universitas Nusa Bangsa melaksanakan kegiatan Sekolah Kepemimpinan yang dilaksanakan pada tanggal 12 Januari 2026. Acara ini merupakan bagian dari agenda Kepala Biro/Kepala Bagian Kemahasiswaan, dan Alumni UNB ibu Ayi Ratnaningsih., S.Pt., S.Si dan dilaksanakan oleh Tim BEM UNB yang di ketuai oleh Salman. Kata sambutan oleh Kepala Biro Kemahasiswaan, Kerjasama dan Alumni Ibu Dra. Febi Nurilmala., M.Si yang memberikan arahan bahwa sekolah kepemimpinan bertujuan untuk membentuk karakter, meningkatkan kompetensi, dan membekali individu dengan keterampilan manajerial serta sosial yang diperlukan untuk memimpin secara efektif. Program ini bertujuan menghasilkan pemimpin masa depan yang inovatif, berintegritas, mampu memecahkan masalah, dan beradaptasi dengan perubahan. Acara Sekolah Kepemimpinan KM-UNB 2026 resmi dibuka oleh Wakil Rektor 3 Ibu Dr. Karmanah., M.Si.", "type": "paragraph"}, {"id": "mrc767dhloxunoqb", "text": "Wakil Rektor 3 Ibu Dr. Karmanah.,M.Si, sedang membuka acara Sekolah Kepemimpinan UNB 2026", "type": "paragraph"}, {"id": "hprhw4m0e79y8zs4", "text": "Kepala Biro Kemahasiswaan, Kerjasama dan Alumni Ibu Dra. Febi Nurilmala., M.Si sedang memberikan kata sambutan", "type": "paragraph"}, {"id": "emfut8j4zxtr7xk0", "text": "Ketua BEM UNB Salman sedang memberikan arahan dan semangat dalam acara Sekolah Kepemimpinan UNB 2026", "type": "paragraph"}, {"id": "u3hhtn8adfthi5j3", "url": "https://unb.ac.id/wp-content/uploads/2026/02/kemas2-edit-845x684.jpg", "type": "image", "caption": ""}, {"id": "dzfn9nkuodw7yhar", "url": "https://unb.ac.id/wp-content/uploads/2026/02/kemas-karmanah-596x684.jpg", "type": "image", "caption": ""}], "excerpt": "Badan Eksekutif Mahasiswa (BEM) Universitas Nusa Bangsa melaksanakan kegiatan Sekolah Kepemimpinan yang dilaksanakan pada tanggal 12 Januari 2026. Acara ini merupakan bagian dari agenda Kepala Biro/Kepala Bagian Kemahasi...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/kemas2-edit-845x684.jpg", "publishedAt": "2026-02-18"}, {"id": "4acr627xcae86x1p", "slug": "ikatan-muslim-universitas-nusa-bangsa-menyelenggaran-peringatan-isra-miraj-1447-", "title": "Ikatan Muslim Universitas Nusa Bangsa Menyelenggaran Peringatan Isra Mi''raj 1447 H/2026 M", "author": "Humas UNB", "blocks": [{"id": "wpzj520av3dbpunl", "text": "Ikatan Muslim (IKLIM) Universitas Nusa Bangsa yang dibina oleh Ibu Kustin Bintani Meiganati, S.Hut., M.Si dan Ketua DKM Masjid Khalid Bin Walid UNB Bapak Abdul Rahman Rusli, S.Hut., M.Si menyelenggarakan peringatan Isra Mi''raj. Tema peringatan Isra Mi''raj adalah \"Meneladani Perjuangan Rasulullah SAW untuk Menjemput Keberkahan Ramadhan\". Acara Peringatan Isra Mi''raj ini dilaksnakan pada hari Senin sampai dengan Selasa, 16 sampai dengan 17 Februari 2026 di Gedung Auditorium Universitas Nusa Bangsa. Acara peringatan Isra Mi''raj mengundang penceramah kondang Ustad Taufikurahman yang biasa disebut ustad pantun. Wakil Rektor 2 Bapak Sunrizal, SE, MM hadir untuk membuka acara Isra Mi''raj dan juga dihadiri oleh Kepala Biro Kemahasiswaan, Kerjasama dan Alumni Ibu Dra. Febi Nurilmala., M.Si memberikan sambutan dalam acara Isra Mi''raj ini. Acara Isra Mi''raj ini juga mendakan lomba da''i muda dan pentas seni Islami.", "type": "paragraph"}, {"id": "nyh1fd05n11ashyu", "text": "Ustad Taufikurahman sedang memberikan tausiah", "type": "paragraph"}, {"id": "i5fmg6t1z28otpxe", "text": "Wakil Rektor 2 UNB Bapak Sunrizal, SE.,MM sedang membuka acara Isra Mi''raj", "type": "paragraph"}, {"id": "inadu7aar9hw11iv", "text": "Kata sambutan oleh Kepala Biro Kemahasiswaan, Kerjasama dan Alumni Ibu Dra. Febi Nurilmala., M.Si", "type": "paragraph"}, {"id": "e9w6ed2398r7kte7", "text": "Lomba ceramah oleh da''i muda", "type": "paragraph"}, {"id": "bapdkzp3e9n9avkk", "url": "https://unb.ac.id/wp-content/uploads/2026/02/rebana1-845x684.jpg", "type": "image", "caption": ""}, {"id": "a8irz5zkxh4txjkq", "url": "https://unb.ac.id/wp-content/uploads/2026/02/ustad-pantun-720x684.jpg", "type": "image", "caption": ""}], "excerpt": "Ikatan Muslim (IKLIM) Universitas Nusa Bangsa yang dibina oleh Ibu Kustin Bintani Meiganati, S.Hut., M.Si dan Ketua DKM Masjid Khalid Bin Walid UNB Bapak Abdul Rahman Rusli, S.Hut., M.Si menyelenggarakan peringatan Isra...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2026/02/rebana1-845x684.jpg", "publishedAt": "2026-02-18"}, {"id": "hjuf8vc61jetgxki", "slug": "peran-penting-ular-dalam-rantai-makanan-dan-mitigasi-potensi-bahaya", "title": "Peran Penting Ular Dalam Rantai Makanan Dan Mitigasi Potensi Bahaya", "author": "Humas UNB", "blocks": [{"id": "yxbapuxavgvln9fu", "text": "Pada tanggal 20 Desember 2025, Kelompok Mahasiswa Pencinta Herpetofauna (KMPK) diundang oleh siswa-siswi Pecinta Alam SMAN 2 Kota Bogor (PALASDA) dalam rangka kegiatan Pradiklatsar ke-3. Kegiatan ini bertujuan untuk membekali peserta dengan pengetahuan dan keterampilan dasar mengenai survival ular serta teknik penanganan ular yang aman dan bertanggung jawab, sebagai upaya meningkatkan keselamatan, kesadaran konservasi, dan pemahaman peran ular dalam ekosistem. Ular memiliki peran yang sangat penting dalam rantai makanan sebagai predator alami yang menjaga keseimbangan ekosistem. Dalam posisi trofik menengah hingga tinggi, ular memangsa hewan seperti tikus, katak, kadal, dan burung kecil. Dengan mengendalikan populasi hama, khususnya tikus yang sering merusak tanaman dan menjadi vektor penyakit, ular berkontribusi langsung terhadap stabilitas lingkungan pertanian dan kesehatan manusia. Keberadaan ular juga menjadi indikator ekosistem yang relatif sehat, karena ular membutuhkan habitat yang seimbang dan ketersediaan mangsa yang cukup untuk bertahan hidup. Selain berperan sebagai predator, ular juga menjadi bagian penting dalam jaring-jaring makanan sebagai mangsa bagi hewan lain seperti elang, biawak, dan mamalia karnivora. Interaksi ini menunjukkan bahwa ular berfungsi sebagai penghubung antar tingkat trofik, sehingga hilangnya ular dapat memicu ketidakseimbangan ekosistem, seperti ledakan populasi hama. Oleh karena itu, pelestarian ular secara tidak langsung mendukung keberlanjutan keanekaragaman hayati dan fungsi ekosistem secara keseluruhan. Di sisi lain, mitigasi potensi bahaya akibat perjumpaan manusia dengan ular perlu dilakukan melalui pendekatan edukatif dan preventif. Upaya seperti pengelolaan lingkungan permukiman agar tidak menjadi habitat tikus, peningkatan kesadaran masyarakat tentang jenis-jenis ular berbisa dan tidak berbisa, serta prosedur penanganan yang tepat saat bertemu ular sangat penting. Dengan pemahaman yang baik, masyarakat tidak hanya dapat meminimalkan risiko gigitan ular, tetapi juga berperan aktif dalam menjaga kelestarian ular sebagai komponen penting dalam ekosistem.", "type": "paragraph"}, {"id": "gnp1gf0qstk0wkac", "url": "https://unb.ac.id/wp-content/uploads/2025/12/ular-1-845x426.jpg", "type": "image", "caption": ""}, {"id": "3lzbboc55moknxn7", "url": "https://unb.ac.id/wp-content/uploads/2025/12/ular-2-845x465.jpg", "type": "image", "caption": ""}], "excerpt": "Pada tanggal 20 Desember 2025, Kelompok Mahasiswa Pencinta Herpetofauna (KMPK) diundang oleh siswa-siswi Pecinta Alam SMAN 2 Kota Bogor (PALASDA) dalam rangka kegiatan Pradiklatsar ke-3. Kegiatan ini bertujuan untuk memb...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/ular-1-845x426.jpg", "publishedAt": "2025-12-20"}, {"id": "yi0hg8b0iy2yghop", "slug": "mahasiswa-kehutanan-unb-melakukan-internship-di-perfectur-tochigi-jepang", "title": "Mahasiswa Kehutanan UNB Melakukan Internship di Perfectur Tochigi Jepang", "author": "Humas UNB", "blocks": [{"id": "ykflx4rildx0a5ii", "text": "Safrida dan Mila Mahasiswa Kehutanan UNB Melakukan Internship di Perfectur Tochigi Jepang pada Aira Farm.", "type": "paragraph"}, {"id": "ecsjtj5l99962spi", "url": "https://unb.ac.id/wp-content/uploads/2025/12/jepang-50.jpg", "type": "image", "caption": ""}], "excerpt": "Safrida dan Mila Mahasiswa Kehutanan UNB Melakukan Internship di Perfectur Tochigi Jepang pada Aira Farm.", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/jepang-50.jpg", "publishedAt": "2025-12-13"}, {"id": "tq25wuu1n2edbnfn", "slug": "lokarya-dan-penutupan-kuliah-kerja-nyata-tematik-kknt-tahun-2025-periode-ii", "title": "Lokarya dan Penutupan Kuliah Kerja Nyata Tematik (KKNT) Tahun 2025 Periode II", "author": "Humas UNB", "blocks": [{"id": "65cstwn4lic2wryj", "text": "Universitas Nusa Bangsa telah melaksanakan kegiatan kuliah kerja nyata tematik (KKNT) pada periode II tahun 2025 dengan tema \"Pembedayaan Usaha Mikro, Kecil (UMK) Berbasis Pengelolaan Sampah di Kota Bogor. Acara ini mengundang Camat Tanah Sereal Bogor, Kepala Bapperinda Kota Bogor, Rektor UNB Prof.Dr. Budi Mulyanto, dan Ketua LPPM bapak Dr.Zainal Muttaqin. Acara ini dilanjutkan dengan presentasi setiap kelompok.", "type": "paragraph"}, {"id": "9kjd7phoqlibw7nq", "url": "https://unb.ac.id/wp-content/uploads/2025/12/IMG-20251213-WA0004-845x631.jpg", "type": "image", "caption": ""}, {"id": "rigk11p5xt8ue6ym", "url": "https://unb.ac.id/wp-content/uploads/2025/12/IMG-20251206-WA0001-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Universitas Nusa Bangsa telah melaksanakan kegiatan kuliah kerja nyata tematik (KKNT) pada periode II tahun 2025 dengan tema \"Pembedayaan Usaha Mikro, Kecil (UMK) Berbasis Pengelolaan Sampah di Kota Bogor. Acara ini meng...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/IMG-20251213-WA0004-845x631.jpg", "publishedAt": "2025-12-13"}, {"id": "swok2ye3w31uk10w", "slug": "universitas-nusa-bangsa-mengundang-gilang-ramadhan-drummer-terbaik-di-indonesia-", "title": "Universitas Nusa Bangsa Mengundang Gilang Ramadhan (Drummer Terbaik di Indonesia dan Budayawan) untuk Memajukan Kegiatan Kesenian di UNB", "author": "Humas UNB", "blocks": [{"id": "qnaulgezzskkq0s3", "text": "Universitas Nusa Bangsa Mengundang Bapak Gilang Ramadhan (Drummer Terbaik di Indonesia dan Budayawan) untuk Memajukan Kegiatan Kesenian di UNB. Bapak Gilang Ramadhan tampak berfoto bersama dengan pejabat Universitas Nusa Bangsa.", "type": "paragraph"}, {"id": "ehlo2hpbrrtfj8ic", "url": "https://unb.ac.id/wp-content/uploads/2025/12/IMG-20251210-WA0003-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Universitas Nusa Bangsa Mengundang Bapak Gilang Ramadhan (Drummer Terbaik di Indonesia dan Budayawan) untuk Memajukan Kegiatan Kesenian di UNB. Bapak Gilang Ramadhan tampak berfoto bersama dengan pejabat Universitas Nusa...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/IMG-20251210-WA0003-845x684.jpg", "publishedAt": "2025-12-13"}, {"id": "nc8t3e2biiqq98he", "slug": "dosen-universitas-nusa-bangsa-menerima-bantuan-publikasi-pada-jurnal-bereputasi-", "title": "Dosen Universitas Nusa Bangsa Menerima Bantuan Publikasi pada Jurnal Bereputasi Tahun 2025 dari Kementerian dan Pendidikan Tinggi, Sains dan, Teknologi", "author": "Humas UNB", "blocks": [{"id": "ltw3p6vd2p817507", "text": "Dosen Universitas Nusa Bangsa Menerima Bantuan Publikasi pada Jurnal Bereputasi Tahun 2025 dari Kementerian dan Pendidikan Tinggi, Sains dan, Teknologi Direktorat Jenderal Riset dan Pengembangan. Peraih hibah publikasi diterima oleh masing-masing dosen yaitu: Ade Ayu Oksari, Devy Susanty, Nina Ariesta, Lalu Solihin, dan Ratna Sari Hasibuan.", "type": "paragraph"}, {"id": "mxv3f774f0cktc3a", "url": "https://unb.ac.id/wp-content/uploads/2025/12/Peraih-publikasi-845x380.jpg", "type": "image", "caption": ""}], "excerpt": "Dosen Universitas Nusa Bangsa Menerima Bantuan Publikasi pada Jurnal Bereputasi Tahun 2025 dari Kementerian dan Pendidikan Tinggi, Sains dan, Teknologi Direktorat Jenderal Riset dan Pengembangan. Peraih hibah publikasi d...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/Peraih-publikasi-845x380.jpg", "publishedAt": "2025-12-13"}, {"id": "txt3h5ca2tn750ov", "slug": "dosen-universitas-nusa-bangsa-meraih-pendanaan-riim-platform-kolaborasi-biologi-", "title": "Dosen Universitas Nusa Bangsa Meraih Pendanaan RIIM Platform Kolaborasi Biologi Struktur Biomolekul Keanekaragaman Hayati Tahun 2025", "author": "Humas UNB", "blocks": [{"id": "laiye40tqvapuzjx", "text": "Dosen Universitas Nusa Bangsa Meraih Pendanaan RIIM Platform Kolaborasi Biologi Struktur Biomolekul Keanekaragaman Hayati Tahun 2025 BRIN. Ketua penelitian Dr. Ricson Pemimpin Hutagaol.,SSi.,M.Si dengan judul dengan judul riset \"Isolasi Determinasi Struktur Senyawa Alkaloid dan Terpenoid dari Aglaia Odorata (Meliaceae).", "type": "paragraph"}, {"id": "u1nla8tg2bgnp1pf", "url": "https://unb.ac.id/wp-content/uploads/2025/12/Ricson-unb.jpg", "type": "image", "caption": ""}], "excerpt": "Dosen Universitas Nusa Bangsa Meraih Pendanaan RIIM Platform Kolaborasi Biologi Struktur Biomolekul Keanekaragaman Hayati Tahun 2025 BRIN. Ketua penelitian Dr. Ricson Pemimpin Hutagaol.,SSi.,M.Si dengan judul dengan judu...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/Ricson-unb.jpg", "publishedAt": "2025-12-13"}, {"id": "w645hospaaatatyi", "slug": "focus-group-discussion-fgd-mengenai-pemodelan-sistem-dinamik-penggunaan-lahan-da", "title": "Focus Group Discussion (FGD) mengenai Pemodelan Sistem Dinamik Penggunaan Lahan dan Ketahanan Pangan Kabupaten Bogor yang didanai melalui Hibah Fundamental Diktisaintek dilaksanakan pada tanggal 13 Desember 2025.", "author": "Humas UNB", "blocks": [{"id": "v5ldw00gzi6sluij", "text": "Focus Group Discussion (FGD) mengenai Pemodelan Sistem Dinamik Penggunaan Lahan dan Ketahanan Pangan Kabupaten Bogor yang didanai melalui Hibah Fundamental Diktisaintek dilaksanakan pada tanggal 13 Desember 2025. Kegiatan FGD ini bertempat di Kampus Universitas Nusa Bangsa dan menghadirkan narasumber Dr. Ir. Yunus Arifien, M.Si dari Universitas Nusa Bangsa, Prof. Dr. Ir. Nyak Ilham, M.Si. (BRIN), serta Ibu Rosi Yuliastini, S.Pt., M.M. dari Dinas Ketahanan Pangan Kabupaten Bogor bekerjasama dengan BEM Pertanian.", "type": "paragraph"}, {"id": "kd0hekw87q561gx7", "text": "Kegiatan ini bertujuan untuk memperoleh masukan dalam pengembangan model sistem dinamik ketahanan pangan Kabupaten Bogor, khususnya terkait dampak konversi lahan pertanian terhadap ketersediaan pangan jangka panjang. Kabupaten Bogor sebagai wilayah penyangga pangan Jawa Barat dan DKI Jakarta menghadapi tekanan pertumbuhan penduduk dan alih fungsi lahan. FGD membahas tujuan dan metodologi penelitian sistem dinamik (CLD dan SFD), indikator ketahanan pangan, serta hasil validasi dan simulasi model. Hasil simulasi menunjukkan bahwa skenario Business as Usual (BAU) berpotensi menimbulkan defisit beras sejak 2030, sementara kebijakan Perlindungan Lahan Pertanian Pangan Berkelanjutan (LP2B) mampu menjaga stabilitas produksi. Kombinasi kebijakan LP2B dan optimasi produktivitas dinilai sebagai skenario paling efektif dalam menjaga ketahanan pangan Kabupaten Bogor hingga 2045. Model yang dikembangkan dinyatakan valid dan layak digunakan sebagai alat bantu perumusan kebijakan, dengan penekanan pada pengendalian konversi lahan, peningkatan produktivitas berkelanjutan, dan penguatan sistem informasi pangan daerah. Sementara itu, paparan Dinas Ketahanan Pangan Kabupaten Bogor menekankan arah kebijakan nasional yang selaras dengan visi Bupati Bogor dalam mewujudkan Kabupaten Bogor yang Istimewa dan Gemilang. Pelayanan publik difokuskan pada ketersediaan pangan yang cukup, aman, dan bermutu; distribusi pangan yang merata dan stabil; serta konsumsi pangan beragam, bergizi, seimbang, dan aman (B2SA). Kedua paparan dalam FGD tersebut saling melengkapi dan memperkuat pembangunan ketahanan pangan Kabupaten Bogor yang berkelanjutan melalui sinergi kebijakan nasional dan daerah, perencanaan berbasis data dan pemodelan, serta integrasi aspek ekonomi, sosial, dan lingkungan, sehingga mampu menjadi landasan yang komprehensif dalam perumusan strategi dan pengambilan keputusan pembangunan pangan jangka panjang di Kabupaten Bogor.", "type": "paragraph"}, {"id": "5befa1g91oejpp1y", "url": "https://unb.ac.id/wp-content/uploads/2025/12/Fotofgd01.jpg", "type": "image", "caption": ""}, {"id": "dpi919k2oy69npef", "url": "https://unb.ac.id/wp-content/uploads/2025/12/foto-FGD.jpg", "type": "image", "caption": ""}], "excerpt": "Focus Group Discussion (FGD) mengenai Pemodelan Sistem Dinamik Penggunaan Lahan dan Ketahanan Pangan Kabupaten Bogor yang didanai melalui Hibah Fundamental Diktisaintek dilaksanakan pada tanggal 13 Desember 2025. Kegiata...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/Fotofgd01.jpg", "publishedAt": "2025-12-13"}, {"id": "qrwiw60q6uvx75x8", "slug": "unb-meraih-juara-pertama-dalam-gelar-inovasi-daerah-2025", "title": "UNB Meraih Juara Pertama dalam Gelar Inovasi Daerah 2025", "author": "Humas UNB", "blocks": [{"id": "nsm2aniagur20zmo", "text": "Gelar Inovasi Daerah (GID) diselenggarakan oleh Bappedalitbang Kabupaten Bogor sejak Tahun 2016, sehingga GID 2025 merupakan GID yang ke-9. Peserta terdiri dari kategori SMP,SMA, Perguruan Tinggi, dan Masyarakat. Penjurian dilakukan sejak bulan Oktober 2025 yang terdiri dari empat tahapan, mulai dari seleksi substansi, seleksi presentasi, samapi dengan tahap presentasi finalis. UNB yang diwakili oleh inovasi Talas Febi521 telah melewati semua tahapan sampai dengan mendapatkan penganugrahan sebagai Juara I kategori Perguruan Tinggi. Penyerahan Penghargaan Juara I diberikan langsung oleh Bupati Kabupaten Bogor Bapak Rudy Susmanto, S.Si. pada puncak acara Gelar Inovasi Daerah yang diselenggarakan pada hari Kamis 11 Desember 2025 di Amphitheater Bappedalitbang Kabupaten Bogor.", "type": "paragraph"}, {"id": "0b60huh73eq4vlpf", "url": "https://unb.ac.id/wp-content/uploads/2025/12/1000150591-1-845x624.jpg", "type": "image", "caption": ""}], "excerpt": "Gelar Inovasi Daerah (GID) diselenggarakan oleh Bappedalitbang Kabupaten Bogor sejak Tahun 2016, sehingga GID 2025 merupakan GID yang ke-9. Peserta terdiri dari kategori SMP,SMA, Perguruan Tinggi, dan Masyarakat. Penjuri...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/1000150591-1-845x624.jpg", "publishedAt": "2025-12-12"}, {"id": "4nq27n549rfdwgna", "slug": "techno-tradisi-mangrove-inovasi-inventarisasi-dan-kearifan-lokal-untuk-konservas", "title": "Techno-Tradisi Mangrove: Inovasi Inventarisasi dan Kearifan Lokal untuk Konservasi MangroveBerkelanjutan", "author": "Humas UNB", "blocks": [{"id": "grhxnqdnqqdkxoxg", "text": "Techno-Tradisi Mangrove: Inovasi Inventarisasi dan Kearifan Lokal untuk Konservasi MangroveBerkelanjutan Talkshow Kolaboratif Kampus UNB dengan Kementerian Kehutanan", "type": "paragraph"}, {"id": "xi81egizqcaabihy", "text": "Fakultas Kehutanan dan lingkungan Universitas Nusa Bangsa, pada Kamis 6 Des 2025 menggelar sebuah talkshow inspiratif bertajuk “Techno-Tradisi Mangrove: Inovasi Inventarisasi dan Kearifan Lokal untuk Konservasi Mangrove Berkelanjutan” di Auditorium Universitas Nusa Bangsa. Kegiatan ini menghadirkan akademisi, praktisi, serta mahasiswa untuk mendiskusikan integrasi teknologi modern dan pengetahuan lokal dalam menjaga ekosistem mangrove Indonesia. Talkshow ini menghadirkan narasumber utama Dr. Messalina L Salampessy.S.Hut.M.Si selaku dosen Fakultas Kehutanan dan lingkungan UNB , dan Muhammad Sufwandika Wijaya. S.Si., M.sc, dari Badan Informasi Geospasial , yang membagikan pengalaman serta pemikiran strategis terkait pendekatan community-based yang mengedepankan kearifan local masyarakat pesisir dan pemanfaatan teknologi inventarisasi, seperti drone mapping, remote sensing, sistem informasi geospasial. Dalam paparannya, para narasumber menekankan bahwa inovasi digital dan kearifan lokal masyarakat pesisir harus dipandang bukan sebagai dua pendekatan yang saling terpisah, melainkan sebagai model kolaboratif yang saling menguatkan. Teknologi inventarisasi yang akurat memungkinkan pemetaan kondisi mangrove secara cepat dan tepat, sementara kearifan local/ local ecological knowledge memberikan konteks budaya, sosial, dan pengalaman turun-temurun yang sangat penting bagi keberlanjutan konservasi. “Techno-tradisi adalah jembatan untuk memastikan bahwa upaya konservasi mangrove tidak hanya berbasis data, tetapi juga berbasis manusia dan budaya dalam bentuk kearifan local ini,” ujar Dr Messalina , yang menegaskan pentingnya integrasi dua pendekatan tersebut. Acara ini turut dihadiri oleh lebih dari 250 peserta, terdiri dari mahasiswa, dan dosen di lingkup Universitas Nusa bangsa. Antusiasme peserta terlihat dari sesi diskusi interaktif yang membahas tantangan lapangan, peluang pemanfaatan teknologi baru, serta bagaimana masyarakat dapat menjadi aktor utama dalam menjaga kelestarian mangrove. Dekan Fakultas Kehutanan Prof Luluk Setyaningsih , menyampaikan bahwa kegiatan ini merupakan bagian dari komitmen kampus untuk mendorong pendidikan lingkungan yang relevan dengan kebutuhan zaman, serta menghubungkan mahasiswa dengan isu-isu strategis pengelolaan pesisir. Selain itu pada kesempatan yang sama, Rektor Universitas Nusa Bangsa Prof Budi dalam sambutannya menyampaikan bahwa “ mahasiswa perlu sejak dini diajak untuk berperan aktif pada upaya konservasi di masyarakat pesisir, terutama dalam pengelolaan hutan mangrove” . Acara ini dibuka secara resmi dengan menyampaikan sambutan dari Direktur Rehabilitasi Mangrove Kementerian Kehutanan adalah Dr. Ristianto Pribadi, S.Hut., M.Tourism . “Kami ingin membangun generasi ilmuwan dan praktisi yang tidak hanya menguasai teknologi, tetapi juga memahami dinamika sosial di wilayah pesisir. Konservasi harus bersifat holistik,” ungkapnya. Talkshow Techno-Tradisi Mangrove diharapkan dapat mendorong peningkatan pemahaman generasi muda untuk aktif berperan aktif dalam upaya memperkuat konservasi mangrove secara berkelanjutan di Indonesia.", "type": "paragraph"}, {"id": "flbura43pa8fe81u", "url": "https://unb.ac.id/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-11-at-8.40.24-AM-844x684.jpeg", "type": "image", "caption": ""}, {"id": "g33bqbwnettdvhdq", "url": "https://unb.ac.id/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-11-at-8.56.30-AM1-845x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Techno-Tradisi Mangrove: Inovasi Inventarisasi dan Kearifan Lokal untuk Konservasi MangroveBerkelanjutan Talkshow Kolaboratif Kampus UNB dengan Kementerian Kehutanan Fakultas Kehutanan dan lingkungan Universitas Nusa Ban...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/12/WhatsApp-Image-2025-12-11-at-8.40.24-AM-844x684.jpeg", "publishedAt": "2025-12-11"}, {"id": "7sm3rvkrsk6vo62x", "slug": "pkkmb-unb-2025-langkah-awal-membangun-generasi-unggul-dan-berdaya-saing-global", "title": "PKKMB UNB 2025: Langkah Awal Membangun Generasi Unggul dan Berdaya Saing Global", "author": "Humas UNB", "blocks": [{"id": "6qy7hoov52ej7x50", "text": "Universitas Nusa Bangsa (UNB) dengan penuh semangat menyambut kedatangan mahasiswa baru melalui kegiatan Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) 2025 , yang digelar pada Sabtu–Minggu, 11–12 Oktober 2025 di Auditorium Kampus UNB . Dengan mengusung tema “Bersama Membangun Nusa Bangsa Mewujudkan Generasi Unggul, Mengglobal, dan Berkelanjutan di Era Revolusi Industri 5.0” , kegiatan ini menjadi gerbang awal bagi mahasiswa baru untuk mengenal lebih dekat dunia akademik dan kehidupan sosial di lingkungan kampus. Rangkaian Kegiatan PKKMB Kegiatan dimulai dengan upacara pembukaan , diawali registrasi peserta dan dilanjutkan dengan menyanyikan lagu kebangsaan serta mars UNB yang menggugah semangat kebersamaan. Acara kemudian dilanjutkan dengan sambutan dari pimpinan universitas , termasuk Ketua Yayasan UNB, Rektor, dan jajaran pejabat kampus. Dalam sambutannya, Ketua Yayasan menegaskan pentingnya peran mahasiswa baru sebagai generasi penerus yang berintegritas dan memiliki semangat inovatif. Beberapa pesan yang disampaikan antara lain:", "type": "paragraph"}, {"id": "9uv7do4t076lksrq", "text": "“Menjadi mahasiswa bukan hanya soal mengejar nilai, tetapi juga tentang membangun integritas, tanggung jawab, dan kepedulian sosial.”", "type": "paragraph"}, {"id": "1oxcpt5a1a4x8qtz", "text": "“Gunakanlah momentum PKKMB ini untuk menumbuhkan pribadi yang adaptif, kreatif, dan mampu berkolaborasi dengan baik.”", "type": "paragraph"}, {"id": "ph1q7nqbyd0g16bj", "text": "“UNB, melalui yayasan dan seluruh civitas akademika, siap mendampingi Anda dalam setiap langkah perjalanan akademik dan kemahasiswaan. Manfaatkan segala fasilitas dan peluang dengan sebaik mungkin.”", "type": "paragraph"}, {"id": "7vi33jj57mjy4aet", "text": "“Semoga semangat inovasi dan kolaborasi yang diusung dalam tema PKKMB ini dapat menjadi budaya kampus, melahirkan lulusan unggul yang peduli terhadap masyarakat dan lingkungan.”", "type": "paragraph"}, {"id": "6kw33gzlbtnrnqzt", "text": "Beliau juga menyampaikan apresiasi kepada seluruh panitia, dosen, tenaga kependidikan, dan pihak-pihak yang telah bekerja keras demi kesuksesan kegiatan ini. Mahasiswa juga diperkenalkan pada civitas akademika dan struktur kampus , mulai dari pimpinan fakultas dan program studi, staf akademik, tenaga kependidikan, hingga berbagai unit layanan mahasiswa. Selain itu, terdapat sesi sosialisasi kebijakan akademik dan administrasi yang menjelaskan sistem kurikulum, penilaian, pembiayaan, tata tertib, hingga penggunaan sistem informasi akademik (SIMAK). Untuk mendukung pengembangan diri, para mahasiswa mengikuti materi pengembangan karakter dan soft skills , seperti kepemimpinan, kreativitas, literasi digital, dan kegiatan pengabdian masyarakat. Tak kalah menarik, mereka juga mendapat kesempatan untuk mengenal organisasi kemahasiswaan dan Unit Kegiatan Mahasiswa (UKM) , yang menjadi wadah menyalurkan minat, bakat, serta semangat kolaborasi. Acara ditutup oleh Wakil Rektor I UNB (Prof. Dr. Ucu Cahyana, ) dilengkapi dengan sesi refleksi, penyerahan penghargaan bagi peserta aktif, serta foto bersama seluruh civitas akademika sebagai simbol kebersamaan. Makna PKKMB 2025 Melalui PKKMB 2025, UNB berharap mahasiswa baru dapat lebih cepat beradaptasi dengan lingkungan akademik, memahami sistem pembelajaran, dan menjalin hubungan harmonis dengan sesama mahasiswa, dosen, serta tenaga kependidikan. Kegiatan ini juga diharapkan mampu menumbuhkan semangat kolaborasi, membentuk karakter yang tangguh dan beretika, serta memupuk kepedulian sosial dan semangat berinovasi. Dengan terselenggaranya PKKMB secara sukses dan penuh makna, Universitas Nusa Bangsa menegaskan kembali komitmennya untuk mencetak generasi muda yang tidak hanya cerdas dan kompetitif, tetapi juga berintegritas, berbudaya, dan peduli terhadap keberlanjutan bangsa.", "type": "paragraph"}, {"id": "loylj0ua8yfzpqgl", "url": "https://unb.ac.id/wp-content/uploads/2025/10/IMG_1076-845x684.jpg", "type": "image", "caption": ""}, {"id": "kdowhzfdbfzrtknx", "url": "https://unb.ac.id/wp-content/uploads/2025/10/IMG_1857-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Universitas Nusa Bangsa (UNB) dengan penuh semangat menyambut kedatangan mahasiswa baru melalui kegiatan Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) 2025 , yang digelar pada Sabtu–Minggu, 11–12 Oktober 2025 d...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/10/IMG_1076-845x684.jpg", "publishedAt": "2025-10-13"}, {"id": "28rdbg4my0zg52tg", "slug": "biro-kemahasiawaan-dan-alumni-melalui-pusat-karir-dan-alumni-akan-menyelengaraka", "title": "Biro kemahasiawaan dan Alumni melalui pusat karir dan alumni , akan menyelengarakan webinar ke-2, juga akan dilaksanakan Rekrutmen dari PT.BRI sekaligus melaksanakan wawancara secara offline di Universitas Nusa Bangsa", "author": "Humas UNB", "blocks": [{"id": "csh1z37rlm6ditb6", "text": "Nomor : 40 /BKA-UNB/F/X/2025 Bogor, 02 Oktober 2025 Lampiran : 1 Berkas Perihal : Undangan Kepada Yth. 1. Rektor 2. Para Wakil Rektor 3. Para Dekan Fakultas 4. Para Ketua Lembaga 5. Para Ka.Progam Studi 6. Para Kabiro 7. Juli Yanti Nasution S.P ( Alumni Pertanian UNB) 8. Widaningsih S.Si., M.M ( Alumni F-MIPA UNB ) 9. Kirana Intaniasari S.H.,M.H ( PT. BRI ) 10. Mega Mutmainah (Mahasiswa Agroteknopreneur dan Agraria UNB) 11. Presma dan Para Ketua BEM Fakultas UNB 12. Para Alumni UNB Angkatan 1993 – 2024 13. Para Mahasiswa UNB Lingkup Universitas Nusa Bangsa di Tempat Dengan hormat, Sehubungan akan diadakannya Webinar ke – 2 Salam Sapa Alumni dan Rekrutmen PT.BRI (Persero) Tbk dengan Tema “Bersama Alumni Universitas Nusa Bangsa Menciptakan Masa Depan” kami mengundang Bapak/Ibu Sdr/Sdri untuk dapat mengikuti Webinar ke-2 yang akan di laksanakan pada : Hari/tanggal : Kamis, 9 Oktober 2025 Waktu : 10.00 – 12.00 WIB Pembicara : Juli Yanti Nasution, S.P ( Alumni Pertanian UNB ) Widaningsih. S.Si., M.M ( Alumni F-MIPA UNB ) Kirana Intaniasari, S.H.,M.H ( PT. BRI ) Moderator : Mega Mutmainah (Mahasiswa Agroteknopreneur dan Agraria UNB) Via : Zoom meeting Link : https://bit.ly/webinaralumniunb25 Demikian disampaikan, atas perhatian dan kerjasamanya diucapkan terima kasih. Biro Kemahasiswaan dan Alumni Universitas Nusa Bangsa Kepala, Dra. Febi Nurilmala, M.Si. Tembusan : 1. Rektor 2. Wakil Rektor I 3. Wakil Rektor II 4. Wakil Rektor III 5. Ketua Ikatan Alumni UNB 6. Arsip", "type": "paragraph"}, {"id": "452m2s359pn1fhgc", "url": "https://unb.ac.id/wp-content/uploads/2025/10/WhatsApp-Image-2025-10-03-at-16.39.07-1-845x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Nomor : 40 /BKA-UNB/F/X/2025 Bogor, 02 Oktober 2025 Lampiran : 1 Berkas Perihal : Undangan Kepada Yth. 1. Rektor 2. Para Wakil Rektor 3. Para Dekan Fakultas 4. Para Ketua Lembaga 5. Para Ka.Progam Studi 6. Para Kabiro 7....", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/10/WhatsApp-Image-2025-10-03-at-16.39.07-1-845x684.jpeg", "publishedAt": "2025-10-03"}, {"id": "2gots5etkmfpppro", "slug": "mahasiswa-feb-unb-sukses-mengikuti-internastional-internship-di-osaka-jepang", "title": "Mahasiswa FEB UNB Sukses Mengikuti Internastional Internship di Osaka, Jepang", "author": "Humas UNB", "blocks": [{"id": "41ymit3a250mzzlj", "text": "Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa kembali mencatatkan prestasi membanggakan! Sebanyak 14 mahasiswa terpilih untuk mengikuti program internship internasional di salah satu perusahaan multinasional Jepang, yaitu SEIWA WAX LOGISTIC Co. Ltd. Dan tahun 2025 ini adalah angkatan ke 3. Program ini tidak hanya membuka wawasan global, tetapi juga memberikan pengalaman kerja nyata di lingkungan industri berstandar internasional.", "type": "paragraph"}, {"id": "9mnrzpj414brt1yv", "text": "Selama mengikuti internship, mahasiswa FEB UNB berkesempatan mempelajari budaya kerja profesional di Jepang, mengasah keterampilan teknis, serta memperkuat soft skills seperti kedisiplinan, kerja tim, dan komunikasi lintas budaya. Keberhasilan ini menjadi bukti nyata bahwa UNB mampu mencetak lulusan yang kompetitif, berdaya saing global, dan siap menghadapi tantangan dunia kerja internasional.", "type": "paragraph"}, {"id": "3bop7pt4o3fhw6gy", "text": "Jajaran pimpinan UNB menyampaikan apresiasi yang tinggi kepada mahasiswa dan seluruh pihak yang terlibat, serta menegaskan bahwa UNB akan terus memperluas jejaring kerja sama internasional untuk memberikan lebih banyak peluang bagi mahasiswa, tidak hanya FEB tapi juga semua fakultas yang ada di UNB.", "type": "paragraph"}, {"id": "0v2qkjowze4jhsib", "text": "Ingin merasakan pengalaman kuliah yang tidak hanya fokus pada teori, tetapi juga membuka jalan menuju karier internasional? Daftarkan dirimu sebagai mahasiswa FEB UNB dan jadilah bagian dari generasi muda yang siap berkiprah di kancah global.", "type": "paragraph"}, {"id": "04xyf9327uoik94u", "text": "📌 Informasi pendaftaran dapat diakses melalui website resmi UNB atau langsung menghubungi tim Humas UNB.", "type": "paragraph"}, {"id": "h3xy03c7v4hbjy29", "url": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-25-at-13.13.35-845x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa kembali mencatatkan prestasi membanggakan! Sebanyak 14 mahasiswa terpilih untuk mengikuti program internship internasional di salah satu perusahaan multinasional Jepang...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-25-at-13.13.35-845x684.jpeg", "publishedAt": "2025-09-25"}, {"id": "s3bn8fzfy4x2pp5v", "slug": "mahasiswa-feb-unb-sukses-mengikuti-internastional-internship-di-osaka-jepang-20250925", "title": "Mahasiswa FEB UNB Sukses Mengikuti Internastional Internship di Osaka, Jepang", "author": "Humas UNB", "blocks": [{"id": "kp63uj8algq48fw4", "text": "Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa kembali mencatatkan prestasi membanggakan! Sebanyak 14 mahasiswa terpilih untuk mengikuti program internship internasional di salah satu perusahaan multinasional Jepang, yaitu SEIWA WAX LOGISTIC Co. Ltd. Dan tahun 2025 ini adalah angkatan ke 3. Program ini tidak hanya membuka wawasan global, tetapi juga memberikan pengalaman kerja nyata di lingkungan industri berstandar internasional. Selama mengikuti internship, mahasiswa FEB UNB berkesempatan mempelajari budaya kerja profesional di Jepang, mengasah keterampilan teknis, serta memperkuat soft skills seperti kedisiplinan, kerja tim, dan komunikasi lintas budaya. Keberhasilan ini menjadi bukti nyata bahwa UNB mampu mencetak lulusan yang kompetitif, berdaya saing global, dan siap menghadapi tantangan dunia kerja internasional. Jajaran pimpinan UNB menyampaikan apresiasi yang tinggi kepada mahasiswa dan seluruh pihak yang terlibat, serta menegaskan bahwa UNB akan terus memperluas jejaring kerja sama internasional untuk memberikan lebih banyak peluang bagi mahasiswa, tidak hanya FEB tapi juga semua fakultas yang ada di UNB. Ingin merasakan pengalaman kuliah yang tidak hanya fokus pada teori, tetapi juga membuka jalan menuju karier internasional? Daftarkan dirimu sebagai mahasiswa FEB UNB dan jadilah bagian dari generasi muda yang siap berkiprah di kancah global. 📌 Informasi pendaftaran dapat diakses melalui website resmi UNB atau langsung menghubungi tim Humas UNB.", "type": "paragraph"}, {"id": "vlexdi2vvwr8hog1", "url": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-25-at-13.13.35-845x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa kembali mencatatkan prestasi membanggakan! Sebanyak 14 mahasiswa terpilih untuk mengikuti program internship internasional di salah satu perusahaan multinasional Jepang...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-25-at-13.13.35-845x684.jpeg", "publishedAt": "2025-09-25"}, {"id": "r5jhoa6o1cf9c24v", "slug": "fakultas-kehutanan-unb-dan-pusat-pengembangan-hutan-berkelanjutan-kementerian-ke", "title": "Fakultas Kehutanan UNB dan Pusat Pengembangan Hutan Berkelanjutan- Kementerian Kehutanan Sepakati Tindak Lanjut Pengelolaan KHDTK Haurbentes", "author": "Humas UNB", "blocks": [{"id": "q55n07seo22wmyud", "text": "Bogor, 11 September 2025 – Fakultas Kehutanan Universitas Nusa Bangsa (Fahutan UNB) bersama Pusat Pengembangan Hutan Berkelanjutan (P2HB) Kementerian Kehutanan melakukan tindak lanjut kerjasama strategis terkait pengelolaan Kawasan Hutan Dengan Tujuan Khusus (KHDTK) Haurbentes. Pertemuan ini membahas pembentukan tim pelaksana yang akan mengawal implementasi kegiatan di KHDTK. Kepala P2HB, Gun Gun Hidayat, Ph.D., menyampaikan harapan agar kerjasama ini segera terealisasi. “Kami berharap proses pembentukan tim dan implementasi di lapangan dapat berjalan dengan cepat, sehingga KHDTK Haurbentes benar-benar menjadi model pengelolaan hutan berkelanjutan di Indonesia,” ujar Gun Gun. Pelaksanaan kegiatan resmi dimulai pada Senin, 15 September 2025, dengan lingkup program meliputi:", "type": "paragraph"}, {"id": "u0b2t9y7ntsi4ncj", "text": "Identifikasi potensi KHDTK Haurbentes", "type": "paragraph"}, {"id": "my0ulh5ngc118jav", "text": "Pengembangan mikoriza hayati", "type": "paragraph"}, {"id": "0uirz6y4w7ycnm56", "text": "Pemberdayaan masyarakat sekitar hutan", "type": "paragraph"}, {"id": "kmwbsxs99gbtibaf", "text": "Pengelolaan wisata berbasis konservasi", "type": "paragraph"}, {"id": "3n4ftmwkrs539cdo", "text": "Dekan Fakultas Kehutanan UNB, Prof. Dr. Ir. Luluk Setyaningsih, menekankan pentingnya kolaborasi multipihak. “Kerjasama ini akan lebih optimal jika melibatkan seluruh stakeholder, mulai dari pemerintah, akademisi, masyarakat, hingga sektor swasta. Dengan demikian, target kegiatan dapat tercapai secara menyeluruh,” tegasnya. Melalui langkah ini, Fahutan UNB dan P2HB berkomitmen menjadikan KHDTK Haurbentes sebagai pusat pembelajaran, penelitian, sekaligus model pengelolaan hutan yang berkelanjutan dan bermanfaat bagi masyarakat.", "type": "paragraph"}, {"id": "32letexs1mo04k0q", "url": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-11-at-16.31.29-845x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 11 September 2025 – Fakultas Kehutanan Universitas Nusa Bangsa (Fahutan UNB) bersama Pusat Pengembangan Hutan Berkelanjutan (P2HB) Kementerian Kehutanan melakukan tindak lanjut kerjasama strategis terkait pengelol...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/09/WhatsApp-Image-2025-09-11-at-16.31.29-845x684.jpeg", "publishedAt": "2025-09-11"}, {"id": "j4rfra369anhdvq3", "slug": "perempuan-tani-di-bogor-dibekali-ilmu-keuangan-dan-rencana-usaha", "title": "Perempuan Tani di Bogor Dibekali Ilmu Keuangan dan Rencana Usaha", "author": "Humas UNB", "blocks": [{"id": "3kxd6ryby2e5huwj", "text": "Di sebuah aula sederhana di Kelurahan Kencana, Kecamatan Tanah Sareal, Kota Bogor, Senin (8/9/2025), suasana ramai dipenuhi semangat belajar puluhan anggota Kelompok Wanita Tani (KWT) Griya Amanah dan KWT Beringin. Mereka bukan hanya belajar cara menanam sayuran melalui urban farming, tetapi kini dibekali pengetahuan baru: bagaimana mengatur keuangan dan menyusun rencana usaha. Pelatihan ini digagas oleh Tim PKM Fakultas Agroteknopreuner & Agraria Universitas Nusa Bangsa (UNB) yang terdiri dari dosen dan mahasiswa. Program ini merupakan bagian dari kegiatan peningkatan ketahanan pangan keluarga melalui urban farming yang didanai Hibah Dikti 2025. Sari Anggarawati, ketua tim, menjelaskan bahwa perempuan tani perlu memiliki pemahaman keuangan yang baik agar usaha kelompok lebih mandiri. Ia percaya, dengan perencanaan bisnis yang matang, produk hasil pertanian lokal akan mampu bersaing di pasar. Materi diberikan oleh Mulyana Gustira Putra, dosen Fakultas Ekonomi dan Bisnis UNB. Para peserta diperkenalkan pada pencatatan arus kas sederhana, cara menabung, hingga strategi pemasaran. Tak berhenti di teori, mereka juga langsung mencoba membuat business plan sesuai usaha yang sedang dirintis. Bagi Devi Azriani, salah satu anggota KWT, pengalaman ini terasa berharga. “Sekarang kami lebih tahu bagaimana mengelola uang usaha dan lebih percaya diri mengembangkan produk olahan pertanian,” ujarnya dengan antusias. Pelatihan juga mendapat dukungan penuh dari Plt Lurah Kencana, Aristianingsih. Ia berharap ilmu yang diperoleh tidak berhenti pada peserta saja, tetapi menyebar ke kelompok lain di sekitar kelurahan. Sebagai penutup, setiap kelompok menerima bantuan peralatan pertanian urban farming. Harapannya, dengan bekal ilmu dan dukungan sarana ini, KWT bisa meningkatkan produksi, memperluas usaha, sekaligus memberi kontribusi pada perekonomian keluarga dan lingkungan sekitar.", "type": "paragraph"}, {"id": "k6ze4p64uhyig2m7", "url": "https://unb.ac.id/wp-content/uploads/2025/09/11-845x684.jpg", "type": "image", "caption": ""}], "excerpt": "Di sebuah aula sederhana di Kelurahan Kencana, Kecamatan Tanah Sareal, Kota Bogor, Senin (8/9/2025), suasana ramai dipenuhi semangat belajar puluhan anggota Kelompok Wanita Tani (KWT) Griya Amanah dan KWT Beringin. Merek...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/09/11-845x684.jpg", "publishedAt": "2025-09-09"}, {"id": "fd1atclav5134lrr", "slug": "universitas-nusa-bangsa-bogor-menjadi-pusat-peradaban-asia-dengan-mengadakan-iso", "title": "UNIVERSITAS NUSA BANGSA BOGOR MENJADI PUSAT PERADABAN ASIA DENGAN MENGADAKAN ISOGOC V (International Seminar On Government And Civilization) Cross-Civilization In The Industrial Revolution 5.0 : Politics, Science And Environmental Sustainability", "author": "Humas UNB", "blocks": [{"id": "vpheersazri1k5a5", "text": "Kampus Universitas Nusa Bangsa Bogor pada hari selasa tanggal 2 September 2025 mengadakan kerjasama dengan Universitas Nusa Putera Malaysia kegiatan ISOGOC V ( International Seminar On Government And Civilization Cross-Civilization In The Industrial Revolution 5.0 ) melalui daring dan luring. Tema yang diusung adalah Politics, Science And Environmental Sustainability. Kegiatan seminar dimulai dengan menyanyikan lagu kebangsaan kedua Negara, dan dilanjutkan dengan sambutan dari Universitas Nusa Bangsa oleh Prof. Dr.Ucu Cahyana selaku wakil rektor bidang akademik dan Dr. Mohd Mahadee Ismail selaku Ketua Jabatan Pengajian Kenegaraan dan Ketamadunan, Universitas Putera Malaysia.", "type": "paragraph"}, {"id": "2fl51ft4gf9rllbi", "text": "Acara Seminar ini dibuka oleh Walikota Bogor Dedie Abdu Rachim. Dalam pidatonya, walikota sangat berharap agar acara ini dapat berkontribusi bagi penguatan silaturahmi antar bangsa dan juga bagi pengembangan keilmuan tata kelola pemerintahan kota Bogor.", "type": "paragraph"}, {"id": "fy2zkidix4rihely", "text": "Walikota Bogor membuka Seminar didampingi Prof. DR. Ucu Cahyana (UNB)", "type": "paragraph"}, {"id": "9k67nmn7zvyys20e", "text": "dan disaksikan oleh DR. Mohd Mahadee Ismail", "type": "paragraph"}, {"id": "enxjnq0zsj42u0mc", "text": "Keynote speaker ISOGOC V berasal dari Indonesia, Malaysia dan Singapura. Pertama, Prof. Dr. Ir. Budi Mulyanto, M.Sc (UNB-Indonesia), yang menampilkan tematik INDONESIA Challenges and Opportunities for Sustainable Oil Palm Smallholder Plantations in the Market Globalization (Tantangan dan Peluang Perkebunan Kelapa Sawit Rakyat yang Berkelanjutan di Era Globalisasi Pasar). Prof Budi sangat menekankan pentingnya jaminan pasar global dan berkelanjutan bagi industri sawit di Indonesia. Selanjutnya Prof. Dr. Zaid Ahmad (International Islamic University Malaysia, Amal Putra, UPM, Malaysia) dengan tema Humanizing Education and Reclaiming Wisdom: Indigenous Knowledge and The Challenges Of Ir 5.0 (Memanusiakan Pendidikan dan Merebut Kembali Kearifan: Pengetahuan Adat dan Tantangan IR 5.0). Intinya Prof. Zaid menekankan proses humanisasi ditengah-tengah gempuran teknologi. AI ( Artificial Inteligent ) jangan dijadikan musuh tetapi harus dijadikan asisten dalam bekerja.", "type": "paragraph"}, {"id": "7c753qm8rdlobvdb", "text": "Keynote Speaker : Prof. Dr. Zaid Ahmad (UPM), Prof. Dr. Ucu Cahyana (UNB)", "type": "paragraph"}, {"id": "w3novfa5nx407yb9", "text": "dan panitia dari UPM Dr. Ratna Roshida Ab. Razak", "type": "paragraph"}, {"id": "0d17b7gvkgrqlpes", "text": "Terakhir dan agak berbeda dengan kedua keynote speaker sebelumnya, Dr. Max Lane (Senior Visiting Fellow, Yusof Ishak Institute, Singapore) menyajikan tema khusus yang berjudul : Indonesia: State Power and Civil Society at a Time of Socio-Economic Dead End (Indonesia: Kekuasaan Negara dan Masyarakat Sipil di Masa Kebuntuan Sosial-Ekonomi). Dr. Max Lane dengan tidak bermaksud mendikotomikan antara kekuasaan Negara dan masyarakat sipil di tengah-tengah krisis sosial dan ekonomi di Indonesia, tetapi diharapkan keduanya saling melengkapi dan bersinergi, mengingat sangat kritisnya kestabilan bangsa dan Negara Indonesia. Sesi ini dipandu oleh panitia dari UPM Malaysia Assoc. Prof. Dr. Ratna Roshida Ab. Razak. Peserta Seminar diikuti kalangan akademisi, peneliti dan pelaku industri dan masyarakat sipil lainnya dari negara Malaysia, Singapura, Pakistan, Cina dan Indonesia. Peserta berjumlah 133 orang yang terdiri dari 33 orang presenter offline, 30 orang presenter online, 45 non presenter dan 25 orang mahasiswa UNB. Kelancaran acara ini tidak luput juga dari peran sponsor yang telah banyak membantu dari sisi pendanaan, antara lain : Badan Pertanahan Nasional (BPN) Kab. Subang, BPN Kab. Bogor, PT Antam Tbk. UB Pertambagan Emas Pongkor, PT Wanantara Alesha Sadhana, PT Meganesia Tirta Foresta, BPN Depok, PT NKL (Nusa Kelola pLestari), LSPHI (Lembaga Sertifikasi Profesi Kehutanan Indonesia) dan Dosen Peserta. Peserta Onsite ISOGOC V", "type": "paragraph"}, {"id": "zfgq9jdgpikagqd1", "text": "Humas Universitas Nusa Bangsa Bogor", "type": "paragraph"}, {"id": "j03oxguxx49vy9nf", "text": "2 September 2025", "type": "paragraph"}, {"id": "isxoa00i7wevlohn", "text": "Baktos, Agus Pranamulia", "type": "paragraph"}, {"id": "5or37jo99013b211", "url": "https://unb.ac.id/wp-content/uploads/2025/09/2.png", "type": "image", "caption": ""}, {"id": "kf62m0qwv8o4dgmt", "url": "https://unb.ac.id/wp-content/uploads/2025/09/1.png", "type": "image", "caption": ""}], "excerpt": "Kampus Universitas Nusa Bangsa Bogor pada hari selasa tanggal 2 September 2025 mengadakan kerjasama dengan Universitas Nusa Putera Malaysia kegiatan ISOGOC V ( International Seminar On Government And Civilization Cross-C...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/09/2.png", "publishedAt": "2025-09-04"}, {"id": "app93ciwyo0zt9j9", "slug": "pascasarjana-ekonomi-pembangunan-adakan-kuliah-umum", "title": "Pascasarjana Ekonomi  Pembangunan  adakan Kuliah Umum", "author": "Humas UNB", "blocks": [{"id": "8uo1bx100nljp15r", "text": "Bogor, 21 Juli 2025 Pascasarjana Universitas Nusa Bangsa Prodi Ekonomi Pembangunan, adakan kegiatan Kuliah Umum Ekonomi Sumberdaya Manusia dan Ketenagakerjaan pada hari Senin tanggal 21 Juli 2025 diruang Auditorium Universitas Nusa Bangsa. Pada kesempatan itu hadir Rektor Universitas Nusa Bangsa Prof. Dr. Ir Budi Mulyanto, MSc dan Wakil Rektor 3 Universitas Nusa Bangsa Dr. Karmanah, SP., MSi memberikan sambutan pada acara tersebut. Acra dimulai setelah dinyanyikan lagu Indonesia Raya dan Doa oleh Heri Susanto, SE., MM. Pada intinya pimpinan sangat bersemangat atas terselenggara kegiatan kuliah umum tersebut terutama pada program pascasarjana ekonomi pembagunan. Walaupun dalam kondisi bekerja para mahasiswa bisa meluangkan waktunya untuk melaksanakan kegiatan kuliah umum. Selain itu juga menjadika persiapan pada para peserta lainnya untuk mempersiapkan diri didunia kerja. Pada kegiatan itu juga dihadiri oleh Ka Biro Kemahasiswaan dan Alumni Febi Nurilmala, S.Si., MSi dan Ka. Prodi Pascasarjana Ekonomi Pembangunan Dr. Anna Fitria, S.P, MSi, para Dosen, mahasiswa Pascarsajana dan para peserta lainnya. Pada kesempatan tersebut ada 2 (dua) narasumber pertama yakni Andrian Aziz Widodo, MM., MSi., ME., MKM., MLing dengan tema Kecerdesan Buatan (AI) : Peluang, Tantangan dan Prospek bagi Human Capital di Indonesia. Sedangkan narasumber kedua yakni Dr. Enirawan , SP., MSi dengan tema Respon Kebijakan Pemerintah dalam Menghadapi Disrupsi Ketenagakerjaan. Acara dipandu oleh moderator yakni Iis Anisa Yulia, SE., MM.", "type": "paragraph"}, {"id": "3cyzv3w7wbgkgecr", "url": "https://unb.ac.id/wp-content/uploads/2025/07/WhatsApp-Image-2025-07-21-at-14.17.03-720x684.jpeg", "type": "image", "caption": ""}, {"id": "ujq6xpwt3ct6mjhd", "url": "https://unb.ac.id/wp-content/uploads/2025/07/WhatsApp-Image-2025-07-21-at-14.17.03-1-720x684.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 21 Juli 2025 Pascasarjana Universitas Nusa Bangsa Prodi Ekonomi Pembangunan, adakan kegiatan Kuliah Umum Ekonomi Sumberdaya Manusia dan Ketenagakerjaan pada hari Senin tanggal 21 Juli 2025 diruang Auditorium Unive...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/07/WhatsApp-Image-2025-07-21-at-14.17.03-720x684.jpeg", "publishedAt": "2025-07-22"}, {"id": "n66zu2ls89ey0s6f", "slug": "universitas-nusa-bangsa-adakan-dies-natalis-yang-ke-38", "title": "UNIVERSITAS NUSA BANGSA ADAKAN DIES NATALIS YANG KE-38", "author": "Humas UNB", "blocks": [{"id": "lxpv61cbux78uvrl", "text": "Bogor, 30 Juni 2025 di Gedung Auditorium, Universitas Nusa Bangsa Dies Natalis yang ke-38 dengan dirangkaikan Gebyar “ GEMA PENTING ” (Gerakan Umat Beragama Peduli Stunting) Tahun 2025 dengan Tema “ Peduli Lingkungan, Keluarga dan Bangsa Menuju Indonesia Emas 2045 ” dengan Ketua Panitia Dra. Febi Nurilmala, MSi. Pada kesempatan itu hadir Ketua Yayasan Pengembangan dan Mutu Kehidupan Nusantara Ir. Doddy Imron Cholid, MS. Rektor beserta Civitas Universitas Nusa Bangsa, Walikota Bogor diwakili oleh Kepala Dinas Pengendalian Penduduk dan Keluarga Berencana Kota Bogor Drs. Anas S. Rasmana, M.M., para tokoh agama, Pemkot Bogor, DPPKB, ICMI PT. Kalbe Milco para-alumni Universitas Nusa Bangsa serta seluruh rekan-rekan mahasiswa Universitas Nusa Bangsa. Kegiatan diawali dengan pembacaan do’a oleh Ki Guru Agus Pranamulia sekaligus tawasulan khususnya untuk para pendiri Bogor sejak abad 15 dan Universitas Nusa Bangsa yang sudah wafat. Dilanjutkan dengan sambutan Rektor Universitas Nusa Bangsa dan pemotongan kue oleh Prof. Dr. Ir. Budi Mulyanto, MSc, beliau menyampaikan tentang kondisi perkembangan dan prestasi yang sudah diperoleh oleh Universitas Nusa Bangsa, baik para dosen dan mahasiswa serta kampus itu sendiri diantaranya melalui kerjasama. Sambutan berikutnya disampaikan oleh Wali Kota Bogor yang disampaikan oleh Kepala Dinas Pengendalian Penduduk dan Keluarga Berencana Kota Bogor Drs. Anas S. Rasmana, M.M., dalam pesannya Wali Kota Bogor menyampaikan perkembangan Universitas Nusa Bangsa yang cukup signifikan dirangkaikan Gebyar “ GEMA PENTING ” (Gerakan Umat Beragama Peduli Stunting) Tahun 2025 dengan Tema “Peduli Lingkungan, Keluarga dan Bangsa Menuju Indonesia Emas 2045”, dalam kesempatan acara tersebut ditandatangi juga PKS LPPM UNB dengan DPPKB terkait pengabdian Masyarakat, kemudian MoU Pemda Kota Bogor dengan UNB serta bersama tokoh lintas agama merupakan salah satu upaya pemerintah dalam mengurangi angka stunting, terutama dalam edukasi pada masyarakat. Pada acara tersebut juga sebagai bukti nyata Pemda dan UNB bersama PT. Kalbe Milco membagikan susu botol kepada masyarakat sekitar. Acara Dies Natalis UNB yang ke-38 juga dimeriahkan oleh penampilan reptil show dari Unit Kegiatan Mahasiswa dan solo vocal dari Alumni Fakultas MIPA, pemeriksaaan kesehatan oleh Puskesmas Kayu Manis (Dinas Kesehatan Kota Bogor) dan pemeriksaaan mata oleh Black and White Optica melalui Koperasi Kosiva UNB diakhiri dengan acara Talkshow dengan tema “Peduli Lingkungan, Keluarga dan Bangsa Menuju Indonesia Emas 2045” dengan nara sumber talkshow dlm podcast UNB:", "type": "paragraph"}, {"id": "9gedknqtsecuvdz5", "text": "Dr. Karmanah, SP, M.Si. Bicara tentang lingkungan (UNB)", "type": "paragraph"}, {"id": "dk6nkrratnjtyrmm", "text": "⁠Dr. Arijulmaman, M.H.I. bicara tentang Keluarga (ICMI Kota Bogor)", "type": "paragraph"}, {"id": "76q739tw45vwafm5", "text": "⁠Dr. Yulina Eva Riany bicara tentang Gender dan Anak (IPB University)", "type": "paragraph"}, {"id": "1mifra5lyltifazp", "text": "Dr. Arief R. Badrudin, M.M. bicara tentang Stunting (DPPKB)", "type": "paragraph"}], "excerpt": "Bogor, 30 Juni 2025 di Gedung Auditorium, Universitas Nusa Bangsa Dies Natalis yang ke-38 dengan dirangkaikan Gebyar “ GEMA PENTING ” (Gerakan Umat Beragama Peduli Stunting) Tahun 2025 dengan Tema “ Peduli Lingkungan, Ke...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-06-30"}, {"id": "iyehde6t1s6vn4qs", "slug": "bamboo-sanctuary-pancawati-dan-fakultas-kehutanan-universitas-nusa-bangsa-adakan", "title": "Bamboo Sanctuary Pancawati dan Fakultas Kehutanan Universitas Nusa Bangsa adakan Kegiatan Pelestrarian Gedepahala", "author": "Humas UNB", "blocks": [{"id": "fz2totwwlp5sn9lh", "text": "“Yuk Lestarikan Bumi Part 2” Sukses Digelar di Bogor: Ketua Pelaksana Yuhika Afrisky Dorong Kolaborasi untuk Pelestarian Gedepahala ________________________________________ Bogor, 1 Juni 2025 - Kegiatan pelestarian lingkungan bertajuk “Yuk Lestarikan Bumi Part 2” sukses diselenggarakan pada Minggu, 1 Juni 2025, di Plaza Node Café and Lounge, Pancawati, Bogor. Acara ini menjadi wadah dialog dan aksi nyata pelestarian alam yang merupakan hasil kolaborasi antara Bamboo Sanctuary Pancawati dan Fakultas Kehutanan Universitas Nusa Bangsa, serta melissbatkan berbagai elemen masyarakat - mulai dari akademisi, pelajar, kelompok pemuda, sektor swasta, komunitas konservasi, LSM, hingga perwakilan pemerintah dan masyarakat umum. Ketua Pelaksana, Yuhika Afrisky, menyampaikan bahwa kegiatan ini merupakan bentuk nyata dari kepedulian kolektif terhadap pelestarian bentang alam strategis Gede Pangrango dan Halimun Salak (Gedepahala), sekaligus menjadi ajang penguatan jejaring antaraktor konservasi di tingkat lokal maupun nasional. ________________________________________ Dengan mengusung tema “Menguatkan Peran Generasi Muda, Komunitas Konservasi, Guru, Swasta, dan Masyarakat untuk Pelestarian Keanekaragaman Hayati di Gede Pangrango dan Halimun Salak,” kegiatan ini bertujuan membangun sinergi lintas sektor guna melindungi kekayaan biodiversitas di kawasan Gedepahala. ________________________________________ Registrasi peserta dibuka pada pukul 08.30 WIB, dan acara resmi dimulai pukul 08.55 WIB dengan pembukaan oleh pembawa acara, Ibu Yani, S.Hut., M.M. Sambutan pertama disampaikan oleh Bapak Daniel Arjuna Filgo, Direktur Bamboo Sanctuary Pancawati, yang menegaskan pentingnya keterlibatan komunitas lokal dalam konservasi. Sambutan kedua disampaikan oleh Prof. Dr. Ir. Luluk Setyaningsih, S.Hut., M.Si., IPU, Dekan Fakusltas Kehutanan Universitas Nusa Bangsa, yang diwakili oleh Bapak Dwi Agus Sasongko, S.Hut., M.Si. Ia menyoroti peran akademisi dan mahasiswa dalam pelestarian lingkungan. ________________________________________ Acara ini juga dihadiri oleh dua tokoh penting konservasi, yakni Ir. Arief Mahmud, M.Si., Kepala Balai Besar Taman Nasional Gunung Gede Pangrango, dan Bapak Budhi Chandra, S.H., M.H., Kepala Balai Taman Nasional Gunung Halimun Salak. Dalam sambutannya, Ir. Arief Mahmud menekankan pentingnya keterlibatan generasi muda dan komunitas dalam menjaga kawasan taman nasional. Sementara itu, Bapak Budhi Chandra menyampaikan bahwa keberhasilan konservasi hanya dapat dicapai melalui pendekatan kolaboratif yang menyatukan berbagai pemangku kepentingan. ________________________________________ Rangkaian kegiatan kemudian berlanjut ke sesi diskusi panel bertema “Potensi dan Tantangan Pelestarian Bentang Alam Gedepahala” yang menghadirkan tiga narasumber utama. Dr. (H.C.) Ir. Wahjudi Wardojo, M.Sc., mantan Sekretaris Jenderal KLHK dan anggota Konsorsium Gedepahala, membuka diskusi dengan menguraikan pentingnya menjaga lanskap Gedepahala secara berkelanjutan. Dr. Dolly Priatna, Direktur Eksekutif Belantara Foundation dan dosen Universitas Pakuan, menyoroti ancaman degradasi lingkungan di wilayah penyangga antara Gunung Gede Pangrango dan Halimun Salak. Sementara itu, Bapak Dwi Agus Sasongko, S.Hut., M.Si., dosen Fakultas Kehutanan Universitas Nusa Bangsa, menekankan peran strategis generasi muda, guru, dan sektor swasta dalam pengelolaan lingkungan yang inklusif dan berkelanjutan. Diskusi berlangsung interaktif dan diakhiri dengan sesi tanya jawab yang memperkuat interaksi antara peserta dan narasumber. ________________________________________ Memasuki sesi kedua bertajuk “Sorotan Spesies Kunci Gedepahala,” sejumlah pelaku konservasi membagikan kisah inspiratif dari lapangan. Dr. Sofian Iskandar memaparkan upaya pelestarian primata endemik Jawa, Owa Jawa, yang kini terancam punah. Selanjutnya, perwakilan dari Yayasan PUTER Indonesia, Bapak Asep Mulyana, menyampaikan edukasi terkait habitat dan pelestarian Elang Jawa - salah satu burung pemangsa yang menjadi indikator kesehatan ekosistem dengan Tagline sekaligus visinya adalah Safe Trail • Happy Communities • Safe Eagle. Sesi ini ditutup oleh perwakilan dari Yayasan SINTAS Indonesia, Ibu Alhalimata Rosyidi, yang menjelaskan strategi konservasi Macan Tutul melalui pendekatan pelibatan masyarakat sekitar hutan. ________________________________________ Sebagai penutup rangkaian kegiatan, dilakukan aksi simbolik pelestarian lingkungan berupa penanaman pohon. Aksi ini tidak hanya melibatkan peserta umum, mahasiswa, dan komunitas konservasi, tetapi juga dihadiri langsung oleh Ir. Arief Mahmud, M.Si., dan Bapak Budhi Chandra, S.H., M.H. Kehadiran kedua pimpinan lembaga konservasi ini mempertegas komitmen kelembagaan terhadap pentingnya kolaborasi lintas sektor dalam menjaga kelestarian kawasan Gedepahala. Keterlibatan aktif berbagai pihak - mulai dari masyarakat sipil hingga otoritas taman nasional - menjadi cerminan bahwa pelestarian alam tidak dapat dilakukan secara terpisah, melainkan memerlukan sinergi yang berkelanjutan. Kegiatan kemudian diakhiri dengan sesi dokumentasi bersama sebagai simbol solidaritas dan pengingat akan pentingnya aksi nyata dalam menjaga keberlanjutan lingkungan hidup. ________________________________________ Menurut Yuhika Afrisky, kegiatan ini bukan hanya menjadi ajang edukatif, tetapi juga ruang penguatan jaringan antara aktor konservasi di tingkat lokal maupun nasional. “Kami percaya bahwa perubahan nyata dimulai dari kebersamaan. Jika semua pihak bergerak dalam satu visi, maka pelestarian alam bukan sekadar wacana, melainkan menjadi komitmen kolektif,” ujarnya dengan penuh optimisme. Ia juga berharap semangat yang terbangun dari kegiatan ini dapat menjadi inspirasi bagi gerakan serupa di berbagai wilayah lainnya. ________________________________________ Secara keseluruhan, “Yuk Lestarikan Bumi Part 2” tidak hanya menjadi wadah edukasi dan penyuluhan lingkungan, tetapi juga berhasil mempertemukan berbagai pihak dalam satu panggung kolaboratif. Semangat kebersamaan yang tercipta dari kegiatan ini menjadi harapan baru bagi gerakan pelestarian lingkungan yang lebih inklusif, berkelanjutan, dan berdampak nyata di masa depan. Kegiatan ini didukung dan disponsori oleh berbagai pihak yang memiliki kepedulian tinggi terhadap pelestarian lingkungan, antara lain: Bamboo Sanctuary Pancawati, Node Café and Lounge, Fakultas Kehutanan Universitas Nusa Bangsa, Balai Besar Taman Nasional Gunung Gede Pangrango, Balai Taman Nasional Gunung Halimun Salak, PT. Eigerindo Multi Produk Industri (EIGER Adventure), PT. Belantara Alam Consultant, Coca-Cola Europacific Partners Indonesia, Javan Hawk Eagle Trail, Yayasan Belantara Foundation, Yayasan PUTER Indonesia, Yayasan SINTAS Indonesia, Yayasan Rasaning Rasa, Kelompok Mahasiswa Pemerhati Herpetofauna (KMPH), Youth Eco Endemic, KTH Model Kampung Konservasi Cisangku, PT. Interteknis Suryaterang dan lainnya. Dukungan ini menjadi bukti nyata bahwa kerja sama lintas sektor adalah kunci keberhasilan gerakan konservasi berkelanjutan. Tentang Bamboo Sanctuary Pancawati Bamboo Sanctuary Pancawati merupakan ruang konservasi dan edukasi berbasis masyarakat yang berlokasi di Desa Pancawati, Kabupaten Bogor. Tempat ini berperan sebagai pusat pembelajaran dan aksi nyata dalam pelestarian lingkungan, dengan menitikberatkan pada pemanfaatan bambu sebagai elemen ekologis, ekonomi, dan budaya. Melalui pendekatan kolaboratif, Bamboo Sanctuary menghubungkan akademisi, komunitas lokal, sektor swasta, dan pemerintah untuk membangun kesadaran dan kapasitas dalam menjaga keanekaragaman hayati di kawasan strategis seperti Gede Pangrango dan Halimun Salak (Gedepahala). Selain sebagai tempat pelatihan dan pertemuan, Bamboo Sanctuary ini juga menjadi wadah inkubasi program konservasi dan pemberdayaan ekonomi berkelanjutan.", "type": "paragraph"}], "excerpt": "“Yuk Lestarikan Bumi Part 2” Sukses Digelar di Bogor: Ketua Pelaksana Yuhika Afrisky Dorong Kolaborasi untuk Pelestarian Gedepahala ________________________________________ Bogor, 1 Juni 2025 - Kegiatan pelestarian lingk...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-06-05"}, {"id": "pce246o2nlg70ltw", "slug": "badan-eksekutif-mahasiswa-fakultas-pertanian-adakan-kegiatan-agricamp-2025", "title": "Badan Eksekutif Mahasiswa Fakultas Pertanian adakan Kegiatan Agricamp 2025", "author": "Humas UNB", "blocks": [{"id": "es91nbif94ni6uqe", "text": "Agricamp 2025: Faperta Agropreneur Camp Badan Eksekutif Mahasiswa Fakultas Pertanian, Universitas Nusa Bangsa (UNB) sukses menyelenggarakan yang berlangsung pada 24–25 Mei 2025 di Agribusiness and Technology Park (ATP) IPB, Jl. Carang Pulang No.1, Cikarawang, Dramaga, Kabupaten Bogor, Jawa Barat 16680. Kegiatan tahunan ini diikuti oleh lebih dari 70 mahasiswa dari program studi Agribisnis dan Agroteknologi di Fakultas Pertanian, dengan tujuan memperkuat wawasan, keterampilan, dan kepemimpinan mahasiswa dalam bidang pertanian berkelanjutan. Selama dua hari, peserta mengikuti berbagai rangkaian kegiatan seperti pembekalan materi smart farming dan smart business, praktik budidaya dan pemasaran produk, pelatihan organisasi, leadership training, serta pengembangan keterampilan kewirausahaan. Selain itu, terdapat pula sesi outbound, api unggun, dan lomba inovasi pertanian yang membangun kerja sama dan kreativitas antar peserta. Kegiatan ini juga menghadirkan narasumber dan alumni sukses untuk berbagi pengalaman serta membuka jejaring kolaborasi. Dekan Fakultas Pertanian UNB, Dr. Ir. Faizal Maad., M.Si, menyampaikan bahwa Agricamp 2025 diharapkan menjadi ruang pembelajaran aktif di luar kelas sekaligus membentuk karakter mahasiswa yang adaptif dan inovatif.", "type": "paragraph"}, {"id": "cu4u7cz1tgwviwbd", "url": "https://unb.ac.id/wp-content/uploads/2025/06/Foto01.jpg", "type": "image", "caption": ""}], "excerpt": "Agricamp 2025: Faperta Agropreneur Camp Badan Eksekutif Mahasiswa Fakultas Pertanian, Universitas Nusa Bangsa (UNB) sukses menyelenggarakan yang berlangsung pada 24–25 Mei 2025 di Agribusiness and Technology Park (ATP) I...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/06/Foto01.jpg", "publishedAt": "2025-06-02"}, {"id": "zjvcomccx03zbq50", "slug": "unb-angkat-isu-lingkungan-berkelanjutan-tekankan-peran-generasi-muda", "title": "UNB Angkat Isu Lingkungan Berkelanjutan, Tekankan Peran Generasi Muda", "author": "Humas UNB", "blocks": [{"id": "i42rtze46x6dfif8", "text": "Laboratorium Biologi Universitas Nusa Bangsa (UNB) bersama Himpunan Mahasiswa Biologi sukses menggelar acara Diskusi Sains Virtual (DSV) #4 bertema Sustainable Environment pada Rabu (21/5/2025) melalui platform Zoom Meeting. Kegiatan ini diikuti oleh 78 peserta dari berbagai kalangan, termasuk mahasiswa, tenaga pendidik, pegawai negeri dan swasta, serta siswa SMA/sederajat. Peserta berasal dari beragam institusi, di antaranya Universitas Nusa Bangsa (UNB), Universitas Terbuka (UT), Universitas Diponegoro, Universitas Noor Huda Mustofa, Universitas Muhammadiyah Bulukumba, Universitas Muhammadiyah Maumere, Universitas Muhammadiyah Palangka Raya, Universitas Mathla''ul Anwar Banten, Universitas Indonesia, Universitas Jenderal Soedirman, Universitas Lampung, Universitas Pendidikan Indonesia, IAIN Metro, UIN Sunan Kalijaga Yogyakarta, UIN Jakarta, Departemen Biologi FMIPA UNHAS, Fakultas Sains dan Teknologi, Program Kehutanan Fahutan UNB, serta BRIN (Badan Riset dan Inovasi Nasional) dan Kementerian Perindustrian. Peserta dari tingkat sekolah juga hadir, seperti SMAN 1 Cisarua, SMAN 1 Ciomas, SMAN 1 Jasinga, SMAN 1 Megamendung, SMAN 1 Cibungbulang, SMK Nusa Widya Mandiri Bogor, SMK PGRI 1 Bogor, SMK Cahaya, SMK Niba Business School Bogor, MA Plus Keterampilan Bertauhid, MA Tarbiyatush Biyyah, serta Yayasan SMAIT Ma’had Darul Husna dan PKBM Ibnu Sina. Hadir pula peserta dari pesantren seperti Pesantren Anshorus Sunnah, kalangan guru dan peserta didik, serta masyarakat umum. Acara dibuka dengan sambutan dari tiga perwakilan pimpinan Universitas Nusa Bangsa. Ketua Program Studi Biologi, Dra. Nia Yuliani, M.Pd., mengatakan, \"Melalui DSV ini saya harapkan bisa memberikan manfaat, menambah wawasan, dan melahirkan ide-ide kreatif serta solusi untuk menjaga lingkungan.\" Wakil Rektor III, Dr. Karmanah, S.P., M.Si., menambahkan, \"Kegiatan ini menjadi agenda rutin Fakultas MIPA. Saya berharap kegiatan ini terus berkesinambungan. Tema lingkungan berkelanjutan ini sangat sejalan dengan visi UNB.\" Dekan Fakultas MIPA, Dr. Lany Nurhayati, S.Si., M.Si., menyampaikan, \"Semoga apa yang kita dengarkan dari para narasumber bisa bermanfaat.\" Diskusi inti menghadirkan dua narasumber dari latar belakang yang berbeda namun memiliki kepedulian yang sama terhadap isu lingkungan. Agus Jaenudin, S.Pi. dari Yayasan Blue Seed Indonesia memaparkan materi bertajuk “Sustainable Marine Life: Peran Generasi Muda dalam Menyelamatkan Laut”. Ia menyoroti urgensi keterlibatan pemuda dalam menjaga kelestarian laut Indonesia. Narasumber kedua, Sehabudin, S.Si., alumni Biologi UNB yang kini bekerja di PT Nutrilab Pratama, membawakan materi bertema “Sustainable Bird Life: Mencintai Tak Harus Memiliki”. Ia mengangkat pentingnya konservasi burung dan mengedukasi peserta untuk menjaga kelestarian satwa tanpa harus memilikinya sebagai peliharaan. Selain itu, Sehabudin juga dikenal sebagai konten kreator di YouTube yang aktif membagikan edukasi dan informasi seputar burung melalui kanal pribadinya, sebagai bentuk kampanye konservasi yang menjangkau masyarakat luas. Diskusi berjalan interaktif dengan antusiasme tinggi dari para peserta, yang terlihat dari banyaknya pertanyaan dan tanggapan selama sesi tanya jawab. Kegiatan ini menjadi salah satu bentuk komitmen UNB dalam memperkuat literasi lingkungan dan mendorong partisipasi aktif generasi muda dalam menjaga keberlanjutan ekosistem. Diskusi Sains Virtual (DSV) bukan sekadar forum diskusi—ia telah menjadi magnet yang menginspirasi banyak peserta untuk lebih peduli pada isu lingkungan sekaligus tertarik mendalami ilmu biologi secara akademik. Lewat topik-topik aktual, narasumber yang kompeten, dan atmosfer diskusi yang terbuka, DSV berhasil menunjukkan bahwa ilmu biologi bukan hanya teori, tapi juga alat perubahan. Banyak peserta yang setelah mengikuti kegiatan ini mengaku semakin tertarik untuk melanjutkan studi di Program Studi Biologi Universitas Nusa Bangsa. Bagi yang ingin tetap terhubung dengan kegiatan edukatif seputar biologi dan lingkungan, serta tidak ingin ketinggalan DSV edisi berikutnya, silakan ikuti akun Instagram resmi di @diskusisainsvirtualunb. DSV telah membuka jalan, Prodi Biologi UNB siap menjadi rumah bagi mereka yang ingin belajar, berkembang, dan memberi dampak nyata.", "type": "paragraph"}], "excerpt": "Laboratorium Biologi Universitas Nusa Bangsa (UNB) bersama Himpunan Mahasiswa Biologi sukses menggelar acara Diskusi Sains Virtual (DSV) #4 bertema Sustainable Environment pada Rabu (21/5/2025) melalui platform Zoom Meet...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-06-02"}, {"id": "ixe09x24uwnanzqu", "slug": "akreditasi-prodi-akuntansi-2025", "title": "Akreditasi Prodi Akuntansi 2025", "author": "Humas UNB", "blocks": [{"id": "weewsp1b84h65vjy", "text": "(Konten berita tersedia di website lama UNB)", "type": "paragraph"}], "excerpt": "", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-05-23"}, {"id": "3mecpswix362l1hc", "slug": "unb-lakukan-kerjasama-dengan-onework-solutions-sdn-bhd-malaysia", "title": "UNB Lakukan Kerjasama dengan Onework Solutions SDN BHD, Malaysia", "author": "Humas UNB", "blocks": [{"id": "gx1fv6m3wycoy8g5", "text": "NUSA BANGSA UNIVERSITY or UNIVERSITAS NUSA BANGSA (hereinafter referred to as “NUSA BANGSA”) as a Private Higher Education Institution established in 1987 with an address of Jl. Sholeh Iskandar No.KM.4, RT.02/RW.05, Cibadak, Kec. Tanah Sereal, Kota Bogor, Jawa Barat 16166, Indonesia represented herein by its Rector, Prof. Dr. Ir. Budi Mulyanto, M.Sc. and ONEWORK SOLUTIONS SDN BHD (hereinafter referred to as “OneWork”) as Gig Economy Platform Operator and Online Skills Assessments Provider established in 2024 with an address of Level 1, Wisma Suria, Jalan Teknokrat 6, Cyber 5, 63000 Cyberjaya, Selangor, Malaysia represented herein by its Chief Executive Officer (CEO), Mr. Abbyamir Sapie, Hereinafter collectively known as the “Parties”. Whereas The Parties desire and agree to enter into an agreement in which they will work together to encourage cooperation in academic and teaching, research and development, and community services, with the following terms and conditions: 1. PURPOSE AND SCOPE The purpose of this MoU is to provide the framework and the scope of collaboration. The Parties agree to develop the following collaborative activities of mutual interests: a. Undergraduate academic freelancing training and employment opportunity development; b. Undergraduate competency, skills and employability assessments; c. Postgraduate career matching and mentoring; and d. Other academic exchange and cooperation to which the Parties mutually agree. 2. IMPLEMENTATION The development and implementation of each program based upon this MOU shall be negotiated and agreed upon by the Parties under a separate written agreement, which explains in more detail regarding program implementation, financing, responsibilities of both parties and dispute resolution. 3. THE PARTIES OBLIGATIONS The Parties agree that this document is not legally binding, but rather an agreement between The Parties to work together in such a manner that would promote a genuine atmosphere of collaboration in support of an effective and efficient partnership. 4. DURATION OF AGREEMENT This MOU is valid for a period of five (5) years from the date of the last signing by the representatives of the Parties. This MOU shall be renewed after being reviewed and renegotiated by both universities. IN WITNESS WHEREOF, this MOU is executed and duly signed by its respective authorized representative in two original copies in English and Indonesian language.", "type": "paragraph"}], "excerpt": "NUSA BANGSA UNIVERSITY or UNIVERSITAS NUSA BANGSA (hereinafter referred to as “NUSA BANGSA”) as a Private Higher Education Institution established in 1987 with an address of Jl. Sholeh Iskandar No.KM.4, RT.02/RW.05, Ciba...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-05-08"}, {"id": "un7cwx6vp64l6m8e", "slug": "unb-dorong-agropreneur-muda-lewat-kuliah-umum-smart-farming-dan-smart-bisnis", "title": "UNB Dorong Agropreneur Muda Lewat Kuliah Umum Smart Farming dan Smart Bisnis", "author": "Humas UNB", "blocks": [{"id": "apge9ed96uk5xu5t", "text": "Sabtu, 3 Mei 2025 Fakultas Pertanian Universitas Nusa Bangsa (UNB) kembali menunjukkan komitmennya dalam membentuk generasi agropreneur muda yang inovatif dan adaptif terhadap bisnis dan teknologi. Melalui kegiatan Kuliah Umum bertema “Unlock the Future: Smart Farming & Smart Bisnis untuk Agropreneur Muda”, UNB membuka wawasan mahasiswa tentang pentingnya integrasi teknologi dan kewirausahaan dalam sektor pertanian. Kegiatan ini merupakan bagian dari rangkaian acara Agricamp 2025, yang difokuskan untuk mencetak mahasiswa sebagai pelaku usaha pertanian berbasis keberlanjutan dan teknologi modern. Dalam kuliah umum yang digelar pada Sabtu, 3 Mei 2025 di Aula Pascasarjana FEB UNB ini, hadir Dr. Harlan Bestari Bengardi, Komisaris Utama AGRICON GROUP sebagai narasumber utama. Ia membagikan pengalaman nyata dari dunia industri agro, sekaligus mendorong mahasiswa untuk menjadi pelaku usaha pertanian yang inovatif, visioner, dan siap bersaing di masa depan. “Mahasiswa hari ini harus belajar melihat peluang dan membangun solusi pertanian dari tantangan yang ada. Jangan hanya jadi pencari kerja, tapi jadi pencipta lapangan kerja,” ujar Dr. Harlan dalam pemaparannya. Turut memberikan sambutan, Dr. Hj. Karmanah, S.P., M.Si., selaku Wakil Rektor III UNB. Ia menyoroti transformasi pertanian modern melalui pemanfaatan teknologi seperti Internet of Things (IoT), Artificial Intelligence (AI), Big Data, dan Sensor Cerdas. Menurut data BRIN 2024, pendekatan ini mampu: Meningkatkan produksi hingga 20% Mengurangi penggunaan air sebanyak 30% Mengurangi tenaga kerja hingga 50% Menurunkan penggunaan pupuk dan pestisida sebesar 10% “Transformasi ini bukan pilihan, tapi keniscayaan jika kita ingin pertanian tetap relevan dan berkelanjutan,” ungkapnya. Sementara itu, Dr. Ir. Faizal Maad, M.Si., Dekan Fakultas Pertanian UNB, menegaskan bahwa pertanian masa depan bukan hanya soal lahan, tapi juga soal gagasan dan semangat berinovasi. “Kampus bukan sekadar tempat belajar teori, tapi tempat lahirnya pemimpin perubahan. Kalian bukan hanya calon sarjana, tapi calon agropreneur,” tegasnya di hadapan peserta kuliah umum. Sebagai penutup sesi akademik, Dr. Ir. Andi Masnang, M.Si., Kaprodi Agroteknologi, memaparkan pentingnya memahami faktor lingkungan dalam budidaya tanaman. Menurutnya, keberhasilan pertanian sangat ditentukan oleh kemampuan adaptasi terhadap kondisi lingkungan yang dinamis. Menariknya, acara ini juga menghadirkan Halal Network International (HNI) sebagai sponsor. Selain mendukung kegiatan, HNI juga memperkenalkan peluang bisnis berbasis produk herbal alami yang sedang berkembang pesat di Indonesia. Hal ini membuka perspektif baru bagi mahasiswa tentang potensi wirausaha di bidang kesehatan yang terintegrasi dengan pertanian. Acara diselenggarakan oleh BEM Fakultas Pertanian UNB, dengan dukungan dari AGRICON GROUP dan HNI.", "type": "paragraph"}], "excerpt": "Sabtu, 3 Mei 2025 Fakultas Pertanian Universitas Nusa Bangsa (UNB) kembali menunjukkan komitmennya dalam membentuk generasi agropreneur muda yang inovatif dan adaptif terhadap bisnis dan teknologi. Melalui kegiatan Kulia...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-05-06"}, {"id": "q0anmvdftm58wou7", "slug": "feb-unb-gelar-kuliah-umum-pasar-modal", "title": "FEB UNB Gelar Kuliah Umum Pasar Modal", "author": "Humas UNB", "blocks": [{"id": "qbvfc9vy3xw2rjez", "text": "FEB UNB Gelar Kuliah Umum Pasar Modal: Mahasiswa Gen Z Didorong Jadi Investor Cerdas Bogor (24/04/2025) – Fakultas Ekonomi dan Bisnis (FEB) Universitas Nusa Bangsa (UNB) menyelenggarakan kuliah umum bertema “Investasi Cerdas untuk Membangun Masa Depan Mahasiswa Gen Z” pada Kamis, 24 April 2025. Kegiatan ini khusus diikuti oleh mahasiswa FEB dan bertujuan untuk memperluas wawasan tentang literasi pasar modal dan investasi yang bijak. Acara menghadirkan dua narasumber profesional dari dunia pasar modal, yaitu Yulia, Senior Investment Specialist dari Mirae Asset Sekuritas, dan Yusuf Adi Pradana, Market Development Analyst dari Indonesia Stock Exchange (IDX). Keduanya memaparkan materi secara menarik dan interaktif, membahas pengenalan instrumen investasi, potensi risiko dan keuntungan, serta strategi aman untuk investor pemula. Moderator acara adalah Nur’aini, mahasiswa aktif dari FEB UNB. Sambutan Dekan: Literasi Keuangan Sangat Penting Dalam sambutan pembuka, Dekan FEB UNB menyampaikan apresiasi kepada semua pihak yang terlibat, terutama kepada Mirae Asset Sekuritas yang telah memfasilitasi kegiatan ini serta HIMAMEN sebagai panitia pelaksana. Beliau menyampaikan: “Kenapa pasar modal? Sekarang minat terhadap pasar modal meningkat, bukan hanya di kalangan Gen Z tapi juga bapak-bapak muda dan mamah muda. Maka, mahasiswa perlu punya pemahaman yang cukup tentang aset dan instrumen keuangan. Ini penting, supaya tidak sekadar ikut tren atau FOMO. Yang terpenting adalah punya literasi keuangan, agar risiko bisa diminimalkan.” Beliau menambahkan bahwa acara ini diharapkan bisa membuka wawasan mahasiswa dan menjadi bekal untuk menghindari jebakan investasi bodong. Acara resmi dibuka dengan harapan menjadi penyemangat seluruh peserta untuk mengikuti kegiatan hingga selesai. Resume Kuliah Umum Dalam sesi kuliah umum, mahasiswa belajar mengenai: • Pengertian dan fungsi pasar modal • Jenis-jenis instrumen keuangan seperti saham, obligasi, dan reksa dana • Cara membuka rekening efek dan memulai investasi • Tips aman investasi serta kewaspadaan terhadap investasi ilegal Para peserta aktif dalam sesi tanya jawab dan diskusi, menunjukkan antusiasme tinggi terhadap materi yang disampaikan. Kolaborasi HIMAMEN dan Dunia Industri Acara ini diselenggarakan oleh Himpunan Mahasiswa Manajemen (HIMAMEN) FEB UNB, yang berperan penuh dalam koordinasi, teknis lapangan, hingga dokumentasi. Dengan menggandeng Mirae Asset Sekuritas dan IDX, kegiatan ini menjadi contoh sinergi antara dunia kampus dan industri dalam mendorong literasi keuangan mahasiswa. Kuliah umum ini diharapkan menjadi awal dari rangkaian edukasi finansial berkelanjutan di lingkungan FEB UNB", "type": "paragraph"}], "excerpt": "FEB UNB Gelar Kuliah Umum Pasar Modal: Mahasiswa Gen Z Didorong Jadi Investor Cerdas Bogor (24/04/2025) – Fakultas Ekonomi dan Bisnis (FEB) Universitas Nusa Bangsa (UNB) menyelenggarakan kuliah umum bertema “Investasi Ce...", "category": "Berita", "bannerUrl": "", "publishedAt": "2025-04-25"}, {"id": "v3jkbe9mf8xy25v9", "slug": "kmph-universitas-nusa-bangsa-bekerja-sama-bamboo-sanctuary-selenggarakan-diskusi", "title": "KMPH Universitas Nusa Bangsa bekerja sama Bamboo Sanctuary selenggarakan Diskusi Inspiratif", "author": "Humas UNB", "blocks": [{"id": "89uq7jufnlljil01", "text": "Memperingati Hari Kartini dan Hari Bumi 2025: Peran Perempuan dalam Konservasi Herpetofauna dan Edukasi Lingkungan Berkelanjutan Dalam rangka memperingati dua momentum penting yaitu Hari Kartini pada tanggal 21 April dan Hari Bumi pada tanggal 22 April, Kelompok Mahasiswa Pemerhati Herpetofauna (KMPH) Universitas Nusa Bangsa bekerja sama dengan seorang pakar konservasi alam dan ekowisata dari Bamboo Sanctuary menyelenggarakan Diskusi Inspiratif bertema: “Meningkatkan Peran Perempuan dalam Penanganan Gangguan Satwa Ular Akibat Pengelolaan Lingkungan yang Tidak Berkelanjutan.” Acara yang berlangsung tanggal 20 April 2025 di NODE Café & Lounge / Bamboo Sanctuary Pancawati ini dihadiri oleh berbagai kalangan, mulai dari akademisi, praktisi konservasi, mahasiswa, komunitas pecinta alam, hingga masyarakat umum dan anak-anak. Diskusi ini bertujuan untuk membuka wawasan dan meningkatkan kepedulian terhadap isu-isu konservasi satwa liar, khususnya ular, yang kerap menjadi korban sekaligus dianggap ancaman akibat terganggunya ekosistem dan habitat alaminya. Momentum Hari Kartini diangkat sebagai penghormatan terhadap perjuangan R.A. Kartini sebagai pelopor emansipasi wanita yang gigih memperjuangkan hak perempuan dalam memperoleh pendidikan. Semangat Kartini menjadi inspirasi bagi perempuan masa kini untuk terus mengembangkan potensi diri di berbagai bidang, termasuk dalam upaya pelestarian lingkungan dan penanganan satwa liar. \"Perempuan masa kini tidak hanya memiliki peran dalam lingkup rumah tangga atau pendidikan formal, tetapi juga mampu berdiri di garda depan konservasi, bahkan ketika harus menghadapi satwa yang dianggap berbahaya seperti ular. Edukasi yang kami berikan hari ini bukan hanya bersifat teoritis, namun juga praktis, agar seluruh peserta—baik perempuan, laki-laki, dewasa maupun anak-anak—memiliki pengetahuan dan keterampilan menghadapi situasi darurat ketika bertemu dengan satwa tersebut di lingkungan sekitar mereka. Kegiatan ini tidak hanya berisi sesi diskusi, tetapi juga dilengkapi dengan demonstrasi langsung mengenai cara penanganan ular yang aman dan tidak melukai satwa tersebut. Peserta diberikan pemahaman mengenai peran penting ular dalam menjaga keseimbangan ekosistem, serta bagaimana perubahan tata guna lahan dan pembangunan yang tidak berkelanjutan meningkatkan risiko konflik antara manusia dan satwa liar. Dengan menggabungkan nilai-nilai emansipasi perempuan ala Kartini dan semangat pelestarian bumi, acara ini menjadi wadah edukatif dan inspiratif untuk membangun kesadaran kolektif dalam menjaga keberlanjutan lingkungan hidup. KMPH Universitas Nusa Bangsa berharap kegiatan seperti ini dapat terus dilakukan secara berkelanjutan dan melibatkan lebih banyak lapisan masyarakat, khususnya generasi muda dan kaum perempuan, agar mereka dapat menjadi agen perubahan dalam menjaga kelestarian alam Indonesia.", "type": "paragraph"}, {"id": "e33ou9o0r0cjb8gb", "url": "https://unb.ac.id/wp-content/uploads/2025/04/P8-232x300.jpg", "type": "image", "caption": ""}, {"id": "2ttz6tfsyem3jj4j", "url": "https://unb.ac.id/wp-content/uploads/2025/04/P6-237x300.jpg", "type": "image", "caption": ""}], "excerpt": "Memperingati Hari Kartini dan Hari Bumi 2025: Peran Perempuan dalam Konservasi Herpetofauna dan Edukasi Lingkungan Berkelanjutan Dalam rangka memperingati dua momentum penting yaitu Hari Kartini pada tanggal 21 April dan...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/04/P8-232x300.jpg", "publishedAt": "2025-04-22"}, {"id": "nq3i2w4ypotuw5ne", "slug": "koperasi-kosiva-unb-adakan-rat-2025", "title": "Koperasi KOSIVA UNB adakan RAT 2025", "author": "Humas UNB", "blocks": [{"id": "r4j6nord8m200xn3", "text": "Bogor,7 Maret2025 Koperasi KOSIVA Universitas Nusa Bangsa Bogor lakukan Rapat Anggota Tahunan (RAT) di Gedung Auditorium. Pada kesempatan itu dihadiri oleh WR 2 Sunrizal, Ketua Koperasi Agus Pranamulia, Ketua Pengawas Koperasi Sari Anggara Wati, Ketua Dekopinda Ade Sarip Hidayat dan Kepala Bidang Koperasi Ali Susanto juga para pengurus dan anggota koperasi lainnya. Pada kesempatan itu Wakil Rektor 2 menyampaikan bahwa Koperasi KOSIVA UNB sebagai etalase yang menyediakan berbagai produk dan mensupport kegiatan di UNB diantaranya ATK, Konsumsi-konsumsi kegiatan kepanitian, baju-baju kepanitian dan lainnya. Sedangkan Ketua Dekopinda Kota Bogor menyampaikan bahwa Koperasi sebagai pengembangan SDM terutama dalam peningkatan kesejahteraan Anggotanya. Sambutan terakhir oleh Dinas Koperasi Kota Bogor, Koperasi akan semakin maju jika di support dari kampus (tempat) yang mewadahi anggota anggota. Beliau juga mengingatkan bahwa anggota dan pengawas harus terus memantau pelaksanaan kegiatan koperasi terutama dalam pengembangan koperasi. (HS)", "type": "paragraph"}, {"id": "scxpdepuiafvcr97", "url": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-07-at-09.26.50-300x169.jpeg", "type": "image", "caption": ""}, {"id": "kmypdqdl5dly8x5z", "url": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-07-at-09.26.51-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor,7 Maret2025 Koperasi KOSIVA Universitas Nusa Bangsa Bogor lakukan Rapat Anggota Tahunan (RAT) di Gedung Auditorium. Pada kesempatan itu dihadiri oleh WR 2 Sunrizal, Ketua Koperasi Agus Pranamulia, Ketua Pengawas Ko...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-07-at-09.26.50-300x169.jpeg", "publishedAt": "2025-03-08"}, {"id": "4z9rqhf7awmgs256", "slug": "universitas-nusa-bangsa-membuka-lowongan-dosen-tetap-2025", "title": "Universitas Nusa Bangsa Membuka Lowongan Dosen Tetap 2025", "author": "Humas UNB", "blocks": [{"id": "ecydvdtw7ul4sh3w", "url": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-06-at-07.19.37-214x300.jpeg", "type": "image", "caption": ""}], "excerpt": "", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-06-at-07.19.37-214x300.jpeg", "publishedAt": "2025-03-06"}, {"id": "4e9t27siyovsw61r", "slug": "kegiatan-komunitas-reptil-unb-dalam-menangani-reptil-saat-banjir", "title": "Kegiatan Komunitas Reptil UNB dalam Menangani Reptil Saat Banjir", "author": "Humas UNB", "blocks": [{"id": "un4aeizkia6s3ypz", "text": "Bogor, 5 Februari 2025 Universitas turut berbangga salah satu mahasiswa dari Fakultas Kehutanan Universitas Nusa Bangsa yakni Abdi, mahasiswa Fahutan Semester 4 juga Ketua komunitas Reptil UNB 2024-sekarang. Menjadi nara sumber di salah satu TV Swasta berkaitan dengan penanganan reptil yang sering muncul dalam kondisi saat dan pasca banjir.", "type": "paragraph"}, {"id": "lkzcoskvjefpfsib", "url": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-05-at-17.45.07-e1741224040733-300x254.jpeg", "type": "image", "caption": ""}, {"id": "nr8sa10a88cfzxyj", "url": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-05-at-17.45.06-2-e1741224101140-300x300.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 5 Februari 2025 Universitas turut berbangga salah satu mahasiswa dari Fakultas Kehutanan Universitas Nusa Bangsa yakni Abdi, mahasiswa Fahutan Semester 4 juga Ketua komunitas Reptil UNB 2024-sekarang. Menjadi nara...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/03/WhatsApp-Image-2025-03-05-at-17.45.07-e1741224040733-300x254.jpeg", "publishedAt": "2025-03-06"}, {"id": "tonhv5ws0tr9c1yc", "slug": "unb-adakan-pembekalan-dan-pelepasan-kknt-2025-periode-1", "title": "UNB adakan Pembekalan dan Pelepasan KKNT 2025 Periode 1", "author": "Humas UNB", "blocks": [{"id": "snff64z40xo3ytza", "text": "Bogor, 8 Februari 2025 Universitas Nusa Bangsa melakukan Pembekalan dan Pelepasan Kuliah Kerja NyataTematik (KKNT) 2025 Periode 1. Acara tersebut dibuka oleh Wakil Rektor 2 Universitas Nusa Bangsa Dr. Karmanah, SP., MSi, pada kesempatan itu juga hadir Ka. Biro LPPM, LPM beserta para Dekan Fakultas dan Dosen Pembimbing Lapangan. Kuliah Kerja Nyata Tematik (KKNT) adalah program pembelajaran yang dilakukan mahasiswa di luar kampus. Program ini bertujuan untuk mengasah keterampilan mahasiswa dalam bekerja sama dengan masyarakat.", "type": "paragraph"}, {"id": "9ggjkjhzrdaaixz4", "text": "Mengembangkan potensi desa/daerah", "type": "paragraph"}, {"id": "0kwtgzgl22rjfxsy", "text": "Merumuskan solusi untuk masalah yang ada di desa", "type": "paragraph"}, {"id": "f2uirt7bbh80nrs3", "text": "Menerapkan keilmuan untuk menyelesaikan permasalahan dalam masyarakat", "type": "paragraph"}, {"id": "w9wtruyxnyajntmi", "text": "Memberikan solusi berdasarkan pada disiplin ilmu masing-masing", "type": "paragraph"}, {"id": "bq438kakhge7g2ce", "text": "Memperkuat kemitraan antara perguruan tinggi dengan berbagai mitra lembaga", "type": "paragraph"}, {"id": "kpxp3pa0rxnm88e3", "text": "Mengembangkan soft skill kemitraan, kerja sama tim, dan leadership mahasiswa", "type": "paragraph"}, {"id": "q9m50otjwkj0u8jd", "text": "Memberikan pengalaman belajar kepada mahasiswa untuk hidup di tengah masyarakat di luar kampus", "type": "paragraph"}, {"id": "npgsxfh6df0w2anw", "text": "Membantu percepatan pembangunan di wilayah pedesaan", "type": "paragraph"}, {"id": "hmobt6u85akpykjr", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-11.38.17-2-300x169.jpeg", "type": "image", "caption": ""}, {"id": "uhqri3rcweqmh6se", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-11.40.29-300x200.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 8 Februari 2025 Universitas Nusa Bangsa melakukan Pembekalan dan Pelepasan Kuliah Kerja NyataTematik (KKNT) 2025 Periode 1. Acara tersebut dibuka oleh Wakil Rektor 2 Universitas Nusa Bangsa Dr. Karmanah, SP., MSi,...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-11.38.17-2-300x169.jpeg", "publishedAt": "2025-02-08"}, {"id": "ja3mgf5hxy811g56", "slug": "kerjasama-universitas-nusa-bangsa-dengan-yayasan-bumi-karuhun-kadudampit-sukabum", "title": "Kerjasama Universitas Nusa Bangsa dengan Yayasan Bumi Karuhun Kadudampit Sukabumi", "author": "Humas UNB", "blocks": [{"id": "ry3xo5zhh82q4ki5", "text": "Bogor, 8 Februari 2025 Pada hari sabtu 8 Februari 2025 telah terjadi kesepakatan Kerjasama Universitas Nusa Bangsa dengan Yayasan Bumi Karuhun Kadudampit Sukabumi. Prof. Dr. Ir. Budi Mulyanto, M.Sc. Rektor yang bertindak atas nama Universitas Nusa Bangsa dan Ir. Dian Achmad Kosasih, M.Sc sebagai Ketua Pengurus / Direktur Utama yang bertindak atas nama Yayasan Bumi Karuhun Kadudampit. Maksud Kesepahaman adalah sebagai dasar dalam pelaksanaan Perjanjian Kerjasama yang akan dibuat sesuai dengan ruang lingkup Kesepahaman. Tujuan Kesepahaman adalah untuk mengembangkan kerjasama di bidang pendidikan, penelitian dan pengabdian kepada masyarakat. Ketua Yayasan Bumi Karuhun Kadudampit menyampaikan bahwa bambu menjadi sesuatu yang bernilai dengan berupaya menjadikan kawasan bambu Indonesia di Kadudampit Sukabumi. Pada kesempatan itu juga Rektor UNB menyampaikan untuk bersama-sama semangat terutama dalam memenuhi cita-cita para pendiri terutama dalam peningkatan mutu SDM.", "type": "paragraph"}, {"id": "55f1jsb2av65efht", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-15.13.50-300x200.jpeg", "type": "image", "caption": ""}, {"id": "r3sj9xvf2fslur77", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-15.13.51-1-300x200.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 8 Februari 2025 Pada hari sabtu 8 Februari 2025 telah terjadi kesepakatan Kerjasama Universitas Nusa Bangsa dengan Yayasan Bumi Karuhun Kadudampit Sukabumi. Prof. Dr. Ir. Budi Mulyanto, M.Sc. Rektor yang bertindak...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-08-at-15.13.50-300x200.jpeg", "publishedAt": "2025-02-08"}, {"id": "a2oiyxsl24jghtz1", "slug": "unb-kedatangan-tamu-dari-filipina-paparkan-konsep-transformasi-pendidikan", "title": "UNB Kedatangan Tamu dari Filipina, Paparkan Konsep Transformasi Pendidikan", "author": "Humas UNB", "blocks": [{"id": "lt8o3va7w3k2t9j7", "text": "Bogor, 4 Februari 2025 Untuk kedua kalinya Ibu Kim dkk dari Pilipina telah berkunjung ke UNB untuk memaparkan konsep transformasi pendidikan. Mereka diterima oleh pimpinan UNB dan Pengurus Yayasan, kegiatan ini dihadiri oleh Prof. Ir. Budi Mulyanto, MSc selaku rektor UNB beserta jajarannya. UNB berupaya menjadikan kampus global, Kampus Global adalah kampus yang menyelenggarakan program pendidikan yang bersifat global, yaitu program yang mencakup berbagai aspek kehidupan di seluruh dunia. Program pendidikan global bertujuan untuk mempersiapkan mahasiswa untuk menghadapi kehidupan yang kompetitif dan saling bergantung antar bangsa. Mahasiswa juga diharapkan memiliki kesadaran untuk membuka diri terhadap isu global, menjaga kelestarian lingkungan, dan melek teknologi. (HS)", "type": "paragraph"}, {"id": "vhsk0u67hzgenok9", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-04-at-11.26.19-300x226.jpeg", "type": "image", "caption": ""}, {"id": "8f2yjn3kckoo4j2y", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-04-at-10.50.43-1-300x226.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 4 Februari 2025 Untuk kedua kalinya Ibu Kim dkk dari Pilipina telah berkunjung ke UNB untuk memaparkan konsep transformasi pendidikan. Mereka diterima oleh pimpinan UNB dan Pengurus Yayasan, kegiatan ini dihadiri...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-04-at-11.26.19-300x226.jpeg", "publishedAt": "2025-02-04"}, {"id": "3wp4xty9zsw46pb5", "slug": "pelatihan-brevet-pajak-ab-dan-sertifikasi-gelar-ctt-prodi-akuntansi-unb", "title": "Pelatihan Brevet Pajak AB dan Sertifikasi Gelar CTT, Prodi Akuntansi UNB", "author": "Humas UNB", "blocks": [{"id": "dlgpe6mm3ov1att6", "text": "Bogor, 1 Februari 2025 Tujuan Prodi Akuntansi Universitas Nusa Bangsa bertujuan agar mahasiswa akuntansi yang lulus ujian akan mendapatkan sertifikat Brevet A dan B serta mendapatkan sertifikat gelar Certified Tax Technician ( CTT ) yang dikeluarkan oleh Asosiasi Teknisi Perpajakan Indonesia ( ATPI). Sertifikat ini dapat digunakan untuk menunjang karier di bidang perpajakan, baik di sektor pemerintahan maupun swasta. Selain itu Memastikan dan memelihara kompetensi yang telah didapat melalui proses pembelajaran, baik formal, non formal, pelatihan kerja ataupun pengalaman kerja . karena dalam dunia kerja kompetensi harus dipelihara, bukan hanya pernah kompeten tetapi kompeten dan terus kompeten. Hadir juga pada acara pembukaan Dekan Fakultas Ekonomi Universitas Nusa Bangsa Dr. Isbandriyati, SE., MSE dan Ka. Prodi Akuntansi Feni Marnilin, SE., M.Ak, kegiatan diselenggarakan pada 1 Februari 2025-16 Februari 2025 di Gedung Fakultas Ekonomi.", "type": "paragraph"}, {"id": "vw3945fybwyok947", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-01-at-13.53.06-300x225.jpeg", "type": "image", "caption": ""}, {"id": "hmty3z4i0kl94ssg", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-01-at-13.53.05-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 1 Februari 2025 Tujuan Prodi Akuntansi Universitas Nusa Bangsa bertujuan agar mahasiswa akuntansi yang lulus ujian akan mendapatkan sertifikat Brevet A dan B serta mendapatkan sertifikat gelar Certified Tax Techni...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-01-at-13.53.06-300x225.jpeg", "publishedAt": "2025-02-03"}, {"id": "sm30iqyc1soiqa2k", "slug": "fakultas-mipa-unb-hki-jabar-banten-adakan-pelatihan-penyusunan-proposal-bidang-s", "title": "Fakultas MIPA UNB, HKI-Jabar Banten Adakan Pelatihan Penyusunan Proposal Bidang Sains Natural", "author": "Humas UNB", "blocks": [{"id": "a6axo0yge4kndpt6", "text": "Bogor, 1 Februari 2025 Bogor, 1 Februari 2025, HKI Jabar-Banten Bersama Fakultas MIPA Universitas Nusa Bangsa (UNB) mengadakan pelatihan penyusunan proposal bidang sains natural di Auditorium UNB. Kegiatan ini diikuti oleh 30 peserta dari 8 instansi yaitu ITB, IPB, UI, UNB, UNPAK, Unjani, Politeknik AKA Bogor dan BRIN. Prof. Dr. Ir. Budi Mulyanto, M.Sc selaku Rektor UNB yang juga membuka kegiatan ini menyampaikan harapannya agar kegiatan ini dapat bermanfaat bagi dosen dalam meningkatkan kualitas proposal penelitian sehingga berpeluang besar mendapatkan hibah penelitian. Pada acara ini juga dilakukan penandatanganan PKS antara HKI Jabar Banten dan FMIPA UNB di bidang pendidikan, penelitian dan pengabdian masyarakat. Pelatihan penyusunan proposal ini mengundang dua narasumber yaitu Prof. Dr. Ir. Suminar Setiati Achmadi, M.Sc. dan Munawar Khalil, S.Si., M.Eng. Sc., Ph.D. Selain penyampaian materi oleh narasumber, dilakukan juga coaching untuk membahas lebih detail proposal penelitian masing-masing peserta. Dalam kegiatan coaching ini, peserta terbagi atas 4 kelompok yang masing-masing dibimbing oleh 1 coach. Adapun yang bertindak sebagai coach pada kegiatan ini yaitu Prof. Dr. Mohamad Rafi, S.Si., M.Si., Prof. Dr. Irmanida Batubara, S.Si., M.Si., Dr. Wulan Tri Wahyuni, S., S.Si., M.Si., dan Dr. Muhammad Yudhistira Azis, S.Si., M.Si yang juga merupakan ketua HKI Jabar-Banten. Peserta merasa mendapatkan informasi yang baik dan bermanfaat dari narasumber dalam penulisan proposal dan strategi mendapatkan hibah penelitian. Peserta juga sangat terbantu dalam menyusun proposal dan mendapatkan review dari proposalnya, sehingga mengetahui kekurangan dari proposal baik dari segi administrasi ataupun substansi. Hasil dari kegiatan ini yaitu dapat disusunnya proposal penelitian yang sesuai persyaratan administrasi dengan substansi yang baik. Peserta berharap kegiatan seperti ini diadakan secara berkelanjutan dengan materi lainnya seperti penulisan proposal untuk hibah internasional dan penulisan artikel ilmiah internasional", "type": "paragraph"}, {"id": "5l26wlhdh0zph1si", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-03-at-13.58.46-300x200.jpeg", "type": "image", "caption": ""}, {"id": "xuukyo9i69fkume6", "url": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-01-at-08.41.53-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 1 Februari 2025 Bogor, 1 Februari 2025, HKI Jabar-Banten Bersama Fakultas MIPA Universitas Nusa Bangsa (UNB) mengadakan pelatihan penyusunan proposal bidang sains natural di Auditorium UNB. Kegiatan ini diikuti ol...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2025/02/WhatsApp-Image-2025-02-03-at-13.58.46-300x200.jpeg", "publishedAt": "2025-02-01"}, {"id": "omnn9cojr0d88061", "slug": "himaksi-feb-unb-adakan-kuliah-umum-dasar-dasar-fraud-auditing-dan-peran-teknolog", "title": "HIMAKSI FEB UNB adakan Kuliah UMUM DASAR DASAR FRAUD AUDITING DAN PERAN TEKNOLOGI DALAM FRAUD AUDITING", "author": "Humas UNB", "blocks": [{"id": "kjdf9ry3qbhn9z91", "text": "Bogor, 3 Desember 2024", "type": "paragraph"}, {"id": "unflwp6tc1f2l09k", "text": "KULIAH UMUM yang diselenggarakan oleh \" HIMAKSI \" dengan mengusung tema materi: \" DASAR DASAR FRAUD AUDITING DAN PERAN TEKNOLOGI DALAM FRAUD AUDITING \"", "type": "paragraph"}, {"id": "snv3re7apixv2qao", "text": "Hari, tanggal : Selasa, 3 November 2024 Waktu : 13.00-15.30 Tempat : Auditorium Universitas Nusa Bangsa", "type": "paragraph"}, {"id": "he0vokds66zmxdud", "text": "Ketua HIMAKSI pada pembukaan kuliah umum menyampaikan rasa terimakasih kepada segenap Civitas Akademik UNB terutama Dekan Fakultas Ekonomi Dr. Isbandriyati Mutmainah, SE., ME dan Ka. Prodi Akuntansi Feni Marnilin, SE., MAk serta para peserta yang hadir pada kegiatan Kuliah UMUM ini sehingga kegiatan ini bisa berjalan dengan baik. Ketua HIMAKSI juga menyampaikan juga terimakasih kepada kedua narasumber. Narasumber pertama adalah Bapak Sunrizal SE., MM., CFRA, CFE, CGAE, GRGP sedangkan narasumber yang kedua adalah Bapak Egi Adithia Pradana, S.Kom., M.Kom . Bapak Sunrizal SE., MM., CFRA, CFE, CGAE, GRGP menyampaikan bahwa audit adalah evaluasi terhadap suatu organisasi mencakup sistem proses hingga produknya. Menurut Alvin A. Arens audit adalah pengumpulan dan evaluasi bukti tentang informasi untuk menentukan dan melaporkan kesesuaiannya dengan kriteria yang ditetapkan. Sedangkan Bapak Egi Adithia Pradana, S.Kom., M.Kom menyampaikan bahwa Teknologi memainkan peran yang sangat penting dalam fraud auditing karena memungkinkan auditor untuk mendeteksi, menganalisis, dan mencegah berbagai bentuk kecurangan secara lebih efisien dan akurat. (HS)", "type": "paragraph"}, {"id": "8tuy3uguldjdyqc5", "url": "https://unb.ac.id/wp-content/uploads/2024/12/WhatsApp-Image-2024-12-03-at-13.54.57-300x300.jpeg", "type": "image", "caption": ""}, {"id": "nksdar250b18z78m", "url": "https://unb.ac.id/wp-content/uploads/2024/12/IMG_0519-2-300x166.jpg", "type": "image", "caption": ""}], "excerpt": "Bogor, 3 Desember 2024 KULIAH UMUM yang diselenggarakan oleh \" HIMAKSI \" dengan mengusung tema materi: \" DASAR DASAR FRAUD AUDITING DAN PERAN TEKNOLOGI DALAM FRAUD AUDITING \" Hari, tanggal : Selasa, 3 November 2024 Waktu...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/12/WhatsApp-Image-2024-12-03-at-13.54.57-300x300.jpeg", "publishedAt": "2024-12-03"}, {"id": "pbtxco66og39roo1", "slug": "tim-ipb-university-universitas-nusa-bangsa-dan-universitas-pakuan-melanjutkan-pr", "title": "Tim IPB University, Universitas Nusa Bangsa, dan Universitas Pakuan Melanjutkan Program Diseminasi Teknologi dan Inovasi di Desa Wirajaya", "author": "Humas UNB", "blocks": [{"id": "qhdm4d8zjierzpo3", "text": "Bogor, 26 Oktober 2024 – Tim kolaborasi dari IPB University, Universitas Nusa Bangsa, dan Universitas Pakuan melaksanakan lanjutan Program Diseminasi Teknologi dan Inovasi di Desa Wirajaya, Kecamatan Jasinga, Kabupaten Bogor. Program ini bertujuan untuk memberdayakan masyarakat melalui teknologi berbasis pertanian dan inovasi produk dari limbah sawit. Kegiatan kali ini diawali dengan kunjungan ke pabrik PT Perkebunan Nusantara 3 Holding Cikasungka. Di pabrik ini, tim menyaksikan langsung proses pengolahan kelapa sawit, mulai dari tahap penyortiran hingga produksi minyak sawit. Proses ini menghasilkan limbah tandan kosong kelapa sawit (TKKS) dalam jumlah besar, yang kemudian dimanfaatkan lebih lanjut dalam program inovasi di Desa Wirajaya. Setelah kunjungan pabrik, tim bergerak untuk melaksanakan pelatihan di Desa Wirajaya terkait pembuatan produk turunan dari geotextile non-woven berbahan dasar TKKS. Geotextile ini sebelumnya telah diproduksi dengan mengolah serat dari TKKS dalam pertemuan sebelumnya. Produk turunan dari geotextile non-woven atau kain sawit ini mencakup berbagai kebutuhan, seperti mulsa dan polybag ramah lingkungan untuk sektor pertanian, serta produk-produk kreatif seperti tas, sepatu, topi, pot bunga, vertical garden, alas gelas, dan dekorasi bunga. Terlihat antusiasme masyarakat desa Wirajaya menyimak cara mengolah kain sawit ini menjadi sebuah produk yang memiliki fungsi dan nilai jual. Sebagai langkah lanjutan untuk memberdayakan masyarakat, tim memberikan pelatihan pemasaran digital. Warga Desa Wirajaya dibimbing dalam membuat akun e-commerce, dan strategi iklan menggunakan media sosial agar mereka dapat memasarkan produk secara online dan meningkatkan keuntungan melalui pemasaran digital. Sebagian masyarakat golongan pemuda cukup paham dengan kegiatan pemasaran digital, namun yang menjadi keluhan mereka adalah sulitnya akses internet didaerahnya. Selain kesulitan akses internet, akses jalan yang akan dilalui oleh pihak logistik pun jadi aspek yang perlu diperhatikan. Melalui program ini, diharapkan masyarakat Desa Wirajaya dapat memanfaatkan limbah kelapa sawit secara kreatif dan produktif, serta mengembangkan potensi pasar untuk produk lokal mereka.", "type": "paragraph"}], "excerpt": "Bogor, 26 Oktober 2024 – Tim kolaborasi dari IPB University, Universitas Nusa Bangsa, dan Universitas Pakuan melaksanakan lanjutan Program Diseminasi Teknologi dan Inovasi di Desa Wirajaya, Kecamatan Jasinga, Kabupaten B...", "category": "Berita", "bannerUrl": "", "publishedAt": "2024-11-13"}, {"id": "ghywb6tthpp3yl5h", "slug": "himamen-feb-gelar-seminar-literasi-keuangan-dengan-pegadaian-kc-kedung-halang", "title": "HIMAMEN FEB GELAR SEMINAR LITERASI KEUANGAN DENGAN PEGADAIAN KC KEDUNG HALANG", "author": "Humas UNB", "blocks": [{"id": "ptfd2p87dhh5tdm4", "text": "HIMAMEN FEB UNB BEKERJASAMA DENGAN PEGADAIAN KC KEDUNG HALANG BOGOR MENGGELAR SEMINAR LITERASI KEUANGAN Pada hari Selasa, 29 oktober 2024 Himpunan Mahasiswa Manajemen Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa berkolaborasi dengan Pegadaian Kantor Cabang Kedung Halang Bogor menggelar kegiatan Seminar Literasi Keuangan di gedung auditorium Universitas Nusa Bangsa dengan tema “Perencanaan Keuangan Untuk Generasi Masa Depan: Investasi, Tabungan, dan Kebebasan Finansial”. Peserta seminar adalah seluruh mahasiswa Fakultas Ekonomi dan Bisnis yang terdiri dari mahasiswa semester I sampai semester VII, dan dosen-dosen Fakultas Ekonomi Bisnis. Acara dimulai dengan sambutan Wakil Rektor 3 Bidang Kemahasiswaan Ibu Dr. Karmanah Sukarna, SP. M.Si, Kepala Biro Kemahasiswaan dan Alumni Ibu Febi Nurilmala, S.Si., M.Si Dekan Fakultas Ekonomi dan Bisnis (FEB) Ibu Dr. Isbandriyati Mutmainah, SE., M.SE, Kepala Biro Humas Promosi dan Informasi Bapak Agus Pranamulia, SE., MM. serta Pihak Pegadaian Ibu Raikha Casrianti Pontiani. Dalam Sambutannya, Dekan FEB memberikan apresiasi yang tinggi terhadap kegiatan seminar ini dan berharap kerjasama dengan Pegadaian Kantor Cabang Kedung Halang Bogor dapat terjalin untuk kegiatan lainnya. Selain memberi sambutan, Dekan FEB juga sekaligus membuka acara seminar. Materi pada acara seminar disampaikan oleh Ibu Raikha Casrianti Pontiani yang merupakan perwakilan dari pihak Pegadaian mengenai pentingnya investasi dan jenis-jenis investasi diantaranya investasi tabungan emas kepada peserta seminar. Selama acara berlangsung peserta seminar sangat antusisas dengan mengajukan beberapa pertanyaan terkait materi seminar yang disampaikan. Antusiasme peserta menunjukkan bahwa mahasiswa sebagai generasi muda sangat peduli dengan pentingnya investasi terutama investasi dalam bentuk tabungan emas untuk masa depan. Acara ditutup dengan pertukaran kenang kenangan dari FEB UNB kepada Pegadaian Kantor Cabang Kedung Halang dan sebaliknya, kemudian dilanjutkan dengan photo bersama dengan peserta seminar. Harapan dari panitia acara seminar seperti ini dapat terlaksana kembali di masa yang akan datang dengan tema yang berbeda. (HS)", "type": "paragraph"}, {"id": "oeaco6o5sw3fzjjz", "url": "https://unb.ac.id/wp-content/uploads/2024/10/Foto-FEB-1024-300x152.jpg", "type": "image", "caption": ""}, {"id": "327g3i6i2fgpdjkm", "url": "https://unb.ac.id/wp-content/uploads/2024/10/Foto-FEB-1024-2-300x169.jpg", "type": "image", "caption": ""}], "excerpt": "HIMAMEN FEB UNB BEKERJASAMA DENGAN PEGADAIAN KC KEDUNG HALANG BOGOR MENGGELAR SEMINAR LITERASI KEUANGAN Pada hari Selasa, 29 oktober 2024 Himpunan Mahasiswa Manajemen Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa b...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/10/Foto-FEB-1024-300x152.jpg", "publishedAt": "2024-10-29"}, {"id": "8wt0fzb0282pzwnu", "slug": "iklim-unb-adakan-peringatan-nabi-muhammad-saw-1446-h", "title": "IKLIM UNB adakan Peringatan Nabi Muhammad SAW 1446 H", "author": "Humas UNB", "blocks": [{"id": "frszua97lylx85x2", "text": "Bogor, 23 Maret 2024 Pada hari rabu, 23 Oktober 2024 Ikatan Muslim (IKLIM) Mahasiswa Universitas Nusa Bangsa mengadakan Peringatan Maulid Nabi Muhammad SAW . Sebelum peringatan Maulid, pada tanggal 22 Oktober 2024, diadakan beberapa Lomba terlebih dahulu diantaranya Lomba Khutbah Jum''at, MTQ dan Hadroh. M. Farhansyah selaku selaku Ketua Panitia menyampaikan hampir 200 peserta dari SLTA se-JABODETABEK mengikuti kegiatan Lomba tersebut. Pada kesempatan itu Rektor UNB, Prof. Dr. Ir. Budi Mulyanto, M.Sc menyampaikan \"Pada Era digital ini kita diharapkan lebih mencintai alqur''an, terutama dalmm meneladani akhlak Nabi Muhammad SAW sehingga dengan keanekaragaman budaya di Indonesia kita tetap saling menghormati dan menghargai dalam Bhineka Tunggal Ika\". Selain itu Ketua Yayasan PKMK Nusantara Ir. Doddy Imron Cholid, M.S, menyampaikan \"Peserta sebagai Generasi 0 atau Z memiliki karakter yang kreatif, hal ini dapat dioptimalkan untuk kegiatan yang positif, terutama dalam meningkatkan keimanan dan takwa kepada Allah SWT\". Sebagai Peceramah adalah Ustadz Taufiqurrahman, S.Q . atau yang dikenal dengan Ust. Pantun beliau menyampaikan ceramahnya berkaitan dengan Maulid Nabi Muhammad SAW diantaranya adalah menyampaikan tentang \"Konsep asal kata Maulud dan Maulid , Maulid adalah Waktu Kelahiran dan Maulud adalah Anak yang dilahirkan\". Peringatan maulid Nabi Muhammad SAW bukanlah sesuatu yang bidah, melainkan sejak Nabi Isa AS, sudah beliau sampaikan akan lahir Nabi Akhir Zaman yakni Ahmad, nabi yang paling mulia dan memiliki akhlakul karimah yang sangat terpuji\". (Radar UNB/HS)", "type": "paragraph"}, {"id": "2ooc42xmnsulwufa", "url": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-23-at-09.34.27-300x169.jpeg", "type": "image", "caption": ""}, {"id": "4poccbl7k2eiynrx", "url": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-23-at-09.16.25-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 23 Maret 2024 Pada hari rabu, 23 Oktober 2024 Ikatan Muslim (IKLIM) Mahasiswa Universitas Nusa Bangsa mengadakan Peringatan Maulid Nabi Muhammad SAW . Sebelum peringatan Maulid, pada tanggal 22 Oktober 2024, diada...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-23-at-09.34.27-300x169.jpeg", "publishedAt": "2024-10-23"}, {"id": "37rbboyo7r7imhdo", "slug": "unb-adakan-orasi-ilmiah-guru-besar-dan-wisuda-program-magister-serta-sarjana-ke-", "title": "UNB adakan Orasi Ilmiah Guru Besar dan Wisuda Program Magister serta Sarjana Ke-32", "author": "Humas UNB", "blocks": [{"id": "bw4ycoflyx2yjst8", "text": "Sabtu, 12 Oktober 2024 di Gedung Auditorium Universitas Nusa Bangsa (UNB), merupakan hari bersejarah dan berbahagia bagi civitas serta orang tua dari wisudawan dan wisudawati Universitas Nusa Bangsa. Bertambah satu orang Guru Besar UNB, terlahir sebagai Profesor dalam bidang ilmu Silvikultur Tropika, Prof. Dr. Ir. Luluk Setyaningsih, S.Hut., M.Si., IPU. menyampaikan Orasi Ilmiah dalam acara Pengukuhan Jabatan Guru Besar, serta merupakan kebanggaan juga bagi UNB yang telah meluluskan 171 wisudawan/wati yang dilantik dalam acara Wisuda Program Magister dan Sarjana Universitas Nusa Bangsa (UNB) ke-32. Acara dihadiri oleh undangan seperti perwakilan dari LLDikti Wilayah IV, perwakilan Wali Kota Bogor, PJ Bupati Kabupaten Bogor, GM PT ANTAM, Ketua DPRD Kota Bogor, Dr. Krystop Obidzinski dan kolega Guru Besar. Diawali dengan pembukaan acara oleh Ketua Senat, dan dilanjutkan pidato Rektor UNB Prof. Dr. Ir. Budi Mulyanto, M.Sc. Pada pidatonya, Budi Mulyanto menyampaikan bahwa guna menghadapi era perubahan sekarang ini, wisudawan wisudawati senantiasa menggunakan kemampuan yang dimiliki. “Para lulusan harus berkemampuan Learning agility atau pembelajar handal. Selalu mau belajar hal-hal baru. Pembelajar handal bisa adaptasi terhadap perubahan, turbulensi yang terjadi, ketidakpastian yang luar biasa, kompleksitas dan ambiguitas tinggi, yang tanda tandanya sudah muncul saat ini”, ucap Budi. Lebih lanjut Budi Mulyanto menyampaikan, saat ini untuk menghadapi masa depan yang dinamis, cakap dalam akademik saja tidaklah cukup. Di masa depan, dibutuhkan sosok manusia yang luwes, adaptif, inovatif, memiliki daya konektifitas yang tinggi dengan dunia luar jika ingin menjadi pemenang dalam tantangan perubahan jaman yang penuh perubahan. Ketua Yayasan PKMK Nusantara Ir. Doddy Imron Cholid, M.S. turut hadir memberikan sambutan dan mengucapkan selamat berbahagia. Semoga ilmu yang telah diperoleh dapat diamalkan, dengan harapan kelak saudara-saudara menjadi anggota masyarakat yang terampil, tanggap dan cerdas, serta mempunyai integritas dan tanggung jawab yang kuat. Ilmu pengetahuan yang telah diperoleh hendaknya terus dikembangkan, jadilah pribadi yang penuh ide dan berdaya saing kuat, kreatif dan inovatif di semua bidang yang kita pilih, karena persaingan semakin berat kedepan. Jangan mudah berpuas diri, terus belajar dari siapapun itu, berkarya dan bekerja dengan hati yang Ikhlas untuk mencapai tujuan. Sesi berikutnya, Orasi ilmiah Guru Besar UNB, Prof. Dr. Ir. Luluk Setyaningsih, S.Hut., M.Si., IPU., Guru Besar tetap Fakultas Kehutanan Universitas Nusa Bangsa pada bidang Silvikultur Tropika menyampaikan Orasi Ilmiah dengan judul: “Potensi Fitoremediasi Oleh Kolaborasi Habitus Pohon Dan Fungi Mikoriza Arbuskula Dalam Mendukung Kebijakan Reklamasi Lahan Pasca Tambang pada Kawasan Hutan”. Prof. Dr. Ir. Luluk Setyaningsih, S.Hut., M.Si., IPU. menyoroti penambangan sumberdaya mineral selain berkontribusi terhadap pendapatan negara, juga telah menyebabkan kerusakan ekstrem pada tanah, memunculkan lahan dengan kelupasan cukup dalam, hilangnya vegetasi, hilangnya biodiversitas mikroba dan fauna lainnya, pemadatan tanah, hamparan tailing, juga berpotensi tertimbunnya limbah yang mengandung unsur-unsur tertentu dalam konsentrasi yang berbahaya. Dengan karakternya yang demikian, akankah lahan bekas tambang yang dahulunya berupa hutan, dapat pulih kembali menjadi hutan??. Tentunya menjadi tantangan tersendiri bagi upaya rehabilitasi dan reklamasi hutan. Revegetasi, semestinya tidak hanya diarahkan untuk peningkatan tutupan hijau pada lahan pasca tambang tetapi juga sekaligus ditujukan untuk kegiatan remediasi, atau fitoremediasi menjadi alternatif yang dapat dipertimbangkan, yaitu upaya membersihkan cemaran lahan/media dengan melakukan penanaman. Tanaman diketahui mempunyai mekanisme melakukan penyerapan logam, sementara Mikroba simbiotik, Fungi Mikoriza Arbuskula (FMA) diketahui dapat meningkatkan pertumbuhan tanaman. Namun Kolaborasi mikroba simbiotik, FMA dengan tanaman habitus pohon/tanaman hutan dalam kegiatan fitoremediasi pada area reklamasi lahan pasca tambang dalam kawasan hutan masih terbatas dilaporkan. Luluk menyebutkan, aplikasi fungi mikoriza arbuskula (FMA) pada media tailing terpapar Pb berpengaruh kuat terhadap toleransi, adaptasi dan kemapuan remediasi tanaman hutan yang memiliki ketergantungan asosisi dengannya. Asosiasi FMA terbukti mempengaruhi pertumbuhan semai hutan pada lahan tailing. “Keberadaan mikoriza telah meningkatkan kemampuan tanaman hutan dalam melakukan remediasi timbal. Informasi ini juga memberikan keyakinan bahwa kolaborasi FMA dengan jenis habitus pohon sangat berpotensi sebagai fitoremediasi timbal” kata Luluk. Praktik reklamasi lahan pasca tambang dengan pendekatan komprehensif dan perawatan yang intens, telah memunculkan optimisme terjadinya perubahan menuju perbaikan kualitas lahan, pemulihan tutupan lahan, terbentuk strata vertikal vegetasi, pemulihan biodiversitas, terkendalinya erosi dan sedimentasi juga cemaran. Selamat kepada Guru Besar UNB beserta Wisudawan dan Wisudawati, semoga ilmu yang saudara dapatkan selama belajar di Universitas Nusa Bangsa ini menjadi ilmu yang bermanfaat bagi diri saudara, masyarakat, dan bagi Bangsa Indonesia", "type": "paragraph"}, {"id": "ye3b0tsczj54cgx9", "url": "https://unb.ac.id/wp-content/uploads/2024/10/PLT_2816-300x200.jpg", "type": "image", "caption": ""}, {"id": "vb4tj4fud6q47wj8", "url": "https://unb.ac.id/wp-content/uploads/2024/10/PLT_2838-300x200.jpg", "type": "image", "caption": ""}], "excerpt": "Sabtu, 12 Oktober 2024 di Gedung Auditorium Universitas Nusa Bangsa (UNB), merupakan hari bersejarah dan berbahagia bagi civitas serta orang tua dari wisudawan dan wisudawati Universitas Nusa Bangsa. Bertambah satu orang...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/10/PLT_2816-300x200.jpg", "publishedAt": "2024-10-13"}, {"id": "hzxsjxylih9m6upb", "slug": "bem-km-unb-bersama-palang-merah-indonesia-pmi-adakan-kegiatan-donor-dara", "title": "BEM KM UNB bersama Palang Merah Indonesia (PMI) adakan kegiatan donor dara", "author": "Humas UNB", "blocks": [{"id": "w847eirotkxdayc8", "text": "Badan Eksekutif Mahasiswa Keluarga Mahasiswa (BEM KM) Universitas Nusa Bangsa (UNB) bekerjasama dengan Palang Merah Indonesia (PMI) menyelenggarakan kegiatan donor darah. Kegiatan donor darah diadakan pada Jum''at (27/9/2024), di Auditorium Universitas Nusa Bangsa. Dalam rangka kegiatan ini, anggota organisasi BEM KM UNB berinisiatif untuk menyelenggarakan kegiatan Donor Darah yang mana kegiatan ini bertujuan untuk membantu Palang Merah Indonesia supaya memiliki banyak stok darah untuk rumah sakit atau masyarakat yang kekurangan darah. Kegiatan donor darah merupakan kegiatan rutin tahunan yang dilaksanakan oleh BEM KM UNB dengan tema \"Your Blood Save Many Lives\" , kegiatan donor darah tersebut dihadiri oleh sejumlah 62 peserta pendonor yang terdiri dari civitas akademika UNB, dan warga sekitaran kampus UNB. Diharapkan dengan diadakannya kegiatan ini, sikap peduli dan saling menyayangi antar sesama di masyarakat semakin bertambah. Dan diharapkan agar kegiatan ini akan tetap menjadi agenda tahunan Badan Eksekutif Mahasiswa Keluarga Mahasiswa Universitas Nusa Bangsa. Dr. Ir. Karmanah, SP., M.Si Wakil Rektor III, Kepala Biro Kemahasiswaan dan Alumni diwakili Rea Dwiardhya Garini, S.Ak., M.E Kepala Bagian Kemahasiswaan, dan Ketua Unit Donor Darah PMI diwakili oleh Siska Petugas Pengambilan Darah PMI serta Amri Al-Fansuri sebagai Presiden Mahasiswa, Nazzira Shalma Herra sebagai Ketua Pelaksana memberikan sambutan pada pembukaan acara. \"Syarat-syarat donor darah : Kondisi badan sehat, cukup tidur, tidak mengkonsumsi obat obatan selama 3 hari terakhir, berat badan minimal 50kg. Perempuan : tidak menstruasi, tidak sedang hamil, menyusui. Pemeriksaan laboratorium setelah darah diambil yaitu pemeriksaan HIV, hepatitis B, hepatitis C dan syphilis. Manfaat donor darah, setelah donor tubuh akan memproduksi sel darah merah baru sehingga sirkulasi peredaran lebih lancar dan tubuh akan jauh lebih sehat. Darah yanh di distribusikan ke rumah sakit adalah darah yang lolos screening\", kata Siska Dalimah salam sambutannya. \"Donor darah sudah menjadi kegiatan rutin UNB melalui kegiatan BEM KM, oleh karena itu diharapkan partisipasi seluruh civitas akademika UNB. Darah sangat penting untuk membantu sesama, seperti yang disampaikan Pihak PMI sampai saat ini tidak ada yang bisa memproduksi darah. Sementara dengan kegiatan BEM KM mahasiswa juga belajar berorganisasi dan belajar bekerja bersama. Saling menghargai, berkomunikasi dan memupuk rasa empati. Apresiasi untuk mahasiswa/i yang tergabung di BEM KM dan Terima kasih kepada PMI atas kerjasama nya\", kata Dr. Ir. Karmanah, SP., M.Si dalam sambutannya. Para pendonor yang akan mendonorkan darahnya sebelumnya melalui tahapan-tahapan dalam mendonorkan darah pertama : registrasi yaitu mengisi formulir pendaftaran dan kuisioner kesehatan, kedua : tahap pemeriksaan pendahuluan yaitu pengukuran berat badan, pemeriksaan kadar hemoglobin darah, pemeriksaan golongan darah bagi pendonor pemula. Ketiga : tahap pemeriksaan kesehatan oleh Dokter yaitu anamnesis, pemeriksaan tekanan darah, pemeriksaan fisik sederhana. Keempat : Tahap pengambilan darah donor yaitu cuci lengan donor, pengambilan darah, pengambilan sampel darah. Kelima : tahap administrasi yaitu mengambil kartu donor dan vitamin, terakhir tahap pemulihan yang dimana pendonor dianjurkan untuk istirahat dan menikmati hidangan ringan yang disajikan. (Radar/UNB).", "type": "paragraph"}, {"id": "uz3ncxdbyuhlbeop", "url": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-03-at-13.10.24-225x300.jpeg", "type": "image", "caption": ""}, {"id": "gbh37b628gynit48", "url": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-03-at-13.11.13-300x226.jpeg", "type": "image", "caption": ""}], "excerpt": "Badan Eksekutif Mahasiswa Keluarga Mahasiswa (BEM KM) Universitas Nusa Bangsa (UNB) bekerjasama dengan Palang Merah Indonesia (PMI) menyelenggarakan kegiatan donor darah. Kegiatan donor darah diadakan pada Jum''at (27/9/2...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/10/WhatsApp-Image-2024-10-03-at-13.10.24-225x300.jpeg", "publishedAt": "2024-10-04"}, {"id": "o2u0rxhbfe8zyd1h", "slug": "unb-adakan-pendampingan-teknis-penyusunan-dan-implementasi-sistem-penjaminan-mut", "title": "UNB adakan Pendampingan Teknis Penyusunan Dan Implementasi Sistem Penjaminan Mutu", "author": "Humas UNB", "blocks": [{"id": "muwwx6a74ci4yjle", "text": "Pada Rabu, 25 September 2024 Universitas Nusa Bangsa telah menjadi host pelaksanaan kegiatan “Pendampingan Teknis Penyusunan Dan Implementasi Sistem Penjaminan Mutu sesuai Permendikbud Nomor 53 Tahun 2023” yang diselenggarakn oleh LLDIKTI IV. Acara dihadiri oleh ketua dan anggota Penjaminan Mutu dari 51 Perguruan Tinggi Swasta Rayon 3 meliputi Bogor, Sukabumi, Cianjur dan Depok sejumlah 102 orang dan Fasilitator Wilayah sebagai instruktur dan narasumber Pendampingan SPMI. Acara dibuka oleh Kepala LLDIKTI Wilayah IV yang diwakili oleh Ketua Tim Kerja Akademik, Riset dan Kemahasiswaan Bapak Agus Gumilar ST., M.Kom, serta sambutan oleh Rektor UNB Prof. Dr. Budi Mulyanto, M.Sc. . Pada sambutannya, Prof. Budi menyatakan tentang pentingnya Sistem Penjaminan Mutu Internal di suatu Perguruan Tinggi, dan SPMI ini agar dapat berjalan secara terintegrasi, efektif dan efisien. Sebelum Peserta dibagi ke dalam 5 kelas terpisah, para peserta dan tamu undangan mendapatkan materi tentang “Pentingnya Budaya Mutu di Perguruan Tinggi” yang disampaikan oleh salahsatu Fasilitator Wilayah SPMI LLDIKTI IV Ibu Nanah Sujanah, S.Ag., M.Si.", "type": "paragraph"}, {"id": "9w0osr6iayfy6o3e", "text": "Gambar 01. Rektor UNB Prof. Dr. Budi Mulyanto, M.Sc", "type": "paragraph"}, {"id": "pnxxwg2pkznen38v", "text": "Gambar 02. Agus Gumilar ST., M.Kom", "type": "paragraph"}, {"id": "nmumtllnrz9yd07x", "text": "Nanah Sujanah, S.Ag., M.Si", "type": "paragraph"}, {"id": "nz8os018ccp4o9z6", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-25-at-15.57.40-300x161.jpeg", "type": "image", "caption": ""}, {"id": "3f4vki3s78p7dc2k", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-25-at-15.58.09-300x156.jpeg", "type": "image", "caption": ""}], "excerpt": "Pada Rabu, 25 September 2024 Universitas Nusa Bangsa telah menjadi host pelaksanaan kegiatan “Pendampingan Teknis Penyusunan Dan Implementasi Sistem Penjaminan Mutu sesuai Permendikbud Nomor 53 Tahun 2023” yang diselengg...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-25-at-15.57.40-300x161.jpeg", "publishedAt": "2024-09-25"}, {"id": "tiu9mwbxanid9i47", "slug": "sehat-melalui-pengenalan-kehidupan-kampus-bagi-mahasiswa-baru-pkkmb-tahap-ii-unb", "title": "Sehat melalui Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Tahap II UNB TA 2024/25", "author": "Humas UNB", "blocks": [{"id": "i3omi9bbzcmwfdg6", "text": "Pada hari kedua yakni Minggu 22 September 2024, Panitia Kegiatan Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Universitas Nusa Bangsa melanjutkan kegiatanPKKMB Tahap II TA 2024/25 yakni diantaranya dengan Senam Bersama di Lapangan Kampus Universitas Nusa Bangsa Jl. Sholeh Iskandar Km 4 Bogor (Dekat Lotte Yasmin) . Kegiatan senam diikuti oleh Mahasiswa Baru dan Panitia beserta para Dosen. Hadir juga Wakil rektor 2 Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRGP, Wakil Rektor 3 Dr. Karmanah, SP., MSi serta Dekan Fakultas Ekonomi dan Bisnnis Dr. Isbandriyati Mutmainah, SE., ME dan Dekan Fakultas Pertanian Dr. Ir. Faizal Maad, MSi. Acara dilanjutkan dengan pemaparan tentang Kesadaran Lingkungan Hidup, Manajemen Resiko dan Kampus Sehat Berbudaya oleh Kang Een S.Hut., MM dan Persiapan Penyesuaian Diri Di Perguruan Tinggi (Motivasi) oleh Heri Mardi Purwanto, S.Pd dan Tim, berikutnya adalah Sosialisasi pengenalan dan Demo Unit Kegiatan Kemahasiswaaan (UKM). Selain itu ada juga acara menarik lainnya yakni Nusa Bangsa Fun Games merupakan acara permainan yang membutuhkan kekompakan dan konsentrasi antar mahasiswa dalam kelompok. Pada akhir acara dilakukan Baksos Yatim Piatu sekitar masyarakat sekitar kampus UNB dan terakhir adalah Penutupan. (Radar UNB - HS)", "type": "paragraph"}, {"id": "puyeribq2f5oh2ju", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-22-at-09.13.33-300x225.jpeg", "type": "image", "caption": ""}, {"id": "f5b1un3xze7wnwij", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-22-at-09.15.24-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Pada hari kedua yakni Minggu 22 September 2024, Panitia Kegiatan Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Universitas Nusa Bangsa melanjutkan kegiatanPKKMB Tahap II TA 2024/25 yakni diantaranya dengan Sena...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-22-at-09.13.33-300x225.jpeg", "publishedAt": "2024-09-22"}, {"id": "ihrw32ojmf2a2dx6", "slug": "unb-adakan-pengenalan-kehidupan-kampus-bagi-mahasiswa-baru-pkkmb-tahap-i-ta-2024", "title": "UNB adakan Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Tahap I TA 2024/25", "author": "Humas UNB", "blocks": [{"id": "i6iasmaj9ue40b5f", "text": "Pada hari ini Sabtu, tanggal 21 September 2024 Universitas Nusa Bangsa menggelar acara Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Tahap I TA 2024/25 . Acara dimulai tepat pukul 07.30 Wib di Lapangan Kampus Universitas Nusa Bangsa, pada kesempatan itu Agus Pranamulia , SE., MM . selaku Ketua Panitia PKKMB yang juga Ka. Biro Humas dan Promosi serta Informasi serta Dosen Fakultas Ekonomi UNB menyampaikan jumlah peserta yang mengikuti PKKMB TA 2024/2025 yakni sebanyak 247 CAMABA yang terdiri dari calon mahasiswa Fakultas Pertanian, Fakultas Ekonomi dan Binsis, Fakultas MIPA dan Fahutan. Pada kesempatan itu juga Rektor UNB Prof. Dr. Ir . Budi Mulyanto, MSc . pada kesempatan pidatonya beliau menyampaikan \" Bahwa kita harus bersyukur dan berbahagia masih bisa berkumpul serta mengikuti kegiatan PPKMB di Universitas Nusa Bangsa, mahasiswa merupakan kader bangsa yang akan menjadi calon pemimpin dimasa depan. Tentunya hal ini menjadi cita-cita dan do''a dari orang tua agar teman-teman CAMABA UNB yang hadir ini menjadi orang yang sukses \". Selain itu beliau menyampaikan \" Bahwa PPKKMB sebagai ajang pengenalan kampus dan interaksi tidak hanya antar mahasiswa juga para dosen dan pengelola kampus, Rektor UNB juga meminta kepada kepada para mahasiswa senior untuk melakukan yang terbaik dan memberikan bimbingan kepada junior atau CAMABA serta bukan untuk kesempatan mengerjai CAMABA, belajar dengan serius dan santai serta disiplin menjadi modal awal kesuksesan \" . Kegiatan PKKMB berikutnya dilanjutkan di Gedung Auditorium Universitas Nusa Bangsa hingga sore nanti. Pada kesempatan itu juga selain rektor UNB hadir juga Wakil Rektor 1 Prof. Dr. Ucu Cahyana, MSi, Wakil Rektor 2 Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRG P yang diwakili oleh Kepala BAUU Ir. Chopep Tolandho, MBA dan Wakil Rektor 3 Dr. Ir. Karmanah, MSi, selain itu hadir juga para Dekan, para Kepala Biro, Kepala Lembaga, Para KaProdi dan Ka. Bag serta para Dosen Universitas Nusa Bangsa dan tamu undangan. (HS)", "type": "paragraph"}, {"id": "ksggpguqqosghuye", "text": "Gambar 1. Acara PKKMB Tahap 1 di Lapangan UNB", "type": "paragraph"}, {"id": "kitwbi0t0e7y81xm", "text": "Gambar 2. Penyematan Kartu Pesrta CAMABA oleh Rektor UNB", "type": "paragraph"}, {"id": "f1cfw8fu4jgrzzeq", "text": "Gambar 3. Pembukaan Acara PKKMB dengan Pelepasan Burung Merpati", "type": "paragraph"}, {"id": "5ty2npjwebs0ccii", "text": "Gambar 4. Foto Bersama Civitas Akademika, Panitia dan CAMABA", "type": "paragraph"}, {"id": "veynh4imd0r2kfw4", "text": "Gambar 5. Pemaparan Narasumber (Rektor dan Para Wakil Rektor serta Moderator)", "type": "paragraph"}, {"id": "ye95a8m5hrof04at", "text": "Gambar 6. Peserta PKKM di Gedung Auditorium UNB", "type": "paragraph"}, {"id": "pf0eqvzga7y0jc9h", "text": "Gambar 7. Dekan, Ka. Biro, Ka. Prodi dan Para Tamu Undangan", "type": "paragraph"}, {"id": "udfrjkgumbkw7u9w", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-21-at-08.18.47-300x169.jpeg", "type": "image", "caption": ""}, {"id": "tbnut8mkub0c2uxf", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-21-at-08.18.45-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Pada hari ini Sabtu, tanggal 21 September 2024 Universitas Nusa Bangsa menggelar acara Pengenalan Kehidupan Kampus bagi Mahasiswa Baru (PKKMB) Tahap I TA 2024/25 . Acara dimulai tepat pukul 07.30 Wib di Lapangan Kampus U...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-21-at-08.18.47-300x169.jpeg", "publishedAt": "2024-09-21"}, {"id": "rqzrhzp5692ac6at", "slug": "sosialisasi-mahasiswa-kip-universitas-nusa-bangsa", "title": "Sosialisasi Mahasiswa KIP Universitas Nusa Bangsa", "author": "Humas UNB", "blocks": [{"id": "ktxrm5c9gm5xelnx", "text": "Pada kesempatan itu Rektor UNB Prof. Dr, Ir. Budi Mulyanto, MSc menyampaikan: 1. Fokus dalam perkuliahan selama di UNB karena batas waktu kalian hanya 8 semester 2. Wajib membawa nama baik UNB di masyarakat sekitar 3. Hindari Judol & Game online karena dapat menggangu capaian selama menempuh akademik", "type": "paragraph"}, {"id": "ypoeb061r99o765i", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-18-at-17.43.53-1-300x197.jpeg", "type": "image", "caption": ""}, {"id": "tnrq63ty4nmh9dog", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-18-at-17.43.53-300x213.jpeg", "type": "image", "caption": ""}], "excerpt": "Pada kesempatan itu Rektor UNB Prof. Dr, Ir. Budi Mulyanto, MSc menyampaikan: 1. Fokus dalam perkuliahan selama di UNB karena batas waktu kalian hanya 8 semester 2. Wajib membawa nama baik UNB di masyarakat sekitar 3. Hi...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-18-at-17.43.53-1-300x197.jpeg", "publishedAt": "2024-09-19"}, {"id": "8f2pu4awn0t0wn5w", "slug": "gerak-cepat-wakil-rektor-ii-universitas-nusa-bangsa-bogor", "title": "Gerak Cepat Wakil Rektor II Universitas Nusa Bangsa Bogor", "author": "Humas UNB", "blocks": [{"id": "b9k8r88u2b4ksmqz", "text": "Bogor, 15 September 2024 Selang 2 hari pelantikan, tepatnya pada tgl 11 September 2024. Wakil Rektor 2 Universitas Nusa Bangsa Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRGP yang juga mantan Inspektur Jenderal (Irjen) Kementerian ATR/BPN 2023 lakukan gerak cepat berkoordinasi dengan Kepala IT (Humas) Universitas Nusa Bangsa, Heri Susanto, SE., MM., untuk segera membuat konsep Podcasting dan pengembangan usaha sebagai sarana recurring income bagi kampus UNB. Pada kesempatan itu Kepala IT UNB melakukan kunjungan ke lokasi studio podcasting yang selama ini sudah dilakukan oleh Wakil Rektor 2. Podcasting pada nantinya tidak hanya sebagai Media Promosi dan Informasi tetapi juga untuk melatih mental para mahasiswa serta integritas yang lebih baik lagi antara kampus dengan mahasiswa maupun dosen dengan mahasiswa atau organisasi dengan organisasi lainnya.", "type": "paragraph"}, {"id": "ieqlp2jl7134o70y", "text": "Kunjungan Ka IT ke Lokasi Studio WR 2 UNB, Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRGP", "type": "paragraph"}, {"id": "0jf6izfrmkoatovh", "text": "Disela-sela kunjungan ke lokasi studio, WR 2 mempernankan untuk melihat-lihat peluang usaha dalam pengembangan bisnis UNB dan peluang penelitian serta pengabdian masyarakat untuk para dosen dan Praktek Lapangan untuk para Mahasiswa UNB. (Radar UNB/HS)", "type": "paragraph"}, {"id": "it1gh9q4rlbdqfl7", "text": "Gambar. Peluang Usaha Ternak Kambing", "type": "paragraph"}, {"id": "vwc7hjtasxyau34m", "text": "Gambar. Peluang Usaha Ternak Ayam", "type": "paragraph"}, {"id": "958dj8zjpomesjc0", "text": "Gambar. Ruang untuk Diskusi dan Pelatihan", "type": "paragraph"}, {"id": "rbu2cb566tnqc9bm", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-15-at-06.35.44-300x225.jpeg", "type": "image", "caption": ""}, {"id": "o06m9rdqjwciivcn", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-15-at-06.36.34-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 15 September 2024 Selang 2 hari pelantikan, tepatnya pada tgl 11 September 2024. Wakil Rektor 2 Universitas Nusa Bangsa Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRGP yang juga mantan Inspektur Jenderal (Irjen) Kement...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-15-at-06.35.44-300x225.jpeg", "publishedAt": "2024-09-15"}, {"id": "uhyr1zpvdh1gaso4", "slug": "lembaga-penjaminan-mutu-iai-tazkia-kunjungi-lembaga-penjaminan-mutu-unb", "title": "Lembaga Penjaminan Mutu IAI Tazkia kunjungi Lembaga Penjaminan Mutu UNB", "author": "Humas UNB", "blocks": [{"id": "78zcecwp3v6vqrtg", "text": "Kunjungan Lembaga Penjaminan Mutu Institut Agama Islam (IAI) Tazkia ke Lembaga Penjaminan Mutu UNB Pada hari Selasa, 10 September 2024, LP-Mutu UNB kedatangan tamu dari LPM IAI Tazkia dalam rangka studi banding Penjaminan Mutu Perguruan Tinggi. Dari pihak Tazkia hadir 3 orang sebagai tim Penjaminan Mutu Tazkia, yaitu Bapak Asnan Purba, Lc., M.Pd.I (Direktur LPM Tazkia), Hera Herdiansyah, M.E (Kepala Bagian SPMI) dan Ahmad Hapid, A.Md (Operator PDDikti). Sedangkan dari pihak UNB dihadiri oleh Wakil Rektor I Bidang Akademik (Ibu Tun Susdiyanti, S.Hut., M.Pd), Ketua LP Mutu (Ibu Mamay Maslahat, S.Si., M.Si), Kepala Bagian Perencanaan Monev dan AMI (Ibu Kustin Bintani, S.Hut., M, M.Si) dan Kepala Bagian Hukum, Pangkalan data dan PME (Bapak Anak Agung E, SP., M.Agb). Tujuan kunjungan tim LPM Tazkia adalah untuk silaturahmi antar Lembaga penjaminan mutu Perguruan Tinggi, sharing informasi terkait perkembangan penjaminan mutu dan Asnan menyampaikan keinginannya untuk membentuk komunitas penjaminan mutu perguruan tinggi se Bogor yang dia sebut: Guyup Mutu se-Bogor. Maksud dan tujuan tersebut disambut baik oleh LP Mutu UNB. Sambutan pertama dari pihak UNB disampaikan oleh WR 1, Tun Susdiyanti, bliau menyampaikan bahwa UNB terbuka untuk sharing informasi demi kemajuan bersama, bliau juga menyampaikan bahwa penjaminan mutu merupakan hal yang paling pokok dalam menentukan akreditasi institusi maupun program studi. Oleh karenanya penguatan Lembaga penjaminan mutu merupakan suatu keniscayaan yang tidak boleh dianggap remeh oleh perguruan tinggi. Selanjutnya Ketua LP Mutu, Mamay Maslahat menyampaikan Selayang pandang LP-Mutu UNB sebagai bahan untuk diskusi. Banyak hal yang didiskusikan dalam pertemuan yang berlangsung selama lebih dari dua jam. Tim LP Mutu Tazkia sangat antusias dalam menanggapi pemaparan Mamay Maslahat, banyak hal yang mereka tanyakan dan semua ditanggapi dengan baik oleh Mamay Maslahat. Harapan ke depan, Kerjasama antara LP-Mutu UNB dengan LPM IAI Tazkia dapat terus berlangsung dan saling mendukung untuk penguatan penjaminan mutu di kedua institusi perguruan tinggi ini .", "type": "paragraph"}, {"id": "10qo54k5ysk8w1b4", "url": "https://unb.ac.id/wp-content/uploads/2024/09/Foto03-300x225.jpg", "type": "image", "caption": ""}, {"id": "gy6n8b9w0ltw7w4f", "url": "https://unb.ac.id/wp-content/uploads/2024/09/Foto02-300x169.jpg", "type": "image", "caption": ""}], "excerpt": "Kunjungan Lembaga Penjaminan Mutu Institut Agama Islam (IAI) Tazkia ke Lembaga Penjaminan Mutu UNB Pada hari Selasa, 10 September 2024, LP-Mutu UNB kedatangan tamu dari LPM IAI Tazkia dalam rangka studi banding Penjamina...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/Foto03-300x225.jpg", "publishedAt": "2024-09-11"}, {"id": "tlclkc886it1taf8", "slug": "pelantikan-11-pejabat-struktural-di-unb-oleh-ketua-yayasan-pkmk", "title": "Pelantikan 11 Pejabat Struktural di UNB oleh Ketua Yayasan PKMK", "author": "Humas UNB", "blocks": [{"id": "fn8tx9096r7gf0ev", "text": "Bogor, 11 September 2024 Tepat di tgl 11 September 2024, Ketua Yayasan PKMK Nusantara Ir. Doddy Imron Cholid. MS melantik 11 pejabat struktural di Universitas Nusa Bangsa Bogor, diantaranya adalah:", "type": "paragraph"}, {"id": "kjnoc7dlg8lohray", "text": "Prof. Dr. Ucu Cahyana, MSi sebagai Wakil Rektor I", "type": "paragraph"}, {"id": "2dzbvbr7zfnqzjcd", "text": "Sunrizal, SE., MM., CFrA, CFE, CGCAE, QRGP sebagai Wakil Rektor II", "type": "paragraph"}, {"id": "wmdkmozar1jjfdo7", "text": "Ir. Chopep Tolandho, MBA sebagai Kepala BAUK", "type": "paragraph"}, {"id": "iq26tjtfyr0psgsj", "text": "Dr. Ir. Faizal Maad, MSi sebagai Dekan Fakultas Pertanian", "type": "paragraph"}, {"id": "svu7b7x01yz1s9jj", "text": "Agus Pranamulia, SE., MM sebagai Ka. BHPI", "type": "paragraph"}, {"id": "94ciuwehzrs54i9r", "text": "Mamun Hidayat, S.Kom sebagai Kepala TU Fak. Pertanian", "type": "paragraph"}, {"id": "fq8718v4wf6e6tz1", "text": "Nuryati, S. Ak sebagai Bendahara Bagian Penerimaan", "type": "paragraph"}, {"id": "8vuoa24a85g0iffu", "text": "Halibas, SE sebagai Ka. Bag. Perpustakaan", "type": "paragraph"}, {"id": "0hy9n7ufracgimdl", "text": "Agus Kusnadi, SE sebagai Ka. Bag. Rumah Tangga dan Aset", "type": "paragraph"}, {"id": "nznq49q9rfw0cy9w", "text": "Ahmad Yusron, SMsebagai Kabag Administrasi Akademik dan Laboratorium", "type": "paragraph"}, {"id": "41vr4qmsgfaqng60", "text": "Rea Dwiardhya Garini, S.Ak, M.E sebagai Plt. Ka. Bag. Kemahasiswaan", "type": "paragraph"}, {"id": "gr0fgp73dilejozm", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-12-at-05.40.44-300x135.jpeg", "type": "image", "caption": ""}, {"id": "atfmbgn42221oeg3", "url": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-12-at-06.15.31-300x135.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 11 September 2024 Tepat di tgl 11 September 2024, Ketua Yayasan PKMK Nusantara Ir. Doddy Imron Cholid. MS melantik 11 pejabat struktural di Universitas Nusa Bangsa Bogor, diantaranya adalah: Prof. Dr. Ucu Cahyana,...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/WhatsApp-Image-2024-09-12-at-05.40.44-300x135.jpeg", "publishedAt": "2024-09-11"}, {"id": "vv25ooe19hlha576", "slug": "musyawarah-besar-himamen-feb-universitas-nusa-bangsa-periode-2024-2025", "title": "Musyawarah Besar HIMAMEN FEB Universitas Nusa Bangsa  Periode 2024-2025", "author": "Humas UNB", "blocks": [{"id": "kaxov7ds6y69lz58", "text": "Musyawarah Besar Himpunan Mahasiswa Manajemen (HIMAMEN)", "type": "paragraph"}, {"id": "adz7mwog7ipnywkc", "text": "Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa Periode 2024-2025", "type": "paragraph"}, {"id": "bg2xdx62nmyaf5dj", "text": "Himpunan Mahasiswa Manajemen (HIMAMEN) Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa menyelenggarakan Musyawarah Besar (Mubes) untuk melaksanakan pemilihan ketua himpunan periode 2024-2025 yang digelar pada hari Rabu, 4 September 2024, di Auditorium Universitas Nusa Bangsa Bogor. Mubes HIMAMEN mengusung tema “ Bersinergi Dalam Menjalin Solidaritas Menuju Eksistensi Himpunan Yang Berkarakter dan Berintegrasi ”. Acara dihadiri oleh Warek III Bidang Kemahasiswaan Dr. Karmanah, SP., M.Si., Dekan Fakultas Ekonomi dan Bisnis Dr. Isbandriyati Mutmainah, S.E., M.SE dan Ketua Program Studi Manajemen Iis Anisa Yulia, S.E., MM, perwakilan organisasi mahasiswa dilingkungan Universitas Nusa Bangsa serta seluruh anggota Himpunan Manajemen. Pada Kegiatan Mubes, Faraz Rachma Zahra dan Raja Sabil terpilih sebagai Ketua dan Wakil Ketua HIMAMEN FEB periode 2024-2025. Faraz Rachma Zahra menggantikan Rangga Aldiansyah, yang dinyatakan demisioner setelah laporan pertanggung jawabannya diterima peserta Mubes. Ketua panitia Mubes HIMAMEN, Ryan Antoni Simanjuntak mengatakan kegiatan tersebut diselenggarakan sebagai bagian jalannya kegiatan organisasi. Selain pemilihan ketua himpunan, juga membahas garis haluan organisasi dan AD/ART. Dekan Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa Dr. Isbandriyati Mutmainah, SE., M.SE, turut memberikan sambutan dan mengapresiasi peran aktif HIMAMEN dalam memajukan organisasi kemahasiswaan sekaligus membuka acara Mubes. Setelah menyelesaikan rangkaian kegiatan Mubes, acara dilanjutkan dengan proses pelantikan pengurus HIMAMEN periode 2024-2025. Pengurus dilantik oleh Iis Anisa Yulia, S.E., MM selaku Ketua Program Studi Manajemen. Selanjutnya acara di tutup dengan foto bersama pengurus baru sebagai simbolis dimulainya perjalanan baru bagi HIMAMEN dalam satu periode ke depan. (HS)", "type": "paragraph"}, {"id": "gdnltrexfbmh9gxg", "url": "https://unb.ac.id/wp-content/uploads/2024/09/Himamen-2024-300x169.jpg", "type": "image", "caption": ""}], "excerpt": "Musyawarah Besar Himpunan Mahasiswa Manajemen (HIMAMEN) Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa Periode 2024-2025 Himpunan Mahasiswa Manajemen (HIMAMEN) Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa men...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/09/Himamen-2024-300x169.jpg", "publishedAt": "2024-09-06"}, {"id": "i2j0ezxk8y3dvack", "slug": "sidang-senat-tertutup-yudisium-ii-ta-20232024", "title": "Sidang Senat Tertutup (Yudisium II) TA. 2023/2024", "author": "Humas UNB", "blocks": [{"id": "3qi5air3fuxwv3en", "text": "Bogor, 28 Agustus 2024 Pada hari rabu, 18 Agustus 2024 Universitas Nusa Bangsa mengadakan Sidang Senat Tertutup (Yudisium II) Tahun Ajaran 2023/2024. Pada kegiatan tersebut dihadiri oleh Ketua Yayasan PKMK Nusantara yang diwakili oleh Sunraizal, SE. MM. CFrA, CFE, CGCAE., QRGP, Rektor UNB Prof. Dr. Ir. Budi Mulyanto, MSc, Ketua Senat UNB Dr. Ir. Faizal Maad, MSi, Para Wakil Rektor, para Dekan Fakultas, Kepala Biro, Ketua Lembaga dan Para Ka. Prodi serta perwakilan dosen UNB.", "type": "paragraph"}, {"id": "new3frng1j8cb0fm", "text": "Gambar Ketua Yayasan, Ketua Senat UNB dan Rektor UNB", "type": "paragraph"}, {"id": "0esrkgs8o6nkl795", "text": "Ketua Senat membuka Sidang Senat Tertutup (Yudisium II) Tahun Ajaran 2023/2024. Dilanjutkan sambutan oleh Rektor UNB, pada kesempatan tersebut Rektor UNB Prof. Dr. Ir. Budi Mulyanto, MSc menyampaikan target kedepan UNB menjadikan Perguruan Tinggi (PT) dan Prodi menjadi unggul. Kemarin 3 (tiga) Prodi di UNB sudah Baik Sekali, perlu effort untuk lebih baik lagi, diantaranya melalui: pengmbangan kurikulum, SDM, Manajemen, Peningkatan Jabatan Fungsional Dosen, dan Peningkatan Pendidikan Dosen. Key Issue UNB adalah lembaganya harus sehat, menjadikan akreditasi unggul, komitmen untuk maju, jabatan akademik perlu ditingkatkan dan lulusan UNB harus ditingkatkan tahun depan menjadi 200 pada setiap tahunnya.", "type": "paragraph"}, {"id": "0wynbhtm3z0hzhs4", "text": "Gambar Peserta Sidang Senat Tertutup (Yudisium II) Tahun Ajaran 2023/2024", "type": "paragraph"}, {"id": "nula60iavuydsz6p", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-28-at-13.39.05-300x225.jpeg", "type": "image", "caption": ""}, {"id": "vt43dl3gz2lt6jw9", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-28-at-13.37.18-300x161.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 28 Agustus 2024 Pada hari rabu, 18 Agustus 2024 Universitas Nusa Bangsa mengadakan Sidang Senat Tertutup (Yudisium II) Tahun Ajaran 2023/2024. Pada kegiatan tersebut dihadiri oleh Ketua Yayasan PKMK Nusantara yang...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-28-at-13.39.05-300x225.jpeg", "publishedAt": "2024-08-28"}, {"id": "ll5n87q8wo5um2t9", "slug": "upacara-bendera-17-agustus-2024-di-lingkungan-yayasan-pkmk", "title": "Upacara Bendera, 17 Agustus 2024 di Lingkungan Yayasan PKMK", "author": "Humas UNB", "blocks": [{"id": "r6ktybp6vfm1gs6q", "text": "Bogor, 17 Agustus 2024 Pada hari Sabtu, 17 Agustus 2024 pada pukul 07.30 Wib Yayasan PKMK mengadakan kegiatan upacara 17 Agustus di Lingkungan Yayasan PKMK dalam rangka HUT RI ke 79. Upacara dihadiri oleh jajaran Yayasaan PKMK, Unit Universitas Nusa Bangsa, Unit SMK Kimia Analis dan Unit SMK IT Universitas Nusa Bangsa beserta para tamu undangan lainnya. Pada kesempatan itu yang bertugas sebagai inspektur upacara adalah Ketua Yayasan PKMK Nusantara Ir. Doddy Imran Cholid , MS , beliau menyampaikan bahwa kita harus bangga menjadi bangsa Indonesia. Kemerdekaan Indonesia pada tanggal 17 Agustus 1945, bukanlah dinyatakan sebagai hasil dari pemberian, janji atau hadiah dari siapa pun, namun melainkan dari hasil sebuah proses perjuangan. Setelah kegiatan Upacara Bendera dilanjutkan dengan penyerahan plakat kenang-kenangan kepada Unit-unit yang sudah berprestasi dan peroleh gelar Professor dilanjutkan dengan berbagai perlombaan yang menambah semaraknya HUT RI ke 79.", "type": "paragraph"}, {"id": "iw9p36cwlpp0s186", "text": "Gambar 1. Pidato Ketua Yayasan PKMK Nusantara Ir. Doddy Imran Cholid , MS", "type": "paragraph"}, {"id": "b2plgzqplqohxdx1", "text": "Gambar2. Unit Universitas pada kegiatan Upacara HUT RI ke 79", "type": "paragraph"}, {"id": "cwvrue55d9x0wr0j", "text": "Gambar3. Ketua Yayasan PKMK mendampingi Rektor UNB saat pemberian Plakat", "type": "paragraph"}, {"id": "hny3h4pumyspur2x", "text": "Gambar: Ucapan Terimakasih kepada Pimpinan Unit yang sudah berprestasi", "type": "paragraph"}, {"id": "1ojyvpwdhaav00gj", "text": "Gambar 4. Perlombaan-perlombaan", "type": "paragraph"}, {"id": "fkvggx6b7e37rxi5", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-17-at-10.23.00-225x300.jpeg", "type": "image", "caption": ""}, {"id": "67o5fsdqlwe6iq6m", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-17-at-07.58.25-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 17 Agustus 2024 Pada hari Sabtu, 17 Agustus 2024 pada pukul 07.30 Wib Yayasan PKMK mengadakan kegiatan upacara 17 Agustus di Lingkungan Yayasan PKMK dalam rangka HUT RI ke 79. Upacara dihadiri oleh jajaran Yayasaa...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-17-at-10.23.00-225x300.jpeg", "publishedAt": "2024-08-17"}, {"id": "chpzfstqv7it9rqx", "slug": "penandatanganan-deklarasi-kerjasama-antara-unb-dan-tnggp", "title": "Penandatanganan Deklarasi Kerjasama antara UNB dan TNGGP.", "author": "Humas UNB", "blocks": [{"id": "hw2anqxsrg4l3rth", "text": "Bogor, Jum''at 9 Agustus 2024", "type": "paragraph"}, {"id": "a3xar85ykmqfajp2", "text": "Penandatanganan Deklarasi Kerjasama antara UNB dan TNGGP.", "type": "paragraph"}, {"id": "wwoxqxzx0ltdsbxt", "text": "Jum''at 9 Agustus 2024, Kepala Balai Besar Taman Nasional Gunung Gede Pangrango yang diwakili oleh Plt. Kepala Balai Besar Taman Nasional Gunung Gede Pangrango Sapto Aji Prabowo, S.Hut, M.Si. bersama Rektor Universitas Nusa Bangsa Prof. Dr. Ir. Budi Mulyanto, M.Sc., Bersepakat untuk mendukung Pelaksanaan Tridarma PerguruanTtinggi dan Penyelenggaraan Merdeka Belajar Kampus Merdeka di Taman Nasional Gunung Gede Pangrango dan Universitas Nusa Bangsa dengan tetap berpedoman pada ketentuan peraturan perundangan yang berlaku, untuk melaksanakan: 1. Pendidikan, penelitian, dan pengabdian kepada masyarakat dalam bidang perlindungan dan pengelolaan lingkungan hidup serta kehutanan di Taman Nasional Gunung Gede Pangrango; 2. Pengkajian, diseminasi, publikasi ilmiah, dan pengembangan ilmu pengetahuan dalam bidang perlindungan dan pengelolaan lingkungan hidup serta kehutanan di Taman Nasional Gunung Gede Pangrango; 3. Monitoring daya dukung dan daya tampung lingkungan di kawasan Taman Nasional Gunung Gede Pangrango berbasis Sistem Informasi Lingkungan (SIL); 4. Penyelenggaraan program Merdeka Belajar Kampus Merdeka (MBKM) di kawasan Taman Nasional Gunung Gede Pangrango; 5. Pertukaran dan penggunaan data serta informasi yang diperlukan.", "type": "paragraph"}, {"id": "wwyjaiklojx93umj", "text": "Gambar. Rektor berikut jajarannya bersama Perwakilan TNGGP", "type": "paragraph"}, {"id": "ebr2bqgjf6p7ypbi", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-16-at-10.49.13-300x162.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, Jum''at 9 Agustus 2024 Penandatanganan Deklarasi Kerjasama antara UNB dan TNGGP. Jum''at 9 Agustus 2024, Kepala Balai Besar Taman Nasional Gunung Gede Pangrango yang diwakili oleh Plt. Kepala Balai Besar Taman Nasio...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-16-at-10.49.13-300x162.jpeg", "publishedAt": "2024-08-16"}, {"id": "pxm96rj7u64qn7gr", "slug": "penandatanganan-kontrak-penerima-hibah-dikti-dgn-rektor-unb", "title": "Penandatanganan kontrak penerima Hibah Dikti dgn Rektor UNB", "author": "Humas UNB", "blocks": [{"id": "dwrxkuztv2uzchl5", "text": "Bogor, 16 Agustus 2024", "type": "paragraph"}, {"id": "l8y169x94jdtpf7i", "text": "Penandatanganan kontrak penerima Hibah Dikti dgn Rektor UNB", "type": "paragraph"}, {"id": "h9vze4qkr0kskcah", "text": "Gambar. Rektor UNB Prof. Dr. Ir. Budi Mulyanto, M.Sc. bersama para penerima Hibah Dikti, 2024", "type": "paragraph"}, {"id": "ouhoiem6hneizx0z", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-16-at-10.11.10-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 16 Agustus 2024 Penandatanganan kontrak penerima Hibah Dikti dgn Rektor UNB Gambar. Rektor UNB Prof. Dr. Ir. Budi Mulyanto, M.Sc. bersama para penerima Hibah Dikti, 2024", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-16-at-10.11.10-300x225.jpeg", "publishedAt": "2024-08-16"}, {"id": "bpwgvw7g1q2nveqn", "slug": "pembekalan-dan-pelepasan-kknt-periode-ii-tahun-2024", "title": "Pembekalan dan Pelepasan KKNT periode II  Tahun 2024", "author": "Humas UNB", "blocks": [{"id": "u9tvds74hzkgelmh", "text": "Bogor, 3 Agustus 2024 LPPM Universitas Nusa Bangsa memberikan Pembekalan dan Pelepasan KKNT periode II Tahun 2024. Pada acara tersebut dihadiri oleh Rektor UNB, Para Wakil Rektor, Ketua LPPM, Ketua Lembaga, para Dekan Fakultas, Kepala Biro dan para Kaprodi serta para DPL dan Mahasiswa KKNT juga Panitia. Acara tersebut dibuka oleh Ketua LPPM Dr. Ir. Zainal Muttaqin, MS dengan menyampaikan materi sesuai dengan tema KKNT ini adalah “ Pemberdayaan Perekonomian Masyarakat melalui KKNT Inovasi di Kelurahan Menteng Kota Bogor ”. Tema pokok inovasi dikaitkan langsung dengan upaya pemberdayaan ekonomi masyarakat dengan input inovasi yang terkait dengan visi dan misi UNB. Hal ini mengamanatkan peran dan partisipasi pengabdian mahasiswa sebagai innovator berupa Inovasi menjadi sangat penting untuk menyebarluaskan dan mengintensifkan Gerakan Inovasi Daerah Kota Bogor untuk memajukan Tingkat perekonomian masyarakat. Gerakan Inovasi Daerah untuk mencapai output produk inovasi daerah yang merupakan Gerakan yang sangat strategis pada saat ini. Selain itu Ketua LPPM menghimbau terhadap panitia, DPL dan kelompok KKNT yang sudah ditentukan mulai menjalin komunikasi dengan baik dengan Bapperida Kota Bogor khususnya perizinan dan pendampingan KKNT Inovasi ini serta aparat kelurahan dan kecamatan yang memfasilitasi kegiatan ini. Kepada kelompok KKNT dapat mengintensifkan komunikasi melalui WAG dan akun IG kelompok, dan media sosial lainnya untuk memberitahukan dan mensosialisasikan ke publik rangkaian aksi program Inovasi pemberdayaan ekonomi masyarakat. Selain itu melaksanakan semangat gotong-royong dalam hal kegiatan dan pendanaan baik dari mahasiswa, UNB dan program CSR jika ada. Saya mengharapkan juga dukungan dan koordinasi dari para Dekan dan Ketua program studi untuk memperlancar KKNT ini yang merupakan agenda akademik sekaligus program pengabdian masyarakat. Pada kesempat itu juga hadir Rektor UNB Prof. Dr. Ir. Budi Mulyanto, MSc sebelum melepas mahasiswa KKNT beliau menyampaikan sambutannya \"Kepada para civitas academica harus ada kemauan berubah untuk kemajuan, perubahan merupakan keharusan agar tidak tertinggal\", beliau juga menyampaikan \"Dengan adanya KKNT ini perlunya kedisiplinan dalam kehidupan pribadi dan bermasyarakat, sehingga akan lahir pemimpin-pemimpin yang baik yang siap memimpin daerahnya, mahasiswa KKNT juga harus bisa beradaptasi dan berinovasi dimasyarakat untuk belajar dari lingkungan tempat melakukan KKNT khusunya, bersinergi dan saling menguatkan. Selain itu ilmu yang diperoleh bisa diterapkan karena UNB sudah menyesuaikan kurikulum agar mahasiswa lulusan UNB untuk bisa terjun dimasyarakat terutama turut serta dalam pembangunan di Indonesia\". Acara berikutnya dilanjutjkan dengan arahan Bappeda Kota Bogor yang diwakili oleh Bidang Perencanaan, dalam arahannya mengharapkan agar mahasiswa KKNT bisa berkontribusi dalam peningkatan PAD, terutama melakukan identifikasi pada permasalahan atau potensi masyarakat yang ada kemudian menyampaikan pada pemerintah daerah untuk dijadikan catatan bahkan menjadi program terutama dari daerah tematik menjadikan desa wisata. Kepala BAPPEDA berpesan 1. Prioritas peningkatan pembangunan daerah (ekonomi berbasis lokal) sebagai kekuatan ekonomi, apa yang menjadi unggulan lokal 2. Salah satu Tag Line sebagai Kota Bogor kasohor, dijadikan Progra-program hingga akhir thn 2025, RJPD sekarang tahun terakhir 2025-2045 mengikuti proses nya terutama dalam membentuk Rencana Pembangunan Daerah (RPD) dan Rencana Pembangunan Jangka Panjang (RPJP) bisa menyesuaikan dengan identifikasi dari hasil KKNT di Kelurahan Menteng 3. Isue strategis tentang STANTING, pemda memberikan bantuan berupa telur pd daerah yg mengalami permasalahan gizi. Sebelum berakhir acara dilanjutkan dengan tanya jawab yang dimpimpin oleh WR 3 Dr. Ir. Karmanah MSi , pada tanya jawab tersebut diharapkan mahasiswa benar-benar siap untuk terjun kemasayarakat melalui KKNT. (HS)", "type": "paragraph"}, {"id": "m7zq7pucw2rydh2s", "text": "Gambar1. Acara Pembekalan dan Pelepasan KKNT periode II Tahun 2024", "type": "paragraph"}, {"id": "5kojm5pjug5xbdrr", "text": "Gambar 2. Sambutan Ketua LPPM UNB", "type": "paragraph"}, {"id": "m2cp7ey4ce7a1qwg", "text": "Gambar 3. Sambutan Rektor UNB, Prof. Dr. Ir. Budi Mulyanto, MSc", "type": "paragraph"}, {"id": "nv5wy7qdryh1mtt8", "text": "Gambar 4. Sambutan dari Bappeda Kota Bogor", "type": "paragraph"}, {"id": "rer7ayf7xl1egxa1", "text": "Gambar 5. Foto Bersama Mahasiswa KKNT periode II Tahun 2024", "type": "paragraph"}, {"id": "xxlh7r98lkjz7ude", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-03-at-11.02.32-300x225.jpeg", "type": "image", "caption": ""}, {"id": "9s383f44xttvkkcq", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-03-at-11.06.55-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 3 Agustus 2024 LPPM Universitas Nusa Bangsa memberikan Pembekalan dan Pelepasan KKNT periode II Tahun 2024. Pada acara tersebut dihadiri oleh Rektor UNB, Para Wakil Rektor, Ketua LPPM, Ketua Lembaga, para Dekan Fa...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-03-at-11.02.32-300x225.jpeg", "publishedAt": "2024-08-03"}, {"id": "gjhs85kp3v8sc0rq", "slug": "penyampaian-materi-pembekalan-kknt-unb", "title": "PENYAMPAIAN MATERI PEMBEKALAN KKNT UNB", "author": "Humas UNB", "blocks": [{"id": "k9tacn0610339ooi", "text": "Bogor, 2 Agustus 2024", "type": "paragraph"}, {"id": "m4uozncvmettkg0t", "text": "PEMBERDAYAAN PEREKONOMIAN MASYARAKAT MELALUI KKNT INOVASI", "type": "paragraph"}, {"id": "c7a8zbsu0pttppc3", "text": "Pada kegiatan pembekalan KKNT UNB pada 2 Agustus 2024, narasumber menjelaskan tentang apa itu KKN, posisi KKN dalam tridharma perguruan tinggi, karaketristik dan tujuan KKNT, mengapa UNB mengambil tema “Pemberdayaan Perekonomian Masyarakat Melalui KKNT Inovasi”, serta tips menuyusun program kegiatan KKNT Isbandriyati Mutmainah, Dekan FEB UNB selaku narasumber menjelaskan bahwa KKN merupakan kegiatan perkuliahan intrakulikuler dalam bentuk pengabdian kepada masyarakat oleh Perguruan Tinggi yang dilaksanakan terutama oleh mahasiswa secara interdisipliner dan dibawah bimbingan dosen dan pimpinan pemerintah daerah. Tema Pemberdayaan Perekonomian Masyarakat Melalui KKNT Inovasi dipiliha karena mahasiswa harus berperan aktif dalam membantu pemerintah memberdayakan ekonomi masyarakat melalui inovasi-inovasi berkelanjutan. Inovasi-inovasi yang disampaikan oleh mahasiswa peserta KKNT Inovasi dapat dilakukan dengan berbagai kegiatan seperti pengembangan produk lokal, pelatihan kewirausahaan, pemanfaatan teknologi informasi, atau penguatan kelembagaan. Narasumber juga menyampaikan tips dalam menyusun program kerja KKNT. Kegiatan KKN harus dilakukan dengan prinsip co-creation, co-funding, flexible, dan sustainable. Dalam pelaksanaan KKN, mahasiswa perlu melakukan perencanaan dan survei awal untuk mengidentifikasi permasalahan dan potensi lokasi KKN, yang selanjutnya menjadi dasar untuk menyusun kegiatan. Output dari kegiatan KKN adalah laporan kegiatan, paparan untuk lokakarya, video pelaksanaan KKN dan output inovasi.", "type": "paragraph"}, {"id": "qlzd3h78xkd8z1nn", "text": "Gambar 1 PENYAMPAIAN MATERI PEMBEKALAN KKNT UNB via ZOOM", "type": "paragraph"}, {"id": "0ylng065kjwhfjkt", "url": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-03-at-11.52.09-300x188.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 2 Agustus 2024 PEMBERDAYAAN PEREKONOMIAN MASYARAKAT MELALUI KKNT INOVASI Pada kegiatan pembekalan KKNT UNB pada 2 Agustus 2024, narasumber menjelaskan tentang apa itu KKN, posisi KKN dalam tridharma perguruan ting...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/08/WhatsApp-Image-2024-08-03-at-11.52.09-300x188.jpeg", "publishedAt": "2024-08-03"}, {"id": "xgnhow8mj2wihokd", "slug": "unb-berdayakan-kth-cibulao-hijau-melalui-inovasi-agroforestri", "title": "UNB Berdayakan KTH Cibulao Hijau Melalui Inovasi Agroforestri", "author": "Humas UNB", "blocks": [{"id": "ucmpwtwzuhmp2r1n", "text": "Bogor – Universitas Nusa Bangsa (UNB) , melaksanakan rangkaian kegiatan dari pelaksanaan Program Kemitraan Masyarakat (PKM) Pengabdian Kepada Masyarakat Kompetitif Nasional yang merupakan hibah Kemendikbud Ristek Dikti Tahun anggaran 2024 dengan tema Pemberdayaan Kelompok Tani Hutan (KTH) Cibulao Hijau dalam Meningkatkan Kemampuan Inovasi Usaha Agroforestri di Desa Tugu Utara Kecamatan Cisarua Kabupaten Bogor . Desa Tugu Utara Kecamatan Cisarua Kabupaten Bogor berada pada kawasan puncak Bogor, yang merupakan daerah penyangga memiliki potensi dalam perlindungan kawasan daerah sekitarnya terhadap banjir dan longsor. Salah satu cara menanggulangi hal tersebut dapat dilakukan dengan pengembangan agroforestri. Agroforestri merupakan satu dari sekian banyaknya sistem pengelolaan lahan yang berfungsi secara produktif dan protektif dengan mempertahankan keanekaragaman hayati, ekosistem sehat, konservasi air dan tanah dan meningkatkan ketahanan pangan. Selain itu adanya perubahan paradigma baru tentang pengelolaan hutan yang lebih mempertimbangkan pengelolaan sumber daya alam ( natural resources management ) dan usaha meningkatkan kesejahteraan masyarakat yang hidup di sekitar hutan, maka Indonesia memiliki peluang besar untuk mengembangkan sistem agroforestry. Desa Tugu Utara memiliki Hutan Pangkuan Desa (HPD) seluas 610,64 Ha yang di dalamnya terdapat kebun kopi Cibulao dengan luas sebesar ±60 Ha. Di dalam kebun tersebut terdapat berbagai macam jenis pohon yang diantaranya adalah Sengon, Rasamala, Kayu Afrika, Jati Putih, Riung Anak, Suren, Jabon, Alpukat, Nangka, Jambu yang berfungsi sebagai naungan untuk tanaman kopi yang di budidayakan oleh para petani hutan. Kelompok Tani Hutan Cibulao Hijau terbentuk pada tahun 2007 yang sebelumnya merupakan Kelompok Peduli Lingkungan pada tahun 1999 dengan tujuan untuk melestarikan pohon-pohon hutan. Perhutani telah memberikan pendampingan atau sosialisasi mengenai pentingnya hutan dan pengembangan ekonomi kreatif, yang berfokus pada agroforestri kopi dengan memanfaatkan pohon-pohon hutan yang sudah tersedia pada lahan sebagai pohon naungan bagi kopi. Program Kemitraan antara perhutani dengan KTH tertuang dalam Surat Keputusan Menteri Lingkungan Hidup dan Kehutanan Republik Indonesia Nomor: SK. 8960/MENLHK-PSKL/PKPS/PSL.0/12/2018 tentang Pengakuan dan Perlindungan Kemitraan Kehutanan (KULIN KK). Berdasarkan penelitian sebelumnya bahwa dalam pengelolaan agroforestri, KTH memiliki pengetahuan kewirausahaan, manajemen usaha dan inovasi usaha masih terbatas. Sehingga diperlukan pelatihan dan pendampingan dalam manajemen dan inovasi usaha. Salah satu rangkaian kegiatan PKM telah dilaksanakan pendampingan dan pelatihan kewirausahaan pada tanggal 23 Juli 2024, yang diikuti sebanyak 30 orang terdiri dari anggota KTH dan tim PKM terdiri dari dosen (Tun Susdiyanti, Linar Humaira, Nengsih Anen) serta mahasiswa (Kristia Sumpiana, Ni Ketut Dhara, Faraz Rachma). Materi kewirausahaan disampaikan oleh Dr. Faizal Maad, Ir., M.Si merupakan dosen Magister Ekonomi Pembangunan UNB. Tindak lanjut kegiatan ini adalah pelatihan dan pendampingan manajemen dan inovasi usaha berupa pelatihan analisis usaha agroforestri dan pelatihan pemasaran secara offline dan online . Kegiatan PKM mendapatkan respon yang baik, terlihat dari antusiasme peserta cukup tinggi, hal ini ditandai dengan pertanyaan-pertanyaan dalam diskusi serta hasil pretest dan post tess terjadi peningkatan pemahaman terhadap materi sebesar 68%. Menurut Herdi salah satu pengurus KTH Cibulao Hijau bahwa kegiatan PKM ini sangat penting dalam meningkatkan kemampuan berwirausaha yang akan berdampak dalam meningkatkan pendapatan anggota kelompok dengan tetap menjaga kelestarian hutan. Sedangkan menurut ketua PKM Tun Susdiyanti bahwa kegiatan PKM ini terintegrasi dengan program Merdeka Belajar Kampus Merdeka (MBKM) berbasis pada Indikator Kinerja Utama (IKU), yang melibatkan 3 orang mahasiswa untuk mendapatkan pengalaman diluar kampus dengan diberikan pengakuan SKS.", "type": "paragraph"}, {"id": "4r3pqqv3qluc5q92", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-30-at-09.09.01-225x300.jpeg", "type": "image", "caption": ""}, {"id": "p4c1iztyafl01zo0", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-30-at-09.09.00-1-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor – Universitas Nusa Bangsa (UNB) , melaksanakan rangkaian kegiatan dari pelaksanaan Program Kemitraan Masyarakat (PKM) Pengabdian Kepada Masyarakat Kompetitif Nasional yang merupakan hibah Kemendikbud Ristek Dikti T...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-30-at-09.09.01-225x300.jpeg", "publishedAt": "2024-07-30"}, {"id": "02cudnru8t96qcnu", "slug": "pembukaan-pu-phl-angkatan-ke-33-fahutan-unb", "title": "Pembukaan PU PHL angkatan ke 33 Fahutan UNB", "author": "Humas UNB", "blocks": [{"id": "o20ujq2ostbkzp2d", "text": "PRAKTIK UMUM KEHUTANAN PENGELOLAAN HUTAN LESTARI (PUPHL)", "type": "paragraph"}, {"id": "hvqle28865q7fajm", "text": "Minggu, 28 Juli 2024 telah dilaksanakan pembukaan Praktik Umum Kehutanan Pengelolaan Hutan Lestari (PU PHL) angkatan ke 33 Fakultas Kehutanan Universitas Nusa Bangsa (UNB) Bogor dan mahasiswa dari Jurusan Kehutanan, Fakultas Pertanian Universitas Lampung (UNILA) di Kampus Lapangan Getas dan Wanagama Universitas Gadjah Mada. Kegiatan PU PHL merupakan implementasi dari Kerjasama (MoU) antara Fakultas Kehutanan Universitas Nusa Bangsa - Fakultas Kehutanan Universitas Gadjah Mada dan Fakultas Kehutanan Universitas Nusa Bangsa - Fakultas Pertanian Universitas Lampung diikuti sebanyak 105 orang (22 orang dari UNB dan 83 orang dari UNILA). Selain itu PU PHL merupakan bagian dari perkuliahan tahap akhir, dimana mahasiswa diharapkan mampu secara simultan mengaplikasikan teori-teori ilmu kehutanan dalam rangka mengelola hutan secara lestari dan berkelanjutan dari aspek ekologi, ekonomi, dan sosial. PU PHL meliputi kegiatan perencanaan hutan, pembinaan hutan, kelola sosial, pemanenan hasil hutan , industri hasil hutan, serta konservasi sumber daya hutan. Kegiatan PU PHL direncanakan berlangsung selama 20 hari (28 Juli - 16 Agustus 2024). Selama PU PHL berlangsung, para peserta diwajibkan mengikuti seluruh rangkaian kegiatan dari perencanaan, pelaksanaan, dan pelaporan setiap harinya. (A/HS)", "type": "paragraph"}, {"id": "2z3oelq3vbjnc9v5", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-29-at-16.43.08-300x225.jpeg", "type": "image", "caption": ""}, {"id": "ecxpyfr4sg5d488a", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-29-at-16.43.07-3-e1722284391634-225x300.jpeg", "type": "image", "caption": ""}], "excerpt": "PRAKTIK UMUM KEHUTANAN PENGELOLAAN HUTAN LESTARI (PUPHL) Minggu, 28 Juli 2024 telah dilaksanakan pembukaan Praktik Umum Kehutanan Pengelolaan Hutan Lestari (PU PHL) angkatan ke 33 Fakultas Kehutanan Universitas Nusa Bang...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-29-at-16.43.08-300x225.jpeg", "publishedAt": "2024-07-29"}, {"id": "23yxzb1ox9nipkmf", "slug": "sarasehan-inohong-jawa-barat-di-auditorium-unb-bogor", "title": "Sarasehan Inohong Jawa Barat di Auditorium UNB Bogor", "author": "Humas UNB", "blocks": [{"id": "s5dny77hsbglrpzp", "text": "Bogor, 28 Juli 2024 Sarasehan inohong Jawa Barat Dalam rangka persiapan dan kesiapan daerah Jawa Barat dalam menghadapi Program Aglomerasi Jakarta sesuai dengan UU No. 2 Tahun 2024. Gerakan Pemuda Islam yang didukung oleh Univesitas Nusa Bangsa, melakukan kegiatan sarasehan inohong Jawa Barat di Gedung Auditorium Universitas Nusa Bangsa Bogor. Pada kegiatan tersebut mengundang narasumber diantaranya Ir. Doddy Imran Cholid, MS Ketua Yayasan PKMK Nusantara, Dr. Ir. Ilham Habibie putra Presiden ke 3 Indonesia Bj Habibie, Kemudian Saudara Ade Calon Bupati Sukabumi, Saudara Ade Wardana calon Bupati Kab Bogor, saudara Sendi Calon Walikota Bogor dan beberapa tokoh jawa barat lainnya. Pada kesempatan itu Doddy dalam paparannya menyampaikan bahwa Kawasan Aglomerasi adalah kawasan yang saling memiliki keterkaitan fungsional yang dihubungkan dengan sistem jaringan prasarana wilayah yang terintegrasi sekalipun berbeda dari sisi administratif sebagai suatu pusat pertumbuhan ekonomi nasional yang berskala Global. Ada 10 (Sepuluh) Kabupaten dan Kota yan masuk dalam kawasan aglomerasi yakni Jakarta, Tangerang, Tangerang Selatan, Bekasa, Kab. Bekasi, Kab. Bogor, Kota Bogor dan Kab. Cianjur.", "type": "paragraph"}, {"id": "decnjgar8eewdrtn", "text": "Gambar 1. Doddy Imran Cholid menyampaikan paparan", "type": "paragraph"}, {"id": "wpbkfm4la9ld5yu7", "text": "Doddy juga menyampaikan kawasan tersebut memiliki banyak kepentingan, misalkan Jakarta perlu di supply dari Kab. Sukabumi, Cianjur, kab. Bekasi dan lainnya 9 bahan pokok selain itu kebutuhan tenaga kerja, kebutuhan industri semuanya itu diperlukan oleh Jakarta sementara Kab. Kota sekitarnya memerlukan Jakarta untuk memasarkan barang-barang hasil produksinya. Akan tetapi Jakarta tidak berharap pada musim hujan dari daerah sekitarnya dikirim air yang banyak yang menyebabkan banjir atau Jakarta tidak jugaberharap pada siang hari semua mobil masuk ke Jakarta, akibatnya Jakarta kena macet. Jakarta juga tidak berharap penduduk terus masuk ke Jakarta menyebabkan Jakarta semakin padat sehingga menimbulkan masalah diantaranya sampah, daerah kumuh dan lainnya. Artinya adanya beberapa masalah pada kawasan Aglomerasi yang pertama masalah banjir, kedua kemacetan, ketiga sampah, dan daerah masalah kumuh. Ini secara bersamaan masing-masing Kab dan Kota harus duduk bersama untuk menanggulangi permasalahan diatas tadi. Jakarta juga berharap barang-barang yang dikirim Ke Jakarta ini berkualitas tinggi dan berhasil guna tinggi, maka untuk itu daerah sekitar Jakarta harus menyiapkan SDM yang bagus sehingga mereka datang ke Jakarta terampil sehingga dapat menciptakan pekerjaan yang bagus, hasil yang bagus sehingga terjadilah pemerataan pendapatan. Selain itu sarana dan prasarana terkait, harus disiapkan untuk menanggulangi permasalahan. Sehingga duduk bersama untuk mendiskusikan kawasan aglomerasi sangat penting dilakukan.", "type": "paragraph"}, {"id": "sv7qqgs5exq4e80t", "text": "Pada kegiatan saresehan itu, narasumber lainnya menyampaikan juga berkaitan dengan daerah yang akan menjadi bakal calon ditempatnya masing-masing, mereka menyampikan alasan mencalonkan, program dan strategi yang akan mereka lakukan. Kegiatan diakhiri dengan Foto dan makan siang bersama. (HS/DIC). [video width=\"1280\" height=\"720\" mp4=\"https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Video-2024-07-28-at-21.11.39-2.mp4\"][/video] [video width=\"720\" height=\"1280\" mp4=\"https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Video-2024-07-28-at-21.11.39.mp4\"][/video]", "type": "paragraph"}, {"id": "89dlflrhovef76gz", "text": "Foto Doddy Imran Chalid bersama Dr. Ir. Ilham Habibie, Sendi, Ade Wardana dan Narasumber lainnya", "type": "paragraph"}, {"id": "9pya3hrovjxzgi8w", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-28-at-20.00.15-300x169.jpeg", "type": "image", "caption": ""}, {"id": "2cx3vd6fpo3tg360", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-28-at-20.00.16-1-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 28 Juli 2024 Sarasehan inohong Jawa Barat Dalam rangka persiapan dan kesiapan daerah Jawa Barat dalam menghadapi Program Aglomerasi Jakarta sesuai dengan UU No. 2 Tahun 2024. Gerakan Pemuda Islam yang didukung ole...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-28-at-20.00.15-300x169.jpeg", "publishedAt": "2024-07-28"}, {"id": "dt4060thyx74n9j4", "slug": "akreditasi-baik-sekali-untuk-magister-ekonomi-pembangunan-unb", "title": "Akreditasi Baik Sekali untuk Magister Ekonomi Pembangunan UNB", "author": "Humas UNB", "blocks": [{"id": "jhtwtsbka60c2iph", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-23-at-14.27.43-300x300.jpeg", "type": "image", "caption": ""}], "excerpt": "", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-23-at-14.27.43-300x300.jpeg", "publishedAt": "2024-07-23"}, {"id": "od06uy38kpnyhstk", "slug": "rapat-kerja-nasional-sylva-indonesia", "title": "RAPAT KERJA NASIONAL SYLVA INDONESIA", "author": "Humas UNB", "blocks": [{"id": "3h5xxrkxwvlot1rh", "text": "Pontianak, 9 juli 2024 Kegiatan Rapat Kerja Nasional telah dilaksanakan pada tanggal 9-14 Juli 2024 yang bertempat di Aula Gedung Rektorat Universitas Tanjungpura Jl. Dr. Prof. H. Hadari Nawawi, Bansir laut, Kec. Pontianak Tenggara, Kota Pontianak, Kalimantan Barat. Rapat Kerja Nasional Sylva Indonesia (RAKERNASSI) merupakan kegiatan wajib yang diatur dalam AD/ART Sylva Indonesia yang mempertemukan para delegasi dari Seluruh Pengurus Cabang Sylva Indonesia untuk membahas hal-hal yang berkaitan dengan pelaksanaan program kerja yang diusung oleh Pengurus Pusat Sylva Indonesia selama 1 periode kepengurusan. Rapat Kerja Nasional Sylva Indonesia diselenggarakan oleh Pengurus Pusat Sylva Indonesia untuk membahas dan menetapkan program-program dan rekomendasi dari PC yang hadir pada Rapat Kerja Nasional Sylva Indonesia (RAKERNASSI). Hasil dari Rakernas nantinya akan dilaksanakan melalui UPT (Unit Penyelenggara Teknis) yang mana UPT sendiri dari PC yang bersedia mengambil kegiatan dan juga atas kesepakatan dari forum Rapat Kerja Nasional Sylva Indonesia. Kegiatan ini nantinya akan diikuti oleh 50 Perguruan Tinggi yang tergabung dalam Sylva Indonesia. Tema yang diusung dalam Rapat Kerja Nasional Sylva Indonesia (RAKERNAS) menjadi landasan utama yang mengarahkan fokus dan substansi dari seluruh kegiatan. Tema yang dipilih untuk Rapat Kerja Nasional (RAKERNAS) tahun ini telah dirumuskan dengan cermat, menggambarkan komitmen Sylva Indonesia dalam berkontribusi aktif dalam aksi mitigasi perubahan iklim melalui kolaborasi multi-stakeholder. Adapun tema kegiatan yang diusung adalah: \"Peran Sylva Indonesia dalam Aksi Mitigasi Perubahan Iklim melalui Kolaborasi Multi-Stakeholder\" Berdasarkan hasil Rapat Kerja Nasional (RAKERNAS) Sylva Indonesia 2024 yang dilaksanakan pada 10-12 Juli 2024 di Pontianak. Isi dari Rapat Kejra Nasional (RAKERNAS) Sylva Indonesia sendiri untuk menetapkan Program Kerja Pengurus Pusat, kegiatan Nasional Sylva Indonesia, dan unit penyelenggara teknis (UPT) kegiatan Nasional Sylva Indonesia. Dengan ini Pengurus Pusat Sylva Indonesia memutuskan berdasarkan penetapan pada PCSI yang terpilih sebagai UPT pelaksana kegiatan Sylva Indonesia periode 2024-2026:", "type": "paragraph"}, {"id": "ez78oqyw4njw8rbj", "text": "Latihan Kepemimpinan Sylva Indonesia (LKSI) dengan unit penyelenggara terpilih ialah, Pengurus Cabang Sylva Indonesia Universitas Lambung Mangkurat.", "type": "paragraph"}, {"id": "2yqw3x95xig9obhj", "text": "Pelatihan Mahasiswa Kehutanan Indonesia (PMKI) dengan unit penyelenggara terpilih ialah, Pengurus Cabang Sylva Indonesia Universitas Lampung.", "type": "paragraph"}, {"id": "6pwz6jd9a982eutt", "text": "Seminar Mahasiswa Kehutanan Indonesia (SMKI) dengan unit penyelenggara terpilih ialah, Pengurus Cabang Sylva Indonesia Universitas Sumatera Utara,", "type": "paragraph"}, {"id": "yjvc45ep7obrto8t", "text": "Loka Karya Sylva Indonesia (LSI) dengan unit penyelenggara terpilih ialah, Pengurus Cabang Sylva Indonesia Universitas Universitas Gadjah Mada.", "type": "paragraph"}, {"id": "8m9fimp5iii55k4g", "text": "Konferensi Nasional Sylva Indonesia (KNSI) dengan unit peyelenggara terpilih ialah, Pengurus Cabang Sylva Indonesia Universitas Tanjungpura.", "type": "paragraph"}, {"id": "e81f8ftuuzg1bo9k", "url": "https://unb.ac.id/wp-content/uploads/2024/07/Rakernas01-300x199.jpg", "type": "image", "caption": ""}, {"id": "o8jon5a2l3bsidca", "url": "https://unb.ac.id/wp-content/uploads/2024/07/Rakernas02-300x200.jpg", "type": "image", "caption": ""}], "excerpt": "Pontianak, 9 juli 2024 Kegiatan Rapat Kerja Nasional telah dilaksanakan pada tanggal 9-14 Juli 2024 yang bertempat di Aula Gedung Rektorat Universitas Tanjungpura Jl. Dr. Prof. H. Hadari Nawawi, Bansir laut, Kec. Pontian...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/Rakernas01-300x199.jpg", "publishedAt": "2024-07-19"}, {"id": "0cznzmheif5ncsac", "slug": "unb-dan-kth-mkk-cisangku-sosialisasi-persemaian-bibit-langka", "title": "UNB dan KTH MKK Cisangku Sosialisasi Persemaian Bibit Langka", "author": "Humas UNB", "blocks": [{"id": "m1ujfox6x01lmyu6", "text": "UNB dan KTH MKK Cisangku", "type": "paragraph"}, {"id": "0r12ymu2u8pvpimh", "text": "Adakan Sosialisasi Persemaian Bibit Langka Endemik di TNGHS", "type": "paragraph"}, {"id": "106rnwbub47awu8w", "text": "Upaya menjaga keberadaan tanaman dan kelestarian kawasan hutan sekitar Taman Nasional Gunung Halimun Salak (TNGHS) perlu dipertahankan guna melindungi habitat dan fungsi-fungsi ekologisnya. Salah satunya dengan mensosialisasikan jenis-jenis tanaman langka endemik TNGHS, seperti jenis Saninten ( Castanopsis argantea ) dan Palahlar ( Dipterocarpus retusus Bl) melalui kegiatan Focus Group Discussion (FGD). Upaya ini dimaksudkan untuk mengenalkan jenis-jenis tanaman langka endemik TNGHS dan sharing informasi dalam pengembangan persemaian bibit tanaman dan pengelolaan kawasan hutan. Menurut Ketua MKK Cisangku (Bp. Hendrik), Saninten dan Palahlar memiliki nilai ekonomi yang baik, permintaannya pun terus meningkat untuk kegiatan restorasi kawasan, namun sudah mulai langka dan sulit ditemukan disekitar TNGHS. Oleh karena itu keberadaannya harus dijaga dengan menyediakan bibit tanaman tersebut dan melakukan penanaman di sekitar kawasan TNGHS. Kegiatan sosialisasi dilakukan oleh beberapa dosen UNB yaitu Dr. Karmanah,SP.MSi, Abdul Rahman Rusli, S.Hut.MSi, Mulyana Gustira Putra, SE.MSi., Kustin Bintani Meiganati, S.Hut. MSi., dan mahasiswa Univeritas Nusa Bangsa (Fahreza, Randi, Badrul Kamal, Iqbal) kepada 27 orang anggota Kelompok Tani Hutan Model Kampung Konservasi (KTH MKK) Cisangku dan Masyarakat. Sosialisasi juga dihadiri oleh Aparat Desa Malasari dan Staf Seksi Wilayah 2 Bogor TNGHS. Menurut ketua pelaksana Dr.Karmanah, kegiatan ini dilaksanakan sebagai salah satu wujud pengabdian masyarakat yang penting dilakukan oleh dosen dan mahasiswa UNB guna menyampaikan informasi pengetahuan. Kegiatan yang mendapatkan dukungan Kemendikbud Ristek Dikti ini juga sebagai wadah belajar bagi dosen dan mahasiswa bersama masyarakat. Kami tentunya sangat mendukung pencapaian Indikator Kinerja Utama (IKU) program Merdeka Belajar Kampus Merdeka (MBKM), terangnya. Lebih lanjut disampaikan bahwa kegiatan ini juga akan disusul dengan pelatihan-pelatihan dalam pengembangan persemaian bibit kedua jenis tanaman tersebut.", "type": "paragraph"}, {"id": "k4mbr4eavt2clmvz", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-13-at-11.24.26-300x226.jpeg", "type": "image", "caption": ""}, {"id": "hptaq22qhykxwh83", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-13-at-11.24.25-300x226.jpeg", "type": "image", "caption": ""}], "excerpt": "UNB dan KTH MKK Cisangku Adakan Sosialisasi Persemaian Bibit Langka Endemik di TNGHS Upaya menjaga keberadaan tanaman dan kelestarian kawasan hutan sekitar Taman Nasional Gunung Halimun Salak (TNGHS) perlu dipertahankan...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-13-at-11.24.26-300x226.jpeg", "publishedAt": "2024-07-14"}, {"id": "jt8l44nzg8k3tu4s", "slug": "telah-berpulang-ke-rahmatullah-bapak-prof-dr-supriyono-eko-wardoyo", "title": "Telah berpulang ke Rahmatullah Bapak Prof Dr Supriyono Eko Wardoyo", "author": "Humas UNB", "blocks": [{"id": "afp5bs7uigfvahl6", "text": "اَلَّذِيْنَ اِذَآ اَصَابَتْهُمْ مُّصِيْبَةٌ ۗ قَالُوْٓا اِنَّا لِلّٰهِ وَاِنَّآ اِلَيْهِ رٰجِعُوْنَۗ", "type": "paragraph"}, {"id": "k2moy15jilk883xx", "text": "Artinya: \"(yaitu) orang-orang yang apabila ditimpa musibah, mereka mengucapkan \"Innā lillāhi wa innā ilaihi rāji''ūn\"", "type": "paragraph"}, {"id": "8rdx9194axteg2to", "text": "(sesungguhnya kami adalah milik Allah dan sesungguhnya hanya kepada-Nya kami akan kembali).\"", "type": "paragraph"}, {"id": "og482dtz5z6dw0c9", "text": "INNALILLAAHI WA INNA ILAIHI ROOJIUN Telah berpulang ke Rahmatullah Bapak Prof Dr Supriyono Eko Wardoyo pada hari Sabtu 13 Juli 2024 jam 14.48.", "type": "paragraph"}, {"id": "pno56zik5f4g5vqu", "text": "Alamat duka Komplek Griya Talangsari no 18 Ciluar BOGOR. Rencana akan dimakamkan besok Minggu jam 09.00", "type": "paragraph"}, {"id": "ds38qjgbu4e67ah0", "text": "Segenap keluarga menghaturkan maaf atas khilaf dan salah Semoga almarhum mendapatkan tempat terbaik di sisi Allah yang maha kuasa, dan seluruh keluarga yang ditinggalkan diberikan ketabahan serta keikhlasan.", "type": "paragraph"}, {"id": "7xad4ism49g9oxo9", "text": "Rektor UNB Prof. Dr. Ir. Budi Mulyanto, M.Sc. dan segenap Civitas Academica Universitas Nusa Bangsa, mengucapkan bela sungkawa atas meninggalnya Prof Dr Supriyono Eko Wardoyo, semoga almarhum terlimpah maghfirah dan kemuliaan dari Allah.", "type": "paragraph"}, {"id": "7o041yp85ttx4878", "text": "Allahummaghfirlahu warhamhu wa ''afihi wa''fu ''anhu, wa akrim nuzulahu.", "type": "paragraph"}, {"id": "6jbp7x2ybcmpkqbd", "text": "Ya Allah, ampunilah, rahmatilah, lindungilah, serta muliakanlah tempatnya", "type": "paragraph"}, {"id": "qs920vo7gqspn9wf", "url": "https://unb.ac.id/wp-content/uploads/2024/07/Turut-Berduka-Prof-Eko-Juli-2024-300x169.jpg", "type": "image", "caption": ""}, {"id": "ehypwmuf6n49z527", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-14-at-03.54.55-247x300.jpeg", "type": "image", "caption": ""}], "excerpt": "اَلَّذِيْنَ اِذَآ اَصَابَتْهُمْ مُّصِيْبَةٌ ۗ قَالُوْٓا اِنَّا لِلّٰهِ وَاِنَّآ اِلَيْهِ رٰجِعُوْنَۗ Artinya: \"(yaitu) orang-orang yang apabila ditimpa musibah, mereka mengucapkan \"Innā lillāhi wa innā ilaihi rāji''ūn\"...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/Turut-Berduka-Prof-Eko-Juli-2024-300x169.jpg", "publishedAt": "2024-07-14"}, {"id": "vpqu3r0c9nh2sita", "slug": "penyerahan-sk-jabatan-akademik-dosen-guru-besar-dr-ir-luluk-setyaningsih-msi", "title": "Penyerahan SK Jabatan Akademik Dosen Guru Besar Dr. Ir. Luluk Setyaningsih, M.Si", "author": "Humas UNB", "blocks": [{"id": "bi6lmh7p05hm3l8w", "text": "Bandung, 9 Juli 2024", "type": "paragraph"}, {"id": "vxswfu559o6dvcw4", "text": "Sehubungan dengan telah terbitnya SK Jabatan Akademik Dosen Guru Besar Kementerian Pendidikan, Kebudayaan, Riset, dan Teknologi, Lembaga Layanan Pendidikan Tinggi Wilayah IV mengundang Dr. Ir. Luluk Setyaningsih, M.Si . Penyerahan SK Jabatan Akademik Dosen Guru Besar Dr. Ir. Luluk Setyaningsih, M.Si tersebut dilaksanakan pada hari Selasa, 9 Juli 2024 di Hotel Aryaduta Bandung, Jl. Sumatera No. 51 Citarum Kec. Bandung Wetan Kota Bandung 40115, penyerahan didampingini oleh Rektor Universitas Nusa Bangsa, Prof. Dr. Ir. Budi Mulyanto, MSc. Berdasarkan hasil Keputusan Menteri Pendidikan, Kebudayaan, Riset dan Teknologi RI No.60054/M/07/2024 ditetapkan Dr. Ir. Luluk Setyaningsih, MSi dinaikkan jabatannya menjadi Profesor dalam bidang ilmu Silvikultur Tropika . Universitas Nusa Bangsa sangat bangga dapat melahirkan Guru Besar perempuan non ASN (dari PTS) pertama Bidang Silvikultur . Silvikultur merupakan budidaya hutan atau teknik bercocok tanam hutan yang dimulai dari pemilihan bibit, pembuatan tanaman, sampai pada pemanenan atau penebangannya di daerah tropis. Ini berarti Universitas Nusa Bangsa menambah peningkatkan dalam Sumber Daya Manusianya, khususnya sebagai Dosen. Sumber daya manusia (SDM) di kalangan dosen menjadi kunci untuk mencapai peningkatan kualitas perguruan tinggi (PT). Berdasarkan Pasal 1 Undang-Undang Nomor 14 Tahun 2005 tentang Guru dan Dosen, Guru Besar atau Profesor adalah jabatan fungsional tertinggi bagi Dosen yang masih mengajar di lingkungan satuan pendidikan tinggi. (HS)", "type": "paragraph"}, {"id": "6igv1bdllxufbxxm", "url": "https://unb.ac.id/wp-content/uploads/2024/07/20240709_133110-scaled-e1720528589560-300x237.jpg", "type": "image", "caption": ""}, {"id": "s6kgbgv1r25m2etm", "url": "https://unb.ac.id/wp-content/uploads/2024/07/20240709_133219-300x169.jpg", "type": "image", "caption": ""}], "excerpt": "Bandung, 9 Juli 2024 Sehubungan dengan telah terbitnya SK Jabatan Akademik Dosen Guru Besar Kementerian Pendidikan, Kebudayaan, Riset, dan Teknologi, Lembaga Layanan Pendidikan Tinggi Wilayah IV mengundang Dr. Ir. Luluk...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/20240709_133110-scaled-e1720528589560-300x237.jpg", "publishedAt": "2024-07-09"}, {"id": "doa9pux270k4idrw", "slug": "gelar-profesor-terlahir-di-universitas-nusa-bangsa", "title": "Gelar Profesor terlahir di Universitas Nusa Bangsa", "author": "Humas UNB", "blocks": [{"id": "yydmh2la961dh1t0", "text": "Bogor, 2 Juli 2024", "type": "paragraph"}, {"id": "w9z1k7rd3je4ymcp", "text": "Profesor. Dr. Ir. Luluk Setyaningsih, MS", "type": "paragraph"}, {"id": "f6sjkq4djidmaan9", "text": "Alhamdulillah, puji syukur kehadirat Allah SWT, berdasarkan hasi Keputusan Menteri Pendidikan, Kebudayaan, Riset dan Teknologi RI No.60054/M/07/2024 ditetapkan Dr. Ir. Luluk Setyaningsih, MSi dinaikkan jabatannya menjadi Profesor dalam bidang ilmu Silvikultur Tropika . Silvikultur merupakan budidaya hutan atau teknik bercocok tanam hutan yang dimulai dari pemilihan bibit, pembuatan tanaman, sampai pada pemanenan atau penebangannya di daerah tropis. Ini berarti Universitas Nusa Bangsa menambah peningkatkan dalam Sumber Daya Manusianya, khususnya sebagai Dosen. Sumber daya manusia (SDM) di kalangan dosen menjadi kunci untuk mencapai peningkatan kualitas perguruan tinggi (PT). Berdasarkan Pasal 1 Undang-Undang Nomor 14 Tahun 2005 tentang Guru dan Dosen, Guru Besar atau Profesor adalah jabatan fungsional tertinggi bagi Dosen yang masih mengajar di lingkungan satuan pendidikan tinggi. Rektor Universitas Nusa Bangsa Profesor Dr. Ir. Budi Mulyanto, MSc beserta keluarga besar Universitas Nusa Bangsa memberikan ucapak Selamat kepada Profesor. Dr. Ir. Luluk Setyaningsih, MSi, beliau menyampaikan semoga capaian Jabatan Akademis sebagai Guru Besar akan menjadikan suri tauladan bagi civitas akademika Universitas Nusa Bangsa. Aamiin", "type": "paragraph"}, {"id": "5hcwu24ovjriu6zf", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-02-at-13.51.05-200x300.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 2 Juli 2024 Profesor. Dr. Ir. Luluk Setyaningsih, MS Alhamdulillah, puji syukur kehadirat Allah SWT, berdasarkan hasi Keputusan Menteri Pendidikan, Kebudayaan, Riset dan Teknologi RI No.60054/M/07/2024 ditetapkan...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-02-at-13.51.05-200x300.jpeg", "publishedAt": "2024-07-02"}, {"id": "5r4b18itiptuzwwn", "slug": "dies-natalis-ke-37-universitas-nusa-bangsa-adakan-tasyakuran", "title": "Dies Natalis ke-37, Universitas Nusa Bangsa adakan Tasyakuran", "author": "Humas UNB", "blocks": [{"id": "5ovnyh5u8wvkyky2", "text": "Senin, 1 Juli 2024 Dalam rangka Dies Natalis ke 37, Universitas Nusa Bangsa Bogor mengadakan tasyakuran dengan mengundang CIVITAS AKADEMIK. Pada kesempatan itu Rektor UNB Prof. Dr. Ir. Budi Mulyanto, MSc menyampaikan pada sambutannya kepada CIVITAS AKADEMIK Universitas Nusa Bangsa untuk lebih meningkatkan kinerja diantaranya menaikkan jumlah mahasiswa. Beliau juga mengharapkan kepada semua yang hadir di HUT UNB ke-37 untuk bersama-sama bersemangat bekerjasama menjadikan Universitas Nusa Bangsa tidak hanya unggul, namun juga berstandar Internasional. Sehingga siapa saja yang tidak serius untuk bekerjasama maka silahkan keluar atau silahkan laporkan.", "type": "paragraph"}, {"id": "2ccealragefjblca", "text": "Sambutan Rektor UNB, Prof. Dr. Ir. Budi Mulyanto, MSc", "type": "paragraph"}, {"id": "4h0mns1tivdonkgd", "text": "Pada acara tersebut juga dihadiri Ketua Yayasan PKMK Nusantara, Ir. Doddy Imran Cholid, MS . Beliau juga berpesan untuk bersama-sama meningkatkan jumlah mahasiswa, bukan hanya kewajiban HUMAS namun setiap Fakultas dan Prodi bahkan setiap Dosen serta Tendik. Universitas Nusa Bangsa Memiliki banyak fasilitas atau aset yang bisa dimanfaatkan, sehingga silahkan mencari peluang sebanyak-banyaknya terutama dengan pemerintah daerah, pusat dan swasta. Bisa juga PORANG menjadi ICON atau BRAND Universitas Nusa Bangsa, jika bicara porang maka Universitas Nusa Bangsa yang akan dicari. Selain itu banyak keunggulan lain yang menjadi keunggulan UNB yang bisa dioptimalkan dalam mencari jumlah mahasiswa.", "type": "paragraph"}, {"id": "80aqjfa9xejo27bn", "text": "Sambutan Ketua Yayasan PKMK Nusantara, Ir. Doddy Imran Cholid, MS", "type": "paragraph"}, {"id": "1riwmkdd3rvxtrp8", "text": "Acara dilanjutkan pada pemberian Cindra Mata pada Karyawan UNB yang sudah memasuk masa pensiun . Cindra mata merupakan salah satu ucapan rasa terimakasih UNB terhadap karyawan yang sudah banyak berjasa dalam memajukan UNB hingga HUT ke 37 ini. Diakhir acara sebelum dilanjutkan acara ramah tamah, dipanjatkan do''a semoga UNB senantiasa diberikan kemudahan dan kemapuan untuk menjadikan UNB berstandar Internasional. Aamiin", "type": "paragraph"}, {"id": "ea0tg9x7tcz2cgl7", "text": "Ucapan Terimakasih dan Pemberian Cindera Mata pada Karyawan UNB yang memasuki masa pensiun", "type": "paragraph"}, {"id": "rf9p0fidp2o1dq2y", "text": "Kegiatan Ramah Tamah Civitas Akademi Universitas Nusa Bangsa", "type": "paragraph"}, {"id": "eieo19t0twizsizw", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-01-at-13.11.51-1-300x169.jpeg", "type": "image", "caption": ""}, {"id": "uedys5lglfcqfbzi", "url": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-01-at-15.20.52-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Senin, 1 Juli 2024 Dalam rangka Dies Natalis ke 37, Universitas Nusa Bangsa Bogor mengadakan tasyakuran dengan mengundang CIVITAS AKADEMIK. Pada kesempatan itu Rektor UNB Prof. Dr. Ir. Budi Mulyanto, MSc menyampaikan pad...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/07/WhatsApp-Image-2024-07-01-at-13.11.51-1-300x169.jpeg", "publishedAt": "2024-07-01"}, {"id": "z9fh8glqprc3cmjn", "slug": "asesment-lapangan-akreditasi-program-studi-manajemen-fakultas-ekonomi-dan-bisnis", "title": "Asesment Lapangan Akreditasi Program Studi Manajemen Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa (FEB-UNB)", "author": "Humas UNB", "blocks": [{"id": "nvm91y0upspavgxh", "text": "Kamis, 27 Juni 2024, berlangsung acara Pembukaan Asesment Lapangan Akreditasi Program Studi Manajemen Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa (FEB-UNB) yang dihadiri oleh Ketua Yayasan Pengembangan Keterampilan dan Mutu Kehidupan Nusantara (PKMKN) sebagai penyelenggara UNB, Rektor dan para Wakil Rektor, Para Dekan, Kepala Biro dan Lembaga, Ketua Prodi beserta para dosen FEB-UNB dan dua orang assessor dari Lembaga Akreditasi Mandiri Ekonomi Manejemen Bisnis dan Akuntansi (LAMEMBA) yaitu Dr.Sih Darmi Astuti, S.E., M.Si dan Dr. Mohammad Haekal, S.E., M.M. Sambutan Dekan FEB, Dr.Isbandriyati Mutmainah, S.E., M.E mengawali acara ini menyampaikan bahwa Asessment Lapangan Akreditasi Prodi Manajemen dipahami sebagai proses verifikasi data, informasi dan dokumen Evaluasi Diri Fakultas sebagai Unit Penyelenggara Prodi dan Laporan Kinerja Prodi oleh para assessor sebagai salah satu rangkaian untuk menilai kinerja Prodi sekaligus merupakan momentum untuk mendapatkan umpan balik guna perbaikan kinerja Prodi lebih lanjut. Pada periode sebelumnya Prodi Manajemen telah berhasil meraih status akreditas B (Baik Sekali), mudah2an Prodi Manajemen akan mampu meraih status akreditasi yang lebih meningkat, minimal Baik Sekali. Prof.Dr. Ir. Budi Mulyanto, M.Sc., sebagai rektor UNB memberikan penekanan bahwa sesuai dengan namanya Universitas Nusa Bangsa, UNB merupakan Perguruan Tinggi Nasional yang sudah berumur tua dengan segala pengalaman dalam penyelenggaraan Tri Dharma Perguruan Tinggi, selalu bercita-cita dan berusaha untuk meraih status akreditasi PT dan Prodi yang unggul minimal baik sekali agar supaya menjadi PT dan Prodi yang diminati dan pilihan bagi masyarakat pengguna. Oleh sebab itu diharapkan Prodi Manajemen FEB yang sudah memiliki kinerja baik hendaknya mampu menampilkan data, informasi, dokumen yang optimal dalam proses Asesmen Lapang Akreditasi ini. Hampir senada dengan Rektor UNB, Ketua Pengurus YPKMKN Ir. H. Doddy Imron Cholid, M.Si dalam sambuatannya menyampaikan bahwa Yayasan ini memiliki unit usaha, terdiri UNB, SMK Analis Kimia, SMK Ilmu Komputer di Bogor dan SMK Otomatif di Temanggung Jawa Tengah. Sebagai PT yang sudah tidak muda lagi, tentu saja diyakini UNB sudah memperoleh banyak pengalaman dalam penyelenggaraan pendidikan tinggi dan diharapkan mampu menyajikan kinerja terbaik, sehingga diharapkan dapat memperoleh status akreditasi minimal baik sekali. Di penghujung acara pembukaan ini, Asesor Assement Lapangan yang diwakili oleh Dr. Sih Darmi Astuti, S.E., M.Si menyampaikan bahwa kehadiran asesor adalah mewakili LAMEMBA bukan wakil suatu Perguruan Tinggi, yang bekerja sesuai dengan tugasnya. Diharapkan Asesment Lapang bukanlah sesuatu yang menakutkan justru menjadi kesempatan untuk memperoleh legalitas status yang dibutuhkan oleh penyelenggara Prodi dan masyarakat pengguna Prodi. Tugas asesor menggali seoptimal mungkin data, informasi dan dokumen tentang Prodi. Prinsip dalam asesmen ini adalah bagaimana Prodi mampu mendokumenkan setiap aktifitas yang dilakukan dan memastikan telah melakukan aktifitas apa yang didokumenkan. Kekuatan utama Prodi dalam mengikuti asesmen lapang ini adalah pada Pusat Data Pendidikan Tinggi (PDDIKTI) dan Sistem Penjaminan Mutu Internal (SPMI). Penentuan kualifikasi Akreditasi Prodi oleh LAMEMBA menggunakan standar penilaian Internasional, ucap Asesor Dr. Sih Darmi Astuti.", "type": "paragraph"}, {"id": "1f47xolmhgwruhy3", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-27-at-08.10.33-1-300x225.jpeg", "type": "image", "caption": ""}, {"id": "rr9nsrhadsk8lz2r", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-27-at-08.10.32-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Kamis, 27 Juni 2024, berlangsung acara Pembukaan Asesment Lapangan Akreditasi Program Studi Manajemen Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa (FEB-UNB) yang dihadiri oleh Ketua Yayasan Pengembangan Keterampil...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-27-at-08.10.33-1-300x225.jpeg", "publishedAt": "2024-06-27"}, {"id": "ruyo3p95t2sv2elv", "slug": "kesepahaman-bersama-unb-dengan-koperasi-tani-bangkit-sejahtera-tabara", "title": "Kesepahaman Bersama UNB dengan KOPERASI TANI BANGKIT SEJAHTERA (TABARA)", "author": "Humas UNB", "blocks": [{"id": "buzs3ihtotstxh0n", "text": "Bogor, 20 Juni 2024 Untuk menunjang dalam melaksanakan dan meningkatkan kualitas sumber daya, kelembagaan, dan pelaksanaan Tri Dharma Perguruan Tinggi. UNIVERSITAS NUSA BANGSA dengan KOPERASI TANI BANGKIT SEJAHTERA (TABARA) pada hari kamis, tanggal Dua Puluh, Bulan Juni, Tahun Dua Ribu Dua Puluh Empat menandatangani Nota Kesepahaman Bersama. Prof. Dr. Ir. Budi Mulyanto, M.Sc sebagai Rektor yang bertindak atas nama Universitas Nusa Bangsa, selanjutnya disebut sebagai PIHAK KESATU dan Septy Diana sebagai Ketua Pengurus / Direktur Utama yang bertindak atas nama Koperasi Tani Bangkit Sejahtera (TABARA) selanjutnya disebut sebagai PIHAK KEDUA. Maksud Kesepahaman adalah sebagai dasar dalam pelaksanaan Perjanjian Kerjasama yang akan dibuat sesuai dengan ruang lingkup Kesepahaman dengan Tujuan Kesepahaman adalah untuk mengembangkan kerjasama di bidang pendidikan, penelitian dan pengabdian kepada masyarakat yang diselenggarakan oleh PARA PIHAK. Ruang lingkup Kesepahaman dalam mengembangkan program kerjasama meliputi:", "type": "paragraph"}, {"id": "0bi1sigryar6q713", "text": "Pelaksanaan pendidikan;", "type": "paragraph"}, {"id": "nkxzlciad563up08", "text": "Pelaksanaan penelitian;", "type": "paragraph"}, {"id": "em5fu9amh1wb1iwv", "text": "Pelaksanaan pengabdian kepada masyarakat;", "type": "paragraph"}, {"id": "nam0ro6ygymyijh9", "text": "Pelaksanaan seminar, workshop dan pelatihan;", "type": "paragraph"}, {"id": "9gn28x7x6f0x43y0", "text": "Program lainnya yang disepakati PARA PIHAK", "type": "paragraph"}, {"id": "7kxnmlm9cl3hyfj6", "text": "Pada kesempatan tersebut dibahas tentang Kultur jaringan. Kultur Jaringan adalah suatu metode untuk mengisolasi bagian dari tanaman seperti sekelompok sel atau jaringan yang ditumbuhkan dalam kondisi aseptik, sehingga bagian tanaman tersebut bisa dapat memperbanyak diri hingga tumbuh menjadi tanaman-tanaman yang baru kembali dengan sifat yang sama. salah satu tanaman yang akan dilakukan kultur jaringan adalah tanaman porang. Porang atau dalam bahasa ilmiah disebut Amorphophallus oncophyllus adalah tanaman umbi-umbian yang berasal dari wilayah Asia Tenggara. Prof. Dr. Ir. Budi Mulyanto, M.Sc sangat mendukung kerjasama ini dikarenakan UNB saat ini sudah mengembangkan talas sedangkan porang sama-sama tanaman umbi umbian yang dapat sejalan dengan arah penelitian kedepannya juga menjadi peluang bisnis. Beliau menyampaikan juga tantangan nya untuk jangka pendek, bisa mengembangkan porang sehingga bisa sebagai suplier ke pabrik yang membutuhkan bahan baku dari porang. Sedangkan untuk jangka panjang tercipta bibit porang yang unggul bahkan ekosistem yang terbentuk perlu di analisis serta teknologinya sehingga menghasilkan bibit porang yang baik selain itu terbentuk Perjanjian Kerja Sama (PKS) pada bidang lainnya.", "type": "paragraph"}, {"id": "8wo8sw317ou8izt5", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-20-at-20.47.39-300x225.jpeg", "type": "image", "caption": ""}, {"id": "ct2xn2dfny8rbkxu", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-20-at-20.47.35-1-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 20 Juni 2024 Untuk menunjang dalam melaksanakan dan meningkatkan kualitas sumber daya, kelembagaan, dan pelaksanaan Tri Dharma Perguruan Tinggi. UNIVERSITAS NUSA BANGSA dengan KOPERASI TANI BANGKIT SEJAHTERA (TABA...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-20-at-20.47.39-300x225.jpeg", "publishedAt": "2024-06-20"}, {"id": "4y5bxj7psbyj7448", "slug": "kegiatan-sholat-idul-adha-dan-penyembelihan-hewan-kurban-di-unb", "title": "Kegiatan Sholat Idul Adha dan Penyembelihan Hewan Kurban di UNB", "author": "Humas UNB", "blocks": [{"id": "rk0teebl4enl8mxm", "text": "Bogor, 17 Juni 2024", "type": "paragraph"}, {"id": "fwzehc9jh50p4smp", "text": "Gema takbir berkumandang memaknai masuknya Hari Raya Idul Adha 1445 H. Universitas Nusa Bangsa melalui DKM Khalid bin Walid, pada tanggal 17 Juni 2024 atau tepatnya 10 Dzulhijah 1445 H melaksanakan kegiatan Sholat Idul Adha di Lapangan Kampus Universitas Nusa Bangsa. Dengan dihadiri lebih kurang 200 warga sekitar kampus, dengan khusyu melaksanakan Sholat Idul adha bersama dan dilanjutkan dengan mendengarkan khutbah yang disampaikan oleh khotib. Pada kesempatan itu yang bertugas sebagai Imam dan Khotib adalah Dr (c) Heri Susanto, SE., MM., CLMA yang merupakan Dosen dari Fakultas Ekonomi dan Bisnis Universitas Nusa Bangsa, pada kesempatan itu beliau mengambil tema khutbah \"Idul Adha tidak hanya pemotongan hewan kurban juga merupakan Perwujudan Kesalehan Sosial\" beliau menyampaikan khutbahnya bahwa bagi kita umat Islam, berqurban dengan menyembelih hewan ternak tidak hanya merupakan salah satu bentuk mendekatkan diri kepada Allah ( taqarrub ilallah ) disamping ibadah lainnya. Namun kalau hanya memahami Qurban sampai di dimensi ini maka pesan Islam sebagai agama yang peduli kepada sesama, sebagaimana disebutkan dalam Hadis Nabi \"sebaik-baik kamu adalah yang paling bermanfaat bagi orang lain\"- tidak akan terwujud. Padahal sebenarnya ibadah qurban juga memiliki dimensi lain yaitu dimensi kesalehan sosial yang sifatnya komunal-konkret (Arab: hablum minannas ). Pemaknaan akan dimensi sosial ini tergambar dari komponen pembagian daging hewan kurban kepada fakir miskin. Disini ditujukan untuk menimbulkan nuansa kepedulian kepada sesama. Sayangnya pesan kedua ini tidak banyak dipikirkan oleh kebanyakan kaum muslim. Dalam konteks yang lebih luas, kesalehan sosial menunjuk pada perilaku yang peduli kepada sesama. Sejatinya mereka yang saleh secara individual berarti beriman dan bertaqwa kepada Allah. Wujud dari keberimanan dan ketaqwaan kepada Allah otomatis akan merefleksikan kesalehan sosial, yaitu peduli kepada mereka yang miskin, bodoh dan terkebelakang. Wujud dari itu, maka mereka akan selalu berpikir, berikhtiar dan berjuang untuk mengubah nasib mereka yang belum beruntung dalam hidupnya yang merupakan salah satu Misi UNB untuk turut serta mencerdasakan bangsa. Selesai melaksanakan Sholat Idul Adha dilanjutkan bersalam salaman antara DKM khalid bin Walid dengan warga sekitar, hadir juga Ketua DKM Khalid bin Walid Abdurrahman Rusli, S.Hut, M.Si .", "type": "paragraph"}, {"id": "8gfu1sg11qe5uy5t", "text": "Khotib dan Imam Sholat Idul Adha bersama Ketua DKM Mesjid Khalid bin Walid UNB", "type": "paragraph"}, {"id": "giw8moy9fsivfohd", "text": "Pengurus Mesjid Khalid bin Walid Universitas Nusa Bangsa", "type": "paragraph"}, {"id": "b04z3t3b4o9nl4kn", "text": "Dilanjutkan dengan penyembelihan hewan kurban sebanyak 3 (tiga) ekor sapi dan 3 (tiga) ekor domba dan 2 (dua) ekor kambing dengan Ketua Panitia Dr. Ir. Faizal Maad, MSi. Setelah dilakukan pemotongan Panitia melakukan pembagian secara merata dan mendistribusikan pada masyarakat sekitar Kampus Universitas Nusa Bangsa.", "type": "paragraph"}, {"id": "uo3lfokibzp9ytw2", "text": "Ketua Panitia Hewan Kurban menyaksikan proses pemotongan hewan kurban", "type": "paragraph"}, {"id": "hdi1axs2ievavb32", "url": "https://unb.ac.id/wp-content/uploads/2024/06/IMG_6078-300x225.jpg", "type": "image", "caption": ""}, {"id": "2nqabcxokniotpkl", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-18-at-08.36.30-300x165.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 17 Juni 2024 Gema takbir berkumandang memaknai masuknya Hari Raya Idul Adha 1445 H. Universitas Nusa Bangsa melalui DKM Khalid bin Walid, pada tanggal 17 Juni 2024 atau tepatnya 10 Dzulhijah 1445 H melaksanakan ke...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/IMG_6078-300x225.jpg", "publishedAt": "2024-06-18"}, {"id": "ihfj3m0zb0apkec1", "slug": "visitasi-asesment-lapangan-prodi-magister-ekonomi-pembangunan-unb", "title": "Visitasi  Asesment Lapangan Prodi Magister Ekonomi Pembangunan UNB", "author": "Humas UNB", "blocks": [{"id": "v2o1ergda7v2evbp", "text": "Penyerahan hasil Asesment Lapangan kepada Dekan FEB UNB", "type": "paragraph"}, {"id": "ht11ldhmwofy7p9i", "text": "Foto Alumni Magister Ekonomi Pembangunan", "type": "paragraph"}, {"id": "yb0nxuw6wf0j20w7", "text": "Foto Mahasiswa Magister Ekonomi Pembangunan", "type": "paragraph"}, {"id": "43lpd0zcm8midjcg", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-12-at-14.13.43-300x300.jpeg", "type": "image", "caption": ""}, {"id": "8fjmn87cmutc4yf6", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-12-at-13.41.22-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Penyerahan hasil Asesment Lapangan kepada Dekan FEB UNB Foto Alumni Magister Ekonomi Pembangunan Foto Mahasiswa Magister Ekonomi Pembangunan", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-12-at-14.13.43-300x300.jpeg", "publishedAt": "2024-06-12"}, {"id": "2qfghzuzh4bz9anc", "slug": "pendanaan-hibah-pada-laboran-fmipa-unb-2024", "title": "Pendanaan Hibah pada Laboran FMIPA UNB, 2024", "author": "Humas UNB", "blocks": [{"id": "knteqe8iomiaq38f", "text": "Selamat dan Sukses", "type": "paragraph"}, {"id": "uhllrt03u5wxmzmj", "url": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-12-at-14.06.27-300x300.jpeg", "type": "image", "caption": ""}], "excerpt": "Alhamdulillah Selamat dan Sukses", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/WhatsApp-Image-2024-06-12-at-14.06.27-300x300.jpeg", "publishedAt": "2024-06-12"}, {"id": "6otewkr2wqxdtle5", "slug": "diskusi-sains-virtual-3-mengupas-tuntas-bioprospeksi-tumbuhan-berpotensi-di-indo", "title": "Diskusi Sains Virtual #3, Mengupas Tuntas Bioprospeksi Tumbuhan Berpotensi di Indonesia dan Peluang Berkarir Bagi Lulusan Biologi", "author": "Humas UNB", "blocks": [{"id": "ilbdyif3jbkjxd28", "text": "Laboratorium Biologi X Himpunan Mahasiswa Biologi Universitas Nusa Bangsa Kembali Menyelenggarakan Diskusi Sains Virtual #3 dengan Mengupas Tuntas Bioprospeksi Tumbuhan Berpotensi di Indonesia dan Peluang Berkarir Bagi Lulusan Biologi", "type": "paragraph"}, {"id": "cq59jxcliu0yrbnh", "text": "Program Studi Biologi FMIPA Universitas Nusa Bangsa kembali mencatat kesuksesan melalui Laboratorium Biologi dan Himpunan Mahasiswa Biologi UNB yang berhasil menyelenggarakan kegiatan Diskusi Sains Virtual (DSV) #3 pada tanggal 30 Mei 2024. Diskusi Sains Virtual ini telah menjadi kegiatan rutin tahunan yang diselenggarakan oleh Laboratorium Biologi UNB berkolaborasi dengan HIMABIO UNB. Keberhasilan DSV#1 dan DSV#2 mendorong penyelenggaraan DSV#3, dengan harapan kegiatan ini dapat memberikan kontribusi yang lebih besar bagi kemajuan ilmu pengetahuan dan teknologi, khususnya di bidang Biologi. Diskusi Sains Virtual (DSV) #3 menghadirkan Ibu Intani Quarta Lailaty, S.Si., M.Sc. dari Pusat Riset Botani Terapan-Badan Riset dan Inovasi Nasional (PRBT-BRIN) dengan mengangkat tema “Bioprospeksi Tumbuhan Berpotensi Indonesia” dan Bapak Faisal Rahmat, S.Si. dari Lloyd''s Register Quality Assurance Indonesia (LRQA) dan merupakan alumni Program Studi Biologi Universitas Nusa Bangsa dengan mengangkat tema “ Navigating Career Opportunities for Biology Student”. \"Kami ingin memberikan wadah bagi para akademisi, peneliti, dan praktisi untuk berbagi pengetahuan, pengalaman, serta hasil penelitian terkait dengan bidang Biologi, serta kegiatan ini diharapkan dapat menjadi forum yang memperluas wawasan dan pemahaman tentang bagaimana kemajuan ilmu pengetahuan dan teknologi, tantangan dalam pengembangannya, serta manfaat yang dapat dihasilkan bagi masyarakat dan industri\" ujar Ketua Pelaksana, Ade Ayu Oksari, S.Si., M.Si. “Pemahaman saya mengenai bioprospeksi tumbuhan dilakukan agar tumbuhan tidak punah dan tetap terjaga karna berhubungan dengan ekosistemnya. Kemudian, lewat DSV ini nanti akan diberikan pemahaman mengenai banyaknya pekerjaan yang membutuhkan seorang lulusan biologi, sehingga terbantahkan pemahaman masyarakat ttg sempitnya lapangan pekerjaan untuk lulusan Biologi. Terimakasih dan semoga apa yang disampaikan nanti membawa manfaat bagi kita semua ” ujar Dekan Fakultas MIPA Universitas Nusa Bangsa, Dr. Lany Nurhayati, S.Si., M.Si. Diskusi Sains Virtual #3 diikuti oleh 105 peserta dari berbagai instansi, termasuk Mahasiswa/i Universitas Nusa Bangsa, Universitas Muhammadiyah Bulukumba, Universitas PGRI Adi Buana Surabaya, Universitas Mathla''ul Anwar Banten, Universitas Labuhanbatu, Universitas Flore, Universitas Timor, Universitas Haji Sumatera Utara, SMA Negeri 7 Bogor, SMKN 1 Koto Baru, PT. Arasy Lab, PT. Sinarmas, PT. Organik Sehat Alami, serta Badan Riset yang meliputi BRIN dan BBPMSOH. Peserta terdiri dari mahasiswa, guru, dosen, tenaga pendidik, pegawai swasta/negeri, serta siswa SMA sederajat. 1 Alhamdulillah Diskusi Sains Virtual #3 berjalan lancar dan sukses. Hal ini ditandai dengan keaktifan peserta selama acara berlangsung, seperti bertanya, menjawab pertanyaan dari narasumber dan mengikuti kuis yang telah dipersiapkan oleh panitia DSV#3. Semoga acara ini dapat menciptakan kolaborasi yang baik antar narasumber dengan peserta DSV serta dapat memotivasi mahasiswa untuk berkontribusi lebih aktif dalam pengembangan ilmu pengetahuan dan teknologi, khususnya di bidang Biologi. Live streaming kegiatan DSV#3 dan video promosi Program Studi Biologi FMIPA UNB dapat dilihat pada channel youtube FMIPA_UNB Bogor dengan link sebagai berikut: https://www.youtube.com/live/4IFYXo8_4WI?feature=shared (DSV#3) dan https://youtu.be/6Yf4FUG86A4 (Video promosi Program Studi Biologi FMIPA UNB. Semoga di tahun berikutnya kegiatan ini dapat dilaksanakan kembali, yaitu Diskusi Sains Virtual Laboratorium Biologi UNB#4.", "type": "paragraph"}, {"id": "265xthmzlw9q90k0", "url": "https://unb.ac.id/wp-content/uploads/2024/06/Foto-Biologi-UNB-240x300.jpg", "type": "image", "caption": ""}, {"id": "bnsze900143jrw1v", "url": "https://unb.ac.id/wp-content/uploads/2024/06/Foto-Biologi-UNB-03-300x158.jpg", "type": "image", "caption": ""}], "excerpt": "Laboratorium Biologi X Himpunan Mahasiswa Biologi Universitas Nusa Bangsa Kembali Menyelenggarakan Diskusi Sains Virtual #3 dengan Mengupas Tuntas Bioprospeksi Tumbuhan Berpotensi di Indonesia dan Peluang Berkarir Bagi L...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/06/Foto-Biologi-UNB-240x300.jpg", "publishedAt": "2024-06-08"}, {"id": "iewsstibz1tdh5tn", "slug": "hibah-instrumen-gas-chromatography-gc-dari-pt-givaudan-indonesia-untuk-unb", "title": "Hibah Instrumen Gas Chromatography (GC) dari PT Givaudan Indonesia untuk UNB", "author": "Humas UNB", "blocks": [{"id": "fdqbztbunhq79nwv", "text": "Pada tanggal 30 Mei 2024,", "type": "paragraph"}, {"id": "103tqken5fg3zvdw", "text": "Universitas Nusa Bangsa menerima hibah instrumen Gas Chromatography (GC) dari PT Givaudan Indonesia, salah satu perusahaan terkemuka di bidang flavor dan fragrance. Kegiatan penyerahan hibah ini dihadiri oleh Rektor Universitas Nusa Bangsa, Wakil Rektor III dan alumni, penelitian, kerjasama, dan pengabdian kepada masyarakat, Dekan Fakultas Matematika dan Pengetahuan Alam (FMIPA), Ketua dan Sekretaris Program Studi Kimia, Kepala Laboratorium Kimia, dan Perwakilan Dosen FMIPA. Sedangkan PT Givaudan Indonesia diwakili oleh Operation Head Fragrance and Beauty Division, Human Resource (HR) Manager, Quality Manager Fragrance and Beauty Division, dan stafnya. Rektor Universitas Nusa Bangsa, Dr. Yunus Arifien, Ir., M.Si, dalam sambutannya menyampaikan rasa terima kasih yang mendalam kepada PT Givaudan Indonesia atas sumbangsih mereka terhadap pengembangan pendidikan dan penelitian di Universitas Nusa Bangsa. Beliau mengatakan bahwa instrumen Gas Chromatography ini akan mendukung penelitian dan praktikum di laboratorium kimia, khususnya di fakultas MIPA Universitas Nusa Bangsa. Operation Head Fragrance and Beauty Division, Zaldy Rachmat Susatya, juga menyampaikan harapannya bahwa hibah ini akan membantu meningkatkan kualitas pendidikan dan penelitian di Universitas Nusa Bangsa. Semoga instrumen GC ini dapat digunakan sebaik-baiknya oleh para mahasiswa dan dosen untuk melakukan penelitian yang inovatif dan relevan dengan kebutuhan industri dan masyarakat saat ini. Setelah serah terima simbolis yang ditandai dengan penyerahan plakat dan penandatanganan berita acara, kegiatan dilanjutkan dengan sesi foto bersama dengan instrumen Gas Chromatography di laboratorium kimia, FMIPA, UNB. Dengan adanya hibah ini, Universitas Nusa Bangsa semakin siap untuk menghasilkan penelitian yang berkualitas tinggi. Selain itu, kerjasama dengan PT Givaudan Indonesia diharapkan dapat terus berlanjut dan berkembang ke arah yang lebih baik, menciptakan sinergi antara dunia akademik dan industri. Kegiatan ini tidak hanya menjadi momentum penting bagi Universitas Nusa Bangsa untuk meningkatkan fasilitas laboratoriumnya, tetapi juga menjadi simbol kemitraan yang harmonis antara dunia pendidikan dan industri, yang bersama-sama berkomitmen untuk memajukan ilmu pengetahuan dan teknologi.", "type": "paragraph"}, {"id": "dy8oe40xdp6pxm2k", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-31-at-13.21.41-1-300x225.jpeg", "type": "image", "caption": ""}, {"id": "rksjy5qb9gck2sdw", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-31-at-13.21.41-300x169.jpeg", "type": "image", "caption": ""}], "excerpt": "Pada tanggal 30 Mei 2024, Universitas Nusa Bangsa menerima hibah instrumen Gas Chromatography (GC) dari PT Givaudan Indonesia, salah satu perusahaan terkemuka di bidang flavor dan fragrance. Kegiatan penyerahan hibah ini...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-31-at-13.21.41-1-300x225.jpeg", "publishedAt": "2024-05-31"}, {"id": "fepe90ogy1a8ivrg", "slug": "pemerhati-keanekaragaman-hayati", "title": "PEMERHATI KEANEKARAGAMAN HAYATI", "author": "Humas UNB", "blocks": [{"id": "g79nuyyy0ylq5m2g", "text": "Bogor, 20 Mei 2024", "type": "paragraph"}, {"id": "s5qgycea51uasdlm", "text": "Telah berlangsung kegiatan Pemerhati Keanekaragaman Hayati yang merupakan rangkaian kegiatan dari Kader Bina Rimbawan (KENARI) XIII. Dimana dalam hal ini pemerhati keanekaragaman hayati adalah keberagaman makhluk hidup yang didasarkan pada ciri-ciri yang dapat diketahuinya melalui suatu observasi/pengamatan. Telah dilaksanakan pada tanggal 4 - 5 Mei 2024 di Suaka Elang Loji Taman Nasional Gunung Halimun Salak, kegiatan Pemerhati Keanekaragaman Hayati tahun 2024 ini bertemakan “Membentuk Rimbawan Muda Yang Berjiwa Kepemimpinan dan Persaudaraan Berlandas Dengan 9 Nilai Dasar Rimbawan” . Kader Bina Rimbawan atau KENARI adalah kegiatan pengkaderan yang telah dilaksanakan oleh BEM Kehutanan-Sylva Indonesia (PC.) Universitas Nusa Bangsa. Pengkaderan ini dilaksanakan setiap tahun, dan merupakan agenda wajib dari BEM Kehutanan-Sylva Indonesia (PC.) Universitas Nusa Bangsa, KENARI ini sudah memasuki edisi ke-XIII. Dalam perkembangannya kegiatan KENARI dari tahun ke tahun selalu ada perbedaan dari segi konsep maupun aplikasinya. Dalam kegiatan Pemerhati Keanekaragaman Hayati tahun 2024 ini diikuti oleh 30 panitia dan 45 peserta. Tujuan diadakannya Pemerhati Keanekaragaman Hayati, yaitu merupakan rangkaian kegiatan KENARI XIII, kegiatan pendidikan, pelatihan dan penelitian tentang keanekaragaman hayati untuk melatih kemampuan diri agar menjadi seseorang Rimbawan muda, yang unggul dalam Ilmu Pengetahuan. Kegiatan ini berisi observasi/pengamatan keberagaman makhluk hidup, bentuk kegiatan yang dilakukan seperti Pengamatan Mamalia, Pengamatan Herpetofauna dan Pengamatan Aves telah dilaksanakan pada Sabtu-Minggu 4-5 Mei 2024.", "type": "paragraph"}, {"id": "z6o9jpdz3iphyp2n", "url": "https://unb.ac.id/wp-content/uploads/2024/05/Hutan002-300x169.jpg", "type": "image", "caption": ""}, {"id": "9piitpewxgavauj4", "url": "https://unb.ac.id/wp-content/uploads/2024/05/Hutan004.jpg", "type": "image", "caption": ""}], "excerpt": "Bogor, 20 Mei 2024 Telah berlangsung kegiatan Pemerhati Keanekaragaman Hayati yang merupakan rangkaian kegiatan dari Kader Bina Rimbawan (KENARI) XIII. Dimana dalam hal ini pemerhati keanekaragaman hayati adalah keberaga...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/05/Hutan002-300x169.jpg", "publishedAt": "2024-05-21"}, {"id": "qzflrlxynx5s4b67", "slug": "jalan-santai-hut-ke-42-yayasan-pkmk-nusantara-upaya-tingkatkan-jumlah-mahasiswa-", "title": "Jalan Santai HUT ke-42 Yayasan PKMK Nusantara Upaya Tingkatkan Jumlah Mahasiswa UNB", "author": "Humas UNB", "blocks": [{"id": "5jq26vc8jxkdmjgz", "text": "BOGOR-Ratusan peserta jalan sehat memeriahkan HUT ke-42 Yayasan Pengembangan Keterampilan dan Mutu Kehidupan (PKMK) Nusantara, pada Minggu (19/5/2024). Adapun, kegiatan jalan santai yang menempuh jarak sepanjang 4 km itu diawali di Gedung Yayasan PKMK Nusantara dan berakhir di Universitas Nusa Bangsa. Ketua Panitia Jalan Santai HUT ke-42 Yayasan PKMK Nusantara Roli Irawan mengatakan, acara jalan santai sekaligus halal bihalal dengan keluarga besar PKMK Nusantara, Kementerian ATR/BPN dan Universitas Nusa Bangsa serta unit lainnya seperti SMK AK Nusa Bangsa, SMK IT Nusa Bangsa Jampang dan SMK JBS Temangung, kegiatan ini selain untuk memeriahkan hari ulang tahun yang berdiri pada 20 Mei 1982 dan menjalin silaturahmi juga untuk mempromosikan Prodi-prodi yang ada di Universitas Nusa Bangsa \"Kegiatan tersebut dilaksanakan dalam rangka menjalin silaturahmi untuk pengembangan Universitas Nusa Bangsa, dan unit lainnya dibawah Yayasan PKMK Nusantara,\" kata Roli Irawan. Menurut dia, jalan sehat ini diikuti lebih dari 700 peserta dari berbagai unsur, mulai dari Dewan Pembina Yayasan PKMK, Direktorat Penataan Agraria, Universitas Nusa Bangsa, SMK Analis Kimia Nusa Bangsa, SMK Nusa Bangsa Jampang Parung, SMK Otomotof Temanggung. \"Ada pelajar SMP, komunitas hingga keluarga besar ATR BPN,\" ucapnya. Roli Irawan menjelaskan, jalan santai ini akan menempuh jarak kurang lebih 4 km, melalui ruas Jalan Sholeh Iskandar, Perumahan Bogor Raya Permai, Jalan KH Abdullah Bin Nuh. Berhenti di Gedung Graha Pena Radar Bogor, kemudian finish di Universitas Nusa Bangsa. Roli menyebut ada 15 pos jaga dan pemberhentian. Disisi lain, pada kegiatan tersebut juga dimeriahkan dengan penampilan bakat dan talenta siswa/siswi sekolah yang berada di bawah Yayasan PKMK Nusantara. \"Semoga dengan kegiatan ini terjalin silaturahmi yang lebih kuat antara ikatan keluarga Yayasan PKPM Nusantara, dan masyarakat sekitar serta unsur masyarakat Kota dan Kabupaten,\" tandas Roli Irawan. Sementara itu, Ketua Yayasan PKMK Nusantara Doddy Imran Cholid menyampaikan bahwa ini merupakan bagian dari Promosi dan sebagai alat evaluasi bagi Yayasan apakah kegiatan ini efektif dilakukan setiap tahun terkait jumlah mahasiswa yang mendaftar di Universitas Nusa Bangsa (UNB) ataupun siswa pada unit lainnya. Ketua Yayasan pun menyampaikan agar setiap bagian dari yayasan berikut unitnya peduli dan turut serta dalam mempromosikan unitnya masing-masing. \"Jangan sampai antar unit yang satu dengan yang lainnya tidak saling mempromosikan bahkan tidak tahu sama sekali kondisi unit lainnya,\" tandas Doddy Imran Cholid. Finish peserta jalan santai dialokasikan di Universitas Nusa Bangsa yang dilanjutkan dengan pembagian Doorprize yang beraneka ragam seperti Kulkas, TV, sepeda, HP, Payung, Tas, Mug dan masih banyak lainnya sehingga sangat menarik dan dinanti para peserta hingga akhir acara.Pada kesemptan itu Rektor UNB Yunus Arifien menyampaikan prodi-prodi yang ada di UNB berikut fasilitas dan program-program yang ditawarkan diantaranya seperti jalur RPL yakni calon mahasiswa yang sudah bekerja dapat dikonversi pengalamannya menjadi SKS yang tidak perlu diambil lagi, berikutnya kampus merdeka yang memungkinkan mahasiswa untuk mengambil mata kuliah pada kampus lain serta program lainnya yang sangat membantu mahasiswa dalam mengembangkan keilmuan dan percepatan dalam masa perkuliahan. Kegiatan jalan santai dan halalbihalal Yayasan PKMK diakhiri dengan penyegaran rohani dengan nara sumber dari ICMI dan dilanjutkan dengan ramah tamah yang di irigi oleh alunan Bank Nusa Bangsa yang jangat bersemangat menemani kegiatan hingga akhir kegiatan. (HS)", "type": "paragraph"}, {"id": "0rcviylvy1val0w7", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-19-at-18.37.35-300x225.jpeg", "type": "image", "caption": ""}, {"id": "zisqnxzrq9shtxd9", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-19-at-18.37.36-225x300.jpeg", "type": "image", "caption": ""}], "excerpt": "BOGOR-Ratusan peserta jalan sehat memeriahkan HUT ke-42 Yayasan Pengembangan Keterampilan dan Mutu Kehidupan (PKMK) Nusantara, pada Minggu (19/5/2024). Adapun, kegiatan jalan santai yang menempuh jarak sepanjang 4 km itu...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-19-at-18.37.35-300x225.jpeg", "publishedAt": "2024-05-19"}, {"id": "08cied6i3h2r7ov0", "slug": "kunjungan-studybanding-lp-mutu-unb-ke-lpm-uhamka", "title": "KUNJUNGAN STUDYBANDING LP MUTU UNB KE LPM UHAMKA", "author": "Humas UNB", "blocks": [{"id": "4r3i7mxhouixtk3i", "text": "Bogor, 8 Mei 2024 Pada Rabu tanggal 8 Mei 2024, Ketua Lembaga Penjaminan Mutu (LP-Mutu) UNB beserta para kepala Bagian di lingkup LP-Mutu UNB berkunjung ke Lembaga Penjaminan Mutu (LPM) UHAMKA dalam rangka studi banding dan berdiskusi perihal pelaksanaan dan peningkatan mutu Pendidikan tinggi di Indonesia. Tim UNB disambut dan diterima dengan sangat baik oleh Wakil Rektor I Bidang Akademik dan Penjaminan Mutu UHAMKA Anisia Kumala, Ketua LPM UHAMKA Ishaq Nuriadin beserta para Kepala Divisi lingkup LPM UHAMKA. Diskusi dan sharing dilaksanakan di Ruang Sidang I Lantai IV FEB UHAMKA, Jl. Raya Bogor KM.23 No.99 Ciaracas Jakarta Timur. Materi diskusi sangat menarik, mulai dari dokumen Sistem Penjaminan Mutu Internal (SPMI), instrumen dan pelaksanaan Audit Mutu Internal (AMI) serta Monitoring Evaluasi (MONEV), pengelolaan pangkalan data perguruan tinggi hingga kesiapan setiap perguruan tinggi di Indonesia dalam menghadapi terbitnya Permendikbud No. 53 Tahun 2023. Ketua LP-Mutu UNB, Mamay Maslahat menyatakan banyak sekali informasi, manfaat dari dilaksanakannya studi banding ke UHAMKA. Semoga sesuai dengan Visi UNB, UNB dapat meningkatkan mutunya dan dapat meraih akreditasi yang unggul serta mendapat kepercayaan masyarakat sebagaimana UHAMKA yang saat ini telah meraih akreditasi unggul.", "type": "paragraph"}, {"id": "k0ft3zgt1pzygqr0", "url": "https://unb.ac.id/wp-content/uploads/2024/05/Uhamka3-300x225.jpg", "type": "image", "caption": ""}, {"id": "1bmzjk2tyew949ed", "url": "https://unb.ac.id/wp-content/uploads/2024/05/Uhamka1-300x247.jpg", "type": "image", "caption": ""}], "excerpt": "Bogor, 8 Mei 2024 Pada Rabu tanggal 8 Mei 2024, Ketua Lembaga Penjaminan Mutu (LP-Mutu) UNB beserta para kepala Bagian di lingkup LP-Mutu UNB berkunjung ke Lembaga Penjaminan Mutu (LPM) UHAMKA dalam rangka studi banding...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/05/Uhamka3-300x225.jpg", "publishedAt": "2024-05-12"}, {"id": "gqtsrz2rrouye12j", "slug": "rapat-persiapan-jalan-santai-dan-halbil-yayasan-pkmk-nusantara", "title": "Rapat Persiapan Jalan Santai dan Halbil Yayasan PKMK Nusantara", "author": "Humas UNB", "blocks": [{"id": "svd0bkuy9hhs5tzu", "text": "Bogor, 30 April 2024 Dalam rangka persiapan Jalan Santai dan Halal bi Halal Ulang Tahun Yayasan PKMK Nusantara ke - 42, Panitia Jalan Santai mengundang para panitia pada 30 April 2024 untuk mendiskusikan persiapan jalan santai dan halal bi halal di Gedung Yayasan PKMK yang rencana kegiatannya Jalan Santai dan Halal bi Halal Ulang Tahun Yayasan PKMK Nusantara ke - 42 akan dilaksanakan pada hari minggu tanggal 19 Mei 2024. Drs. Roli Irawan, SH., MM., M.H selaku Ketua Panitia Jalan Santai Ulang Tahun ke-42 Yayasan PKMK Nusantara menyampaikan latar belakang dari kegiatan ini yakni diantaranya untuk memeriahkan Ulang Tahun ke-42 Yayasan PKMK Nusantara yang merupakan bagian dari Universitas Nusa Bangsa dan saling memaafkan setelah Ramadhan berlalu. Rencananya Jarak jalan sehat ini berkisar 4 km dengan lokasi tidak jauh atau sekitar Gedung Yayasan PKMK Jl. Sholeh Iskandar Km 4 Kecamatan Tanah Sareal Bogor, beliau juga menyampaikan target peserta diharapkan hingga 700 peserta yang tidak hanya unit-unit dibawah Yayasan PKMK Nusantara juga pimpinan dari pemda Kota dan Kab. Bogor, para kolega, dari ATR/BPN, juga perwakilan SLTA dan SLTP yang berada disekitar Yayasan PKMK dan unit dibawahnya. Selain memperoleh baju dan snack juga Door prize yang menarik disiapkan oleh Panitia dengan ketentuan berlaku, hal ini untuk menarik minat para calon peserta diluar unit Yayasan PKMK Nusantara. Pada kesempatan itu juga Ketua Yayasan PKMK Ir. Doddy Imran Cholid, M.S menyampaikan bahwa ini merupakan bagian dari Promosi dan sebagai alat evaluasi bagi Yayasan apakah kegiatan ini efektif dilakukan setiap tahun terkait jumlah mahasiswa yang mendaftar di Universitas Nusa Bangsa (UNB) ataupun siswa pada unit lainnya. Turut hadir juga Rektor UNB Dr. Ir. Yunus Arifin, MSi beserta para pimpinan unit lainnya menghadiri kegiatan persiapan jalan santai dan halal bi halal. Ketua Yayasan pun menyampaikan agar setiap bagian dari yayasan berikut unitnya peduli dan turut serta dalam mempromosikan unitnya masing-masing, jangan sampai antar unit yang satu dengan yang lainnya tidak saling mempromosikan bahkan tidak tahu sama sekali kondisi unit lainnya. Ketua Yayasan PKMK berharap semoga rencana kegiatannya yang akan diadakan pada hari minggu tanggal 19 Mei 2024 pukul 06.30 Wib dapat berjalan dengan baik dan lancar. (HS)", "type": "paragraph"}, {"id": "jja5esm0h9nctl0x", "text": "Gambar. Kegiatan Rapat Persiapan Jalan Santai dan Halal bi Halal Yayasan PKMK Nusantara", "type": "paragraph"}, {"id": "x9doo0clc3gvoqyv", "text": "Lokasi rapat, Gedung Rapat Yayasan PKMK Nusantara, Jl. Sholeh Iskandar Km. 4 Kota Bogor", "type": "paragraph"}, {"id": "xbd1lxxip7oa6isd", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-01-at-11.31.16-300x225.jpeg", "type": "image", "caption": ""}, {"id": "jun2rx59y2mr5uj1", "url": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-01-at-11.31.15-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 30 April 2024 Dalam rangka persiapan Jalan Santai dan Halal bi Halal Ulang Tahun Yayasan PKMK Nusantara ke - 42, Panitia Jalan Santai mengundang para panitia pada 30 April 2024 untuk mendiskusikan persiapan jalan...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/05/WhatsApp-Image-2024-05-01-at-11.31.16-300x225.jpeg", "publishedAt": "2024-05-01"}, {"id": "ztf9zilkh6rtoqe0", "slug": "rat-koperasi-sivitas-akademika-universitas-nusa-bangsa-kosiva-unb-tahun-buku-202", "title": "RAT Koperasi Sivitas Akademika Universitas Nusa Bangsa (KOSIVA-UNB) TAHUN BUKU 2023", "author": "Humas UNB", "blocks": [{"id": "kw4bnlz78t3zyy2d", "text": "Bogor, 1 April 2024 Sesuai dengan aturan organisasi koperasi dengan memperhatikan Undang-undang Pokok Perkoperasian, maka setiap tahun Pengurus harus melaporkan pertanggungjawaban kegiatan Koperasi melalui Rapat Anggota Tahunan (RAT). Untuk itu Koperasi Sivitas Akademika Universitas Nusa Bangsa (KOSIVA-UNB) sampaikan kepada para peserta Rapat Anggota Tahunan (RAT) tahun buku 2023 yang meliputi :", "type": "paragraph"}, {"id": "u6jkq91x97d53j4j", "text": "Perkembangan Koperasi selama tahun 2023", "type": "paragraph"}, {"id": "1oy2epowofp7nphd", "text": "Rencana Kerja dan Rencana Anggaran Pendapatan dan Belanja (RAPB) tahun kerja 2024.", "type": "paragraph"}, {"id": "haedy7vn2fr3miyi", "text": "Adapun dalam rapat anggota yang akan kita laksanakan, ada 2 (dua) hal yang harus dibahas, yaitu :", "type": "paragraph"}, {"id": "dtch6ybio7qqmiud", "text": "Mengesahkan laporan pertanggungjawaban pelaksanaan tugas Pengurus dan Pengawas tahun buku 2023.", "type": "paragraph"}, {"id": "n2ggl35b30xygvff", "text": "Mengesahkan Rencana Kerja dan Rencana Anggaran Pendapatan dan Belanja (RAPB) tahun 2024.", "type": "paragraph"}, {"id": "1rlaatvztym8lsu9", "text": "Ketua Koperasi Agus Pranamulia, SE., MM mengharapkan dukungan dan partisipasi anggota yang sebesar-besarnya dalam berbagai segi demi pengembangan koperasi selanjutnya. Kunci keberhasilan koperasi tidak semata-mata terletak pada kemampuan kerja Pengurus dan aparatnya saja, tetapi juga sangat tergantung kepada partisipasi para anggotanya", "type": "paragraph"}, {"id": "aouegdkyyp93yezq", "url": "https://unb.ac.id/wp-content/uploads/2024/04/WhatsApp-Image-2024-04-04-at-1.48.46-PM-225x300.jpeg", "type": "image", "caption": ""}, {"id": "jr5hr62ok4v85fuf", "url": "https://unb.ac.id/wp-content/uploads/2024/04/WhatsApp-Image-2024-04-04-at-1.49.06-PM-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "Bogor, 1 April 2024 Sesuai dengan aturan organisasi koperasi dengan memperhatikan Undang-undang Pokok Perkoperasian, maka setiap tahun Pengurus harus melaporkan pertanggungjawaban kegiatan Koperasi melalui Rapat Anggota...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/04/WhatsApp-Image-2024-04-04-at-1.48.46-PM-225x300.jpeg", "publishedAt": "2024-04-04"}, {"id": "90l4sgv7lng9wsg8", "slug": "kegiatan-kebakar-kerja-bakti-dan-buka-bareng-ormawa-universitas-nusa-bangsa", "title": "Kegiatan KEBAKAR (Kerja Bakti dan Buka Bareng) Ormawa Universitas Nusa Bangsa", "author": "Humas UNB", "blocks": [{"id": "vj8g84swe9dqlczs", "text": "(Bogor, 24 Maret 2024) Dalam rangka menjaga kebersihan lingkungan Anggota MAPAR bersama Ormawa Universitas Nusa Bangsa melakukan kerja bakti disekitar kampus UNB. Kerja bakti ini bertujuan untuk membersihkan seluruh area kampus yang diharapkan tidak ada lagi sampah dan rumput yang berantakan. Selain itu kegiatan ini dilanjutkan dengan buka bersama. Ormawa UNB lakukan kerja bakti bersama DPM BEM-KM UNB dan Kabinet kepengurusan BEM-KM UNB turut hadir dalam kegiatan tersebut Amri alfansuri selaku Presiden Mahasiswa UNB, Anggrah Maulana selaku wakil Presiden Mahasiswa UNB, Feri Kurnia Sandy selaku ketua umum dewan pengurus MAPAR dan jajaran pengurus setiap ormawa UNB Amri Alfansuri selaku Presiden Mahasiswa BEM-KM UNB mengatakan “ semoga dengan ada nya kegiatan ini dapat menumbuhkan rasa simpati dan empati, serta dapat menjalin tali silaturahmi antar ormawa” ujar Amri Alfansuri", "type": "paragraph"}, {"id": "jo074fjkwv2t56y1", "url": "https://unb.ac.id/wp-content/uploads/2024/03/WhatsApp-Image-2024-03-26-at-13.11.13-1-225x300.jpeg", "type": "image", "caption": ""}, {"id": "vokrbd5y17bq4phx", "url": "https://unb.ac.id/wp-content/uploads/2024/03/WhatsApp-Image-2024-03-26-at-13.11.13-2-300x225.jpeg", "type": "image", "caption": ""}], "excerpt": "(Bogor, 24 Maret 2024) Dalam rangka menjaga kebersihan lingkungan Anggota MAPAR bersama Ormawa Universitas Nusa Bangsa melakukan kerja bakti disekitar kampus UNB. Kerja bakti ini bertujuan untuk membersihkan seluruh area...", "category": "Berita", "bannerUrl": "https://unb.ac.id/wp-content/uploads/2024/03/WhatsApp-Image-2024-03-26-at-13.11.13-1-225x300.jpeg", "publishedAt": "2024-03-27"}], "categories": ["Berita", "Konferensi", "Prestasi", "Fasilitas", "Akademik"]}', '2026-03-19 09:40:14.372094');


